interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'gold';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'gold', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {

  const baseStyles = "relative overflow-hidden px-8 py-3.5 rounded-lg font-medium text-sm tracking-widest uppercase transition-all duration-500 flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed group";

  const variants = {
    // Gold Gradient - The "Call to Action"
    gold: "bg-gradient-to-r from-gold-300 via-gold-500 to-gold-400 text-black hover:shadow-[0_0_20px_rgba(212,175,55,0.3)] border border-transparent hover:scale-[1.02]",

    // Ghost/Glass - Secondary actions
    secondary: "bg-white/5 backdrop-blur-md border border-white/10 text-white hover:bg-white/10 hover:border-gold-400/30 hover:text-gold-200",

    // Minimal Text
    outline: "bg-transparent text-slate-400 hover:text-white border-b border-transparent hover:border-gold-400/50 rounded-none px-0 py-1 h-auto w-auto",

    // Dark Primary
    primary: "bg-charcoal text-white border border-white/10 hover:border-gold-500/50 hover:bg-white/5"
  };

  const finalClassName = `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {/* Shine effect on hover for gold buttons */}
      {variant === 'gold' && (
        <div className="absolute top-0 -left-[100%] w-[50%] h-full bg-gradient-to-r from-transparent via-white/40 to-transparent skew-x-[25deg] group-hover:animate-shimmer" />
