  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';

export const Landing: React.FC = () => {
  const [view, setView] = useState<'login' | 'register' | 'reset'>('login');
  const [connectionStatus, setConnectionStatus] = useState<'checking' | 'connected' | 'disconnected'>('checking');

  // Fields
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [registrationCode, setRegistrationCode] = useState('OBT-VIP'); 

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    storageService.init();
    const verifyConnection = async () => {
        setConnectionStatus('checking');
        const isLive = await storageService.testConnection();
        setConnectionStatus(isLive ? 'connected' : 'disconnected');
    };
    verifyConnection();
  }, []);

  const handleGoogleLogin = async () => {
    setError('');
    setIsLoading(true);
    try {
        await storageService.loginWithGoogle();
        navigate('/dashboard');
    } catch (err: any) {
        console.error("Google Login Error:", err);
        setError("התחברות עם גוגל נכשלה.");
    } finally {
        setIsLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setIsLoading(true);

    try {
      if (connectionStatus === 'disconnected') {
          const retry = await storageService.testConnection();
          if (retry) setConnectionStatus('connected');
      }

      if (view === 'register') {
        if (!name || !email || !password || !registrationCode) throw new Error("אנא מלא את כל השדות");
        await storageService.registerUser(name, email, password, registrationCode);
        navigate('/dashboard');
      } 
      else if (view === 'login') {
        if (!email || !password) throw new Error("אנא מלא אימייל וסיסמה");
        await storageService.login(email, password);
        navigate('/dashboard');
      }
      else if (view === 'reset') {
         if (!email || !registrationCode || !password) throw new Error("נדרש אימייל, קוד אימות וסיסמה חדשה");
         await storageService.resetPassword(email, registrationCode, password);
         setSuccessMsg("הסיסמה שונתה בהצלחה. ניתן להתחבר.");
         setTimeout(() => setView('login'), 2000);
      }
    } catch (err: any) {
      console.error("Submit Error:", err);
      if (err.message.includes("auth")) setError("פרטי הזיהוי שגויים.");
      else if (err.message.includes("network")) setError("שגיאת תקשורת.");
      else setError(err.message || 'אירעה שגיאה.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Layout>
      <div className="flex flex-col items-center justify-center min-h-[70vh]">

        {/* Luxury Typography Header */}
        <div className="text-center mb-16 animate-fade-in-up">
            <h1 className="text-6xl md:text-8xl font-serif font-medium text-white mb-6 tracking-tight leading-tight">
                One Big <span className="text-gradient-gold italic pr-2">Thing</span>
            </h1>
            <p className="text-lg md:text-xl text-slate-400 font-light tracking-wide max-w-xl mx-auto">
               פלטפורמת 360° אקסקלוסיבית למנהלים שרוצים להתמקד בעיקר.
            </p>
        </div>

        {/* Login Card */}
        <div className="glass-card w-full max-w-[420px] p-8 md:p-12 rounded-xl animate-fade-in-up border-t border-t-white/10 relative">

            {/* Admin Link - hidden but accessible */}
            <div className="absolute top-4 left-4 opacity-30 hover:opacity-100 transition-opacity">
                 <Link to="/admin" className="text-[10px] text-slate-500 uppercase tracking-widest">Admin</Link>
            </div>

