import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהל/ת',
  'peer': 'קולגה',
  'subordinate': 'כפיף/ה',
  'friend': 'חבר/ה',
  'other': 'אחר'
};

export const Dashboard: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [loadingData, setLoadingData] = useState(true);
  const [copied, setCopied] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) {
      navigate('/');
      return;
    }
    setUser(currentUser);

    const loadData = async () => {
        if (!storageService.isCloudEnabled()) {
             setLoadingData(false);
             return;
        }
        setLoadingData(true);
        try {
            const data = await storageService.getResponsesForUser(currentUser.id);
            setResponses(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoadingData(false);
        }
    };
    loadData();
  }, [navigate]);

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses);
      setAnalysis(result);
    } catch (error) {
      console.error(error);
      alert("שגיאה בניתוח הנתונים.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    if (!user) return;
    const baseUrl = window.location.href.split('#')[0];
    const cleanBase = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl;
    const url = `${cleanBase}/#/survey/${user.id}`;

    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleExport = () => {
      if(user) exportToWord(user, analysis, responses);
  };

  const groupResponses = (data: FeedbackResponse[]) => {
      const grouped: Record<string, FeedbackResponse[]> = {};
      data.forEach(r => {
          const key = r.relationship || 'other';
          if (!grouped[key]) grouped[key] = [];
          grouped[key].push(r);
      });
      return grouped;
  };

  if (!user) return null;
  const groupedResponses = groupResponses(responses);

  return (
    <Layout>
      <div className="animate-fade-in-up pb-12">

        {/* Luxury Header */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16 border-b border-white/5 pb-8">
          <div>
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-gold-500 mb-2 block">Executive Dashboard</span>
            <h1 className="text-5xl font-serif text-white">
                {user.name}
            </h1>
            <div className="flex items-center gap-3 mt-4 text-slate-400 font-light">
                <span className="w-2 h-2 rounded-full bg-emerald-500"></span>
                <p>Status: Active • {responses.length} Insights Collected</p>
            </div>
          </div>
          <div className="flex gap-4">
             <Button onClick={copyLink} variant="secondary">
               {copied ? 'Link Copied' : 'העתק לינק לשליחה'}
             </Button>
             <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="outline">
                יציאה
             </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          {/* Main Content (Responses) */}
          <div className="lg:col-span-8 space-y-12">

            {responses.length === 0 ? (
              <div className="glass-card text-center py-24 rounded-2xl border-dashed border-2 border-white/10">
                <div className="w-16 h-16 rounded-full bg-white/5 mx-auto flex items-center justify-center mb-6">
                    <span className="text-2xl">✉️</span>
                </div>
                <h3 className="text-2xl font-serif text-white mb-3">ממתין למשובים ראשונים</h3>
                <p className="text-slate-400 max-w-sm mx-auto mb-8 font-light">
                    על מנת שהמערכת תוכל לנתח את פרופיל המנהיגות שלך, יש לאסוף לפחות משוב אחד.
                </p>
                <Button onClick={copyLink} variant="gold">
                    העתק קישור
                </Button>
              </div>
            ) : (
              <div className="space-y-10">
                {Object.entries(groupedResponses).map(([rel, items]) => (
                   <div key={rel} className="animate-fade-in-up">
                       <div className="flex items-center gap-4 mb-6">
                            <h2 className="text-xl font-serif text-gold-200">
                                {relationshipLabels[rel] || rel}
                            </h2>
                            <span className="h-px flex-grow bg-gradient-to-r from-gold-500/50 to-transparent"></span>
                       </div>

                       <div className="grid gap-6">
                            {items.map((resp) => (
                                <div key={resp.id} className="glass-card p-8 rounded-xl hover:border-gold-500/30 transition-all group">
                                    <div className="grid md:grid-cols-2 gap-8">
                                        <div>
                                            <span className="text-[10px] text-gold-500 uppercase tracking-widest block mb-3 font-bold">הדבר האחד</span>
                                            <p className="text-lg text-platinum font-serif leading-relaxed group-hover:text-white transition-colors">{resp.q1_change}</p>
                                        </div>
                                        <div className="md:border-r md:border-white/10 md:pr-8">
                                            <span className="text-[10px] text-slate-500 uppercase tracking-widest block mb-3 font-bold">חסם נוכחי</span>
                                            <p className="text-sm text-slate-400 font-light italic">"{resp.q2_actions}"</p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                       </div>
                   </div> 
                ))}
              </div>
            )}
          </div>

          {/* Sidebar (Analysis) */}
          <div className="lg:col-span-4">
            <div className="sticky top-28">
                 <div className="glass-card p-1 rounded-2xl">
                    <div className="bg-obsidian/80 p-8 rounded-xl border border-white/5 relative overflow-hidden">

                        {/* Glow effect */}
                        <div className="absolute top-0 right-0 w-32 h-32 bg-gold-500/10 rounded-full blur-[60px]"></div>

                        <div className="relative z-10">
                            <h2 className="text-2xl font-serif text-white mb-6 flex items-center gap-2">
                                <span className="text-gold-400">✦</span> AI Synthesis
                            </h2>

                            {!analysis ? (
                            <div className="text-center py-6">
                                <p className="text-slate-400 text-sm mb-8 font-light leading-relaxed">
                                המערכת תבצע ניתוח סמנטי של כלל המשובים ותזקק את התובנה האסטרטגית עבורך.
                                </p>
                                <Button 
                                onClick={handleAnalyze} 
                                disabled={responses.length === 0}
                                isLoading={loadingAnalysis}
                                variant="gold"
                                className="w-full"
                                >
                                הפק דוח תובנות
                                </Button>
                            </div>
                            ) : (
                            <div className="space-y-8 animate-fade-in-up max-h-[70vh] overflow-y-auto custom-scrollbar pr-2">
                                <div>
                                    <span className="text-[10px] uppercase tracking-widest text-gold-500 font-bold mb-2 block">התובנה המרכזית</span>
                                    <p className="text-lg leading-relaxed text-white font-serif">{analysis.summary}</p>
                                </div>

                                <div>
                                    <span className="text-[10px] uppercase tracking-widest text-slate-500 font-bold mb-2 block">נושאים חוזרים</span>
                                    <ul className="space-y-3">
                                        {analysis.keyThemes.map((theme, i) => (
                                        <li key={i} className="text-sm text-slate-300 flex items-center gap-3">
                                            <span className="w-1 h-1 bg-gold-500 rounded-full"></span>
                                            {theme}
                                        </li>
                                        ))}
                                    </ul>
                                </div>

                                {analysis.groupAnalysis && (
                                    <div className="space-y-4 pt-6 border-t border-white/10">
                                        {Object.entries(analysis.groupAnalysis).map(([key, val]) => (
                                            <div key={key}>
                                                <span className="text-xs font-bold text-white block mb-1">{relationshipLabels[key] || key}</span>
                                                <p className="text-xs text-slate-400 font-light">{val}</p>
                                            </div>
                                        ))}
                                    </div>
                                )}

                                <div className="bg-gold-900/20 p-5 rounded-lg border border-gold-500/20 mt-4">
                                    <span className="text-[10px] uppercase tracking-widest text-gold-400 block mb-2 font-bold">המלצה לביצוע</span>
                                    <p className="text-sm text-gold-100 italic font-medium">"{analysis.actionableAdvice}"</p>
                                </div>

                                <div className="space-y-3 pt-6">
                                    <Button onClick={handleExport} variant="secondary" className="w-full">
                                        שמור דוח כ-Word
                                    </Button>
                                    <button 
                                        onClick={handleAnalyze} 
                                        className="text-[10px] uppercase tracking-widest text-slate-500 hover:text-white w-full text-center mt-2 transition-colors"
                                    >
                                    רענן ניתוח מחדש
                                    </button>
                                </div>
                            </div>
                            )}
                        </div>
                    </div>
                </div>
            </div>
          </div>

        </div>
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType } from '../types';

export const Survey: React.FC = () => {
  const { userId } = useParams<{ userId: string }>();
  const [userName, setUserName] = useState<string>('');

  // Form State
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [q1, setQ1] = useState('');
  const [q2, setQ2] = useState('');

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [error, setError] = useState<string>('');
  const [isLoadingUser, setIsLoadingUser] = useState(true);

  useEffect(() => {
    const checkConnection = async () => {
        setIsLoadingUser(true);
        if (userId) {
            try {
                const name = await storageService.getUserNameById(userId);
                if (name) {
                    setUserName(name);
                } else {
                    setError('קישור לא תקין.');
                }
            } catch (e) {
                setError('שגיאה בטעינת הנתונים.');
            }
        }
        setIsLoadingUser(false);
    };
    checkConnection();
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    setIsSending(true);
    try {
        await storageService.addResponse(userId, relationship, q1, q2);
        setSubmitted(true);
    } catch (err) {
        setError('שגיאה בשמירה.');
    } finally {
        setIsSending(false);
    }
  };

  if (isLoadingUser) {
      return (
          <Layout>
              <div className="flex justify-center items-center h-[50vh]">
                 <div className="w-1 h-12 bg-gold-500 animate-pulse"></div>
              </div>
          </Layout>
      );
  }

  if (submitted) {
    return (
      <Layout>
        <div className="flex flex-col items-center justify-center min-h-[60vh] text-center animate-fade-in-up">
          <div className="w-20 h-20 rounded-full border border-gold-500/30 flex items-center justify-center mb-8">
             <span className="text-4xl text-gold-400">✓</span>
          </div>
          <h2 className="text-4xl font-serif text-white mb-4">תודה על השקיפות</h2>
          <p className="text-slate-400 text-lg font-light leading-relaxed max-w-md mb-12">
                המשוב שלך נקלט בדיסקרטיות מלאה.
          </p>
          <Link to="/">
              <Button variant="outline">חזרה לדף הבית</Button>
          </Link>
        </div>
      </Layout>
    );
  }

  if (error) {
      return (
        <Layout>
            <div className="max-w-md mx-auto mt-20 text-center animate-fade-in-up">
                <h2 className="text-xl font-serif text-rose-500 mb-4">שגיאת מערכת</h2>
                <p className="text-slate-400 mb-8">{error}</p>
                <Link to="/">
                    <Button variant="outline">חזרה</Button>
                </Link>
            </div>
        </Layout>
      );
  }

  return (
    <Layout>
      <div className="max-w-3xl mx-auto w-full animate-fade-in-up">

        {/* Minimal Header */}
        <div className="text-center mb-16">
            <span className="text-[10px] font-bold uppercase tracking-[0.3em] text-gold-500 block mb-4">Private Feedback Session</span>
            <h1 className="text-5xl font-serif text-white">
              {userName}
            </h1>
        </div>

        <div className="glass-card p-10 md:p-14 rounded-2xl relative">
            <form onSubmit={handleSubmit} className="space-y-16">

                {/* Relationship Selector */}
                <div className="text-center">
                    <label className="block text-sm font-bold uppercase tracking-widest text-slate-500 mb-4">
                        הקשר המקצועי שלך
                    </label>
                    <div className="inline-block relative min-w-[200px]">
                        <select 
                            value={relationship}
                            onChange={(e) => setRelationship(e.target.value as RelationshipType)}
                            className="appearance-none bg-transparent border-b border-white/20 text-white font-serif text-xl py-2 px-8 text-center focus:outline-none focus:border-gold-500 w-full transition-colors cursor-pointer"
                        >
                            <option className="bg-charcoal" value="peer">אני קולגה / עמית</option>
                            <option className="bg-charcoal" value="manager">אני מנהל/ת ישיר/ה</option>
                            <option className="bg-charcoal" value="subordinate">אני כפיף/ה</option>
                            <option className="bg-charcoal" value="friend">אני חבר/ה</option>
                            <option className="bg-charcoal" value="other">ממשק עבודה אחר</option>
                        </select>
                        <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center text-gold-500">
                            <svg className="h-4 w-4 fill-current" viewBox="0 0 20 20"><path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z"/></svg>
                        </div>
                    </div>
                </div>

                {/* Q1 */}
                <div className="group">
                    <label className="block text-2xl md:text-3xl font-serif text-white mb-6 leading-normal">
                        1. מהו <span className="text-gold-400 italic">הדבר האחד</span> (One Big Thing) שאם ישונה, יקפיץ את האדם הזה קדימה?
                    </label>
                    <textarea
                        required
                        value={q1}
                        onChange={(e) => setQ1(e.target.value)}
                        rows={1}
                        onInput={(e) => {
                            e.currentTarget.style.height = 'auto'; 
                            e.currentTarget.style.height = e.currentTarget.scrollHeight + 'px';
                        }}
                        className="luxury-input resize-none overflow-hidden"
                        placeholder="הקלד/י כאן..."
                    />
                </div>

                {/* Q2 */}
                <div className="group">
                    <label className="block text-2xl md:text-3xl font-serif text-white mb-6 leading-normal">
                        2. אילו התנהגויות קיימות כיום מעכבות או סותרות את השינוי הזה?
                    </label>
                    <textarea
                        required
                        value={q2}
                        onChange={(e) => setQ2(e.target.value)}
                        rows={1}
                        onInput={(e) => {
                            e.currentTarget.style.height = 'auto'; 
                            e.currentTarget.style.height = e.currentTarget.scrollHeight + 'px';
                        }}
                        className="luxury-input resize-none overflow-hidden"
                        placeholder="הקלד/י כאן..."
                    />
                </div>

                <div className="pt-8 text-center flex flex-col items-center gap-4">
                    <Button type="submit" variant="gold" isLoading={isSending} className="w-full md:w-auto min-w-[240px] shadow-[0_0_30px_rgba(212,175,55,0.2)]">
                        שלח משוב
                    </Button>
                    <p className="text-[10px] uppercase tracking-widest text-slate-600">
                         אנונימי לחלוטין • מוצפן מקצה לקצה
                    </p>
                </div>
            </form>
        </div>
      </div>
    </Layout>
  );
};

