                    )}

                    <div>
                        <label className="block text-sm font-medium text-slate-700 mb-1">
                            {view === 'reset' ? 'סיסמה חדשה' : 'סיסמה'}
                        </label>
                        <input
                        type="password"
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        className="clean-input text-left"
                        dir="ltr"
                        />
                    </div>

                    {error && <p className="text-red-600 text-sm bg-red-50 p-2 rounded">{error}</p>}
                    {successMsg && <p className="text-green-600 text-sm bg-green-50 p-2 rounded">{successMsg}</p>}

                    <div className="pt-2">
                        <Button type="submit" variant="primary" className="w-full" isLoading={isLoading}>
                            {view === 'register' ? 'צור חשבון' : view === 'reset' ? 'עדכן' : 'כניסה'}
                        </Button>
                    </div>
                </form>
            </div>

            <div className="mt-6 pt-4 border-t border-slate-100 flex flex-col items-center gap-2 text-sm">
                {view === 'login' && (
                    <>
                        <button onClick={() => setView('reset')} className="text-slate-500 hover:text-brand-600">
                            שכחתי סיסמה
                        </button>
                        <div className="text-slate-600">
                             עדיין אין לך חשבון? <button onClick={() => setView('register')} className="text-brand-600 font-medium hover:underline">להרשמה</button>
