import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהלים',
  'peer': 'קולגות',
  'subordinate': 'כפיפים',
  'friend': 'חברים',
  'other': 'אחר'
};

export const Dashboard: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [loadingData, setLoadingData] = useState(true);
  const [copied, setCopied] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) {
      navigate('/');
      return;
    }
    setUser(currentUser);

    const loadData = async () => {
        if (!storageService.isCloudEnabled()) {
             setLoadingData(false);
             return;
        }
        setLoadingData(true);
        try {
            const data = await storageService.getResponsesForUser(currentUser.id);
            setResponses(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoadingData(false);
        }
    };
    loadData();
  }, [navigate]);

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses);
      setAnalysis(result);
    } catch (error) {
      console.error(error);
      alert("שגיאה בניתוח הנתונים.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    if (!user) return;
    const baseUrl = window.location.href.split('#')[0];
    const cleanBase = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl;
    const url = `${cleanBase}/#/survey/${user.id}`;

    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleExport = () => {
      if(user) exportToWord(user, analysis, responses);
  };

  const groupResponses = (data: FeedbackResponse[]) => {
      const grouped: Record<string, FeedbackResponse[]> = {};
      data.forEach(r => {
          const key = r.relationship || 'other';
          if (!grouped[key]) grouped[key] = [];
          grouped[key].push(r);
      });
      return grouped;
  };

  if (!user) return null;
  const groupedResponses = groupResponses(responses);

  return (
    <Layout>
      <div className="pb-12">

        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 mb-10 pb-6 border-b border-slate-200">
          <div>
            <h1 className="text-3xl font-heading font-bold text-slate-900">
                שלום, {user.name}
            </h1>
            <p className="text-slate-500 mt-1">
                נאספו עד כה {responses.length} משובים.
            </p>
          </div>
          <div className="flex flex-wrap gap-3">
             <Button onClick={copyLink} variant="secondary" className="whitespace-nowrap">
               {copied ? 'הקישור הועתק!' : 'העתק קישור לשליחה'}
             </Button>
             <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost">
                יציאה
             </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Content (Responses) */}
          <div className="lg:col-span-8 space-y-8">

            {responses.length === 0 ? (
              <div className="bg-white rounded-xl shadow-card p-12 text-center border border-slate-100">
                <div className="w-16 h-16 bg-slate-50 rounded-full flex items-center justify-center mx-auto mb-4 text-2xl">
                    📬
                </div>
                <h3 className="text-xl font-heading font-medium text-slate-800 mb-2">טרם התקבלו משובים</h3>
                <p className="text-slate-500 max-w-sm mx-auto mb-6">
                    כדי להתחיל את תהליך הצמיחה, שלח את הקישור האישי שלך לאנשים שעובדים איתך.
                </p>
                <Button onClick={copyLink} variant="primary">
                    העתק קישור אישי
                </Button>
              </div>
            ) : (
              <div className="space-y-8">
                {Object.entries(groupedResponses).map(([rel, items]) => (
                   <div key={rel}>
                       <h3 className="text-lg font-heading font-semibold text-slate-700 mb-4 flex items-center gap-2">
                           {relationshipLabels[rel] || rel}
                           <span className="text-xs font-normal text-slate-400 bg-slate-100 px-2 py-0.5 rounded-full">{items.length}</span>
                       </h3>

                       <div className="space-y-4">
                            {items.map((resp) => (
                                <div key={resp.id} className="bg-white p-6 rounded-lg shadow-card border border-slate-100">
                                    <div className="mb-4">
                                        <div className="text-xs font-semibold text-brand-600 uppercase tracking-wide mb-1">הדבר האחד לשינוי</div>
                                        <p className="text-slate-800 text-lg leading-relaxed">{resp.q1_change}</p>
                                    </div>
                                    <div className="pt-4 border-t border-slate-50">
                                        <div className="text-xs font-semibold text-slate-400 uppercase tracking-wide mb-1">התנהגויות מעכבות</div>
                                        <p className="text-slate-600">{resp.q2_actions}</p>
                                    </div>
                                </div>
                            ))}
                       </div>
                   </div> 
                ))}
              </div>
            )}
          </div>

          {/* Sidebar (Analysis) */}
          <div className="lg:col-span-4">
            <div className="sticky top-24 space-y-6">

                 {/* Analysis Card */}
                 <div className="bg-white rounded-xl shadow-soft border border-slate-100 overflow-hidden">
                    <div className="bg-slate-900 p-6 text-white">
                        <h2 className="text-xl font-heading font-semibold flex items-center gap-2">
                            <span className="text-brand-400">✨</span> ניתוח AI
                        </h2>
                        <p className="text-slate-400 text-sm mt-1">עיבוד חכם של כל המידע</p>
                    </div>

                    <div className="p-6">
                        {!analysis ? (
                        <div className="text-center py-4">
                            <p className="text-slate-600 mb-6 text-sm">
                            לחץ כאן כדי לזקק את כל המשובים לתובנה אחת מרכזית והמלצות לפעולה.
                            </p>
                            <Button 
                            onClick={handleAnalyze} 
                            disabled={responses.length === 0}
                            isLoading={loadingAnalysis}
                            variant="primary"
                            className="w-full"
                            >
                            צור דוח תובנות
                            </Button>
                        </div>
                        ) : (
                        <div className="space-y-6">
                            <div>
                                <h4 className="text-xs font-bold text-brand-600 uppercase mb-2">התובנה המרכזית</h4>
                                <p className="text-slate-800 font-medium leading-relaxed">{analysis.summary}</p>
                            </div>

                            <div>
                                <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">נושאים חוזרים</h4>
                                <ul className="space-y-2">
                                    {analysis.keyThemes.map((theme, i) => (
                                    <li key={i} className="text-sm text-slate-700 flex items-start gap-2">
                                        <span className="text-brand-500 mt-1">•</span>
                                        {theme}
                                    </li>
                                    ))}
                                </ul>
                            </div>

                            {analysis.groupAnalysis && (
                                <div className="pt-4 border-t border-slate-100">
                                    <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">הבדלים בגישה</h4>
                                    <div className="space-y-3">
                                        {Object.entries(analysis.groupAnalysis).map(([key, val]) => (
                                            <div key={key}>
                                                <span className="text-xs font-semibold text-slate-900 block">{relationshipLabels[key] || key}</span>
                                                <p className="text-xs text-slate-500">{val}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="bg-brand-50 p-4 rounded-lg border border-brand-100">
                                <h4 className="text-xs font-bold text-brand-700 uppercase mb-1">המלצה לביצוע</h4>
