import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType } from '../types';

export const Survey: React.FC = () => {
  const { userId } = useParams<{ userId: string }>();
  const [userName, setUserName] = useState<string>('');

  // Form State
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [q1, setQ1] = useState('');
  const [q2, setQ2] = useState('');

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [error, setError] = useState<string>('');
  const [isLoadingUser, setIsLoadingUser] = useState(true);

  useEffect(() => {
    const checkConnection = async () => {
        setIsLoadingUser(true);
        if (userId) {
            try {
                const name = await storageService.getUserNameById(userId);
                if (name) {
                    setUserName(name);
                } else {
                    setError('הקישור אינו תקין.');
                }
            } catch (e) {
                setError('שגיאה בטעינת הנתונים.');
            }
        }
        setIsLoadingUser(false);
    };
    checkConnection();
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    setIsSending(true);
    try {
        await storageService.addResponse(userId, relationship, q1, q2);
        setSubmitted(true);
    } catch (err) {
        setError('שגיאה בשמירה.');
    } finally {
        setIsSending(false);
    }
  };

  if (isLoadingUser) {
      return (
          <Layout>
              <div className="flex justify-center items-center h-[50vh]">
                 <div className="w-8 h-8 border-4 border-brand-200 border-t-brand-600 rounded-full animate-spin"></div>
              </div>
          </Layout>
      );
  }

  if (submitted) {
    return (
      <Layout>
        <div className="flex flex-col items-center justify-center min-h-[50vh] text-center">
          <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mb-6 text-3xl">
             ✓
          </div>
          <h2 className="text-3xl font-heading font-bold text-slate-900 mb-3">תודה רבה!</h2>
          <p className="text-slate-600 text-lg max-w-md mb-8">
                המשוב שלך התקבל בהצלחה ועוזר לנו מאוד.
          </p>
          <Link to="/">
              <Button variant="outline">לעמוד הבית</Button>
          </Link>
        </div>
      </Layout>
    );
  }

  if (error) {
      return (
        <Layout>
            <div className="max-w-md mx-auto mt-12 text-center p-8 bg-white shadow-card rounded-xl">
                <h2 className="text-lg font-bold text-red-600 mb-2">שגיאה</h2>
                <p className="text-slate-600 mb-6">{error}</p>
                <Link to="/">
                    <Button variant="secondary">חזרה</Button>
                </Link>
            </div>
        </Layout>
      );
  }

  return (
    <Layout>
      <div className="max-w-2xl mx-auto w-full">

        <div className="text-center mb-10">
            <h1 className="text-3xl font-heading font-bold text-slate-900 mb-2">
              משוב 360 עבור {userName}
            </h1>
            <p className="text-slate-500">
                המשוב הינו אנונימי לחלוטין ומטרתו צמיחה והתפתחות.
            </p>
        </div>

        <div className="bg-white p-8 md:p-10 rounded-xl shadow-card border border-slate-100">
            <form onSubmit={handleSubmit} className="space-y-10">

                {/* Relationship */}
                <div>
                    <label className="block text-sm font-semibold text-slate-700 mb-2">
                        מה הקשר המקצועי שלך?
                    </label>
                    <select 
                        value={relationship}
                        onChange={(e) => setRelationship(e.target.value as RelationshipType)}
                        className="clean-input bg-slate-50"
                    >
                        <option value="peer">אני קולגה / עמית</option>
                        <option value="manager">אני מנהל/ת ישיר/ה</option>
                        <option value="subordinate">אני כפיף/ה</option>
                        <option value="friend">אני חבר/ה</option>
                        <option value="other">ממשק עבודה אחר</option>
                    </select>
                </div>

                {/* Q1 */}
                <div>
                    <label className="block text-lg font-heading font-medium text-slate-900 mb-3 leading-relaxed">
                        1. מהו <span className="text-brand-600 font-bold">הדבר האחד</span> (המרכזי ביותר) שאם ישונה, יקפיץ את האדם הזה קדימה?
                    </label>
                    <textarea
                        required
                        value={q1}
                        onChange={(e) => setQ1(e.target.value)}
                        rows={3}
                        className="clean-input min-h-[100px]"
                        placeholder="כתוב כאן בצורה חופשית..."
                    />
                </div>

                {/* Q2 */}
                <div>
                    <label className="block text-lg font-heading font-medium text-slate-900 mb-3 leading-relaxed">
                        2. אילו התנהגויות קיימות כיום מעכבות אותו/ה או סותרות את השינוי הזה?
                    </label>
                    <textarea
                        required
                        value={q2}
                        onChange={(e) => setQ2(e.target.value)}
                        rows={3}
                        className="clean-input min-h-[100px]"
                        placeholder="תן דוגמאות אם אפשר..."
                    />
                </div>

                <div className="pt-4 text-center">
                    <Button type="submit" variant="primary" isLoading={isSending} className="w-full md:w-auto min-w-[200px] text-lg py-3">
                        שלח משוב
                    </Button>
                    <p className="text-xs text-slate-400 mt-4 flex items-center justify-center gap-1">
                        🔒 המידע נשמר באופן מאובטח ואנונימי
                    </p>
                </div>
            </form>
        </div>
      </div>
    </Layout>
  );
};

