import { User, FeedbackResponse, FirebaseConfig, RelationshipType } from '../types';
import { firebaseService } from './firebaseService';

// =================================================================
// הגדרות FIREBASE (ממשתני סביבה בלבד)
// =================================================================

const FIREBASE_CONFIG: FirebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY || "",
  authDomain: process.env.FIREBASE_AUTH_DOMAIN || "",
  projectId: process.env.FIREBASE_PROJECT_ID || "",
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID || "",
  appId: process.env.FIREBASE_APP_ID || "",
  measurementId: process.env.FIREBASE_MEASUREMENT_ID || ""
}; 

// =================================================================

const USER_KEY = '360_user_session';
const MOCK_RESPONSES_KEY = '360_mock_responses'; // For offline demo storage

const generateId = () => Math.random().toString(36).substring(2, 9) + Date.now().toString(36);

export const storageService = {

  init: () => {
    if (firebaseService.isInitialized()) return;

    // Check if config exists
    if (!FIREBASE_CONFIG.apiKey) {
        console.warn("⚠️ App running in DEMO MODE (No Firebase Config detected).");
        return;
    }

    const success = firebaseService.init(FIREBASE_CONFIG);
    if (!success) console.error("Failed to connect to Firebase Cloud. Falling back to local storage.");
  },

  isCloudEnabled: () => firebaseService.isInitialized(),
  testConnection: async () => firebaseService.testConnection(),

  getCurrentUser: (): User | null => {
    try {
        const stored = localStorage.getItem(USER_KEY);
        return stored ? JSON.parse(stored) : null;
    } catch (e) {
        return null;
    }
  },

  // ADMIN
  updateRegistrationCode: async (newCode: string): Promise<void> => {
      if (storageService.isCloudEnabled()) {
          await firebaseService.updateRegistrationCode(newCode);
      } else {
          // Local simulation
          localStorage.setItem('demo_reg_code', newCode);
      }
  },

  // LOGIN (EMAIL)
  login: async (email: string, password?: string): Promise<User> => {
    // 1. Try Cloud
    if (storageService.isCloudEnabled()) {
        const user = await firebaseService.findUserByEmail(email);
        if (user && user.password === password) {
             localStorage.setItem(USER_KEY, JSON.stringify(user));
             return user;
        }
    }

    // 2. Fallback / Local check (very basic for demo)
    const stored = localStorage.getItem(USER_KEY);
    if (stored) {
        const user = JSON.parse(stored);
        if (user.email === email) return user;
    }

    throw new Error("משתמש לא נמצא או סיסמה שגויה (נסה כניסה מהירה עם גוגל).");
  },

  // LOGIN (GOOGLE) - WITH DEMO FALLBACK
  loginWithGoogle: async (): Promise<User> => {
      // Attempt Real Login
      if (storageService.isCloudEnabled()) {
          try {
            const firebaseUser = await firebaseService.loginWithGoogle();
            if (!firebaseUser.email) throw new Error("No email from Google");

            let user = await firebaseService.findUserByEmail(firebaseUser.email);
            if (!user) {
                user = {
                    id: generateId(),
                    name: firebaseUser.displayName || firebaseUser.email.split('@')[0],
                    email: firebaseUser.email,
                    createdAt: Date.now()
                };
                await firebaseService.createUser(user);
            }
            localStorage.setItem(USER_KEY, JSON.stringify(user));
            return user;

          } catch (e) {
              console.warn("Cloud login failed, switching to Demo User", e);
          }
      }

      // Demo Mode Fallback (Simulated Login)
      // This ensures the user sees the app working even if configuration is missing
      const demoUser: User = {
          id: 'demo-user-id',
          name: 'אורח (מצב הדגמה)',
          email: 'demo@google.com',
          createdAt: Date.now()
      };

      console.log("Logged in with DEMO user");
      localStorage.setItem(USER_KEY, JSON.stringify(demoUser));
      return demoUser;
  },

  // REGISTER (With Access Code)
  registerUser: async (name: string, email: string, password?: string, registrationCode?: string): Promise<User> => {
    const isValidCode = registrationCode?.toUpperCase() === 'OBT-VIP' || registrationCode === localStorage.getItem('demo_reg_code');

    if (!registrationCode) throw new Error("נדרש קוד רישום.");

    // Cloud Validation
    if (storageService.isCloudEnabled()) {
        const cloudValid = await firebaseService.validateRegistrationCode(registrationCode);
        if (!cloudValid) throw new Error("קוד רישום שגוי.");

        const existing = await firebaseService.findUserByEmail(email);
        if (existing) throw new Error("המייל כבר קיים במערכת.");
    } else {
        if (!isValidCode) throw new Error("קוד רישום שגוי (דמו: OBT-VIP).");
    }

    const newUser: User = {
      id: generateId(),
      name,
      email,
      password,
      createdAt: Date.now(),
    };

    // Save
    if (storageService.isCloudEnabled()) {
        await firebaseService.createUser(newUser);
    }

    // Always save locally for session
    localStorage.setItem(USER_KEY, JSON.stringify(newUser));
    return newUser;
  },

  // RESET PASSWORD
  resetPassword: async (email: string, registrationCode: string, newPassword: string): Promise<void> => {
    if (storageService.isCloudEnabled()) {
        const isValid = await firebaseService.validateRegistrationCode(registrationCode);
        if (!isValid) throw new Error("קוד שגוי.");
        const user = await firebaseService.findUserByEmail(email);
        if (!user) throw new Error("משתמש לא נמצא.");
        await firebaseService.updatePassword(user.id, newPassword);
    } else {
        // Mock success
        await new Promise(r => setTimeout(r, 1000));
    }
  },

  logout: async () => {
    if (storageService.isCloudEnabled()) {
        await firebaseService.logout();
    }
    localStorage.removeItem(USER_KEY);
  },

  // DATA OPERATIONS (Hybrid Cloud/Local)

  addResponse: async (surveyId: string, relationship: RelationshipType, q1: string, q2: string) => {
    const newResponse: FeedbackResponse = {
      id: generateId(),
      surveyId,
      relationship,
      q1_change: q1,
      q2_actions: q2,
      timestamp: Date.now(),
    };

    if (storageService.isCloudEnabled()) {
      await firebaseService.addResponse(newResponse);
    } else {
        // Save to LocalStorage for Demo
        const existing = JSON.parse(localStorage.getItem(MOCK_RESPONSES_KEY) || '[]');
        existing.push(newResponse);
        localStorage.setItem(MOCK_RESPONSES_KEY, JSON.stringify(existing));
    }
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    let responses: FeedbackResponse[] = [];

    if (storageService.isCloudEnabled()) {
       try {
        responses = await firebaseService.getResponsesForUser(userId);
       } catch (e) { console.warn("Cloud fetch failed"); }
    }

    // Merge with local demo responses
    const local = JSON.parse(localStorage.getItem(MOCK_RESPONSES_KEY) || '[]');
    const userLocal = local.filter((r: FeedbackResponse) => r.surveyId === userId);

    // If no responses found at all (and it's a demo user), maybe add some fake ones for "Wow effect"?
    if (responses.length === 0 && userLocal.length === 0 && userId === 'demo-user-id') {
        return [
            { id: '1', surveyId: userId, relationship: 'manager', q1_change: 'לשחרר יותר שליטה ולסמוך על הצוות.', q2_actions: 'בודק כל אימייל שיוצא, נכנס לפרטים טכניים קטנים מדי.', timestamp: Date.now() },
            { id: '2', surveyId: userId, relationship: 'peer', q1_change: 'להיות יותר קשוב בישיבות צוות.', q2_actions: 'נוטה להתפרץ לדברי אחרים, מסתכל בטלפון בזמן שאחרים מדברים.', timestamp: Date.now() - 100000 },
            { id: '3', surveyId: userId, relationship: 'subordinate', q1_change: 'לתת פידבק חיובי, לא רק ביקורת.', q2_actions: 'שיחות המשוב מתמקדות רק במה לא עבד טוב.', timestamp: Date.now() - 200000 }
        ];
    }

    return [...responses, ...userLocal];
  },

  getUserNameById: async (userId: string): Promise<string> => {
    if (storageService.isCloudEnabled()) {
        const user = await firebaseService.getUser(userId);
        if (user) return user.name;
    }
    if (userId === 'demo-user-id') return "אורח (הדגמה)";

    // Fallback try local session
    const currentUser = storageService.getCurrentUser();
    if (currentUser && currentUser.id === userId) return currentUser.name;

    return "משתמש"; 
  }
};

storageService.init();

import { 
  getFirestore, 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where,
  limit,
  updateDoc
} from "firebase/firestore";
// Separate type import to avoid runtime errors in some environments
import type { Firestore } from "firebase/firestore";
import { initializeApp, getApp, getApps, FirebaseApp } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, Auth, User as FirebaseUser } from "firebase/auth";
import { FirebaseConfig, User, FeedbackResponse } from "../types";

// Global instances
let app: FirebaseApp | null = null;
let db: Firestore | null = null;
let auth: Auth | null = null;

export const firebaseService = {
  init: (config: FirebaseConfig) => {
    // Critical fix: Do not attempt to initialize if config is empty
    if (!config.apiKey || config.apiKey.length === 0) {
        console.warn("Firebase init skipped: No API Key provided.");
        return false;
    }

    try {
      // Check for existing apps using named exports logic
      const apps = getApps();
      if (apps.length > 0) {
        app = getApp();
      } else {
        app = initializeApp(config);
      }
      db = getFirestore(app);
      auth = getAuth(app);
      console.log("Firebase initialized");
      return true;
    } catch (e) {
      console.error("Firebase init critical error:", e);
      db = null;
      app = null;
      auth = null;
      return false;
    }
  },

  isInitialized: () => !!db,

  testConnection: async (): Promise<boolean> => {
    if (!db) return false;
    try {
      // Try to read something public or just check if we can reach the server
      const dummyRef = collection(db, "users");
      const q = query(dummyRef, limit(1));
      await getDocs(q);
      return true;
    } catch (e: any) {
      // If permission denied, it means we successfully contacted the server, 
      // but security rules blocked the read. This counts as "Connected".
      if (e.code === 'permission-denied') {
          console.log("Connection verified (permission denied is OK)");
          return true;
      }

      console.error("Connectivity test failed:", e.code);
      // 'unavailable' usually means offline
      if (e.code === 'unavailable') return false;

      // For other errors, assume connected but erroring
      return true;
    }
  },

  // --- Auth & Google Sign In ---

  loginWithGoogle: async (): Promise<FirebaseUser> => {
    if (!auth) throw new Error("Auth not initialized");
    const provider = new GoogleAuthProvider();
    try {
        const result = await signInWithPopup(auth, provider);
        return result.user;
    } catch (error) {
        console.error("Google Sign In Error", error);
        throw error;
    }
  },

  logout: async (): Promise<void> => {
      if (auth) {
          await auth.signOut();
      }
  },

  // --- System Config (Registration Code) ---

  validateRegistrationCode: async (codeToCheck: string): Promise<boolean> => {
    if (!db) return false;
    // Normalize code: remove spaces, uppercase
    const cleanCode = codeToCheck.trim().toUpperCase();

    try {
        const configRef = doc(db, "settings", "config");
        const docSnap = await getDoc(configRef);

        let validCode = "OBT-VIP"; // Default fallback code if not set in DB

        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.registrationCode) {
                validCode = data.registrationCode;
            }
        } 

        // Check match (case insensitive)
        return cleanCode === validCode.toUpperCase();

    } catch (e) {
        console.warn("Error validating code (using fallback mode):", e);
        // Fallback: If we can't read DB (e.g. permission denied or offline), 
        // we ONLY allow the default code to prevent total lockout.
        return cleanCode === "OBT-VIP";
    }
  },

  updateRegistrationCode: async (newCode: string): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    try {
        const configRef = doc(db, "settings", "config");
        await setDoc(configRef, { registrationCode: newCode }, { merge: true });
    } catch (e) {
        throw new Error("Failed to update registration code");
    }
  },

  // --- User Operations ---

  createUser: async (user: User): Promise<void> => {
    if (!db) throw new Error("System Error: Database not connected.");
    try {
      const userRef = doc(db, "users", user.id);
      await setDoc(userRef, user);
    } catch (e: any) {
      if (e.code === 'permission-denied') {
        throw new Error("שגיאת הרשאה. ייתכן וקוד הרישום לא נקלט כראוי, או שיש חסימת אבטחה.");
      }
      console.error("Create User Error:", e);
      throw new Error("נכשל הרישום לענן. אנא נסה שוב.");
    }
  },

  updatePassword: async (userId: string, newPassword: string): Promise<void> => {
    if (!db) throw new Error("Database disconnected");
    try {
        const userRef = doc(db, "users", userId);
        await updateDoc(userRef, { password: newPassword });
    } catch (e) {
        console.error("Password update failed", e);
        throw new Error("עדכון סיסמה נכשל.");
    }
  },

  getUser: async (userId: string): Promise<User | null> => {
    if (!db) return null;
    try {
      const userRef = doc(db, "users", userId);
      const docSnap = await getDoc(userRef);
      if (docSnap.exists()) return docSnap.data() as User;
      return null;
    } catch (e) { return null; }
  },

  findUserByEmail: async (email: string): Promise<User | null> => {
    if (!db) return null;
    try {
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("email", "==", email));
      const querySnapshot = await getDocs(q);

      if (querySnapshot.empty) return null;
      return querySnapshot.docs[0].data() as User;
    } catch (e: any) {
      if (e.code === 'permission-denied') throw new Error("permission-denied");
      throw e;
    }
  },

  // --- Response Operations ---

  addResponse: async (response: FeedbackResponse): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    try {
      const responseRef = doc(db, "responses", response.id);
      await setDoc(responseRef, response);
    } catch (e) {
      throw new Error("Failed to save response to cloud.");
    }
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (!db) return [];
    try {
      const responsesRef = collection(db, "responses");
      const q = query(responsesRef, where("surveyId", "==", userId));
      const querySnapshot = await getDocs(q);

      const responses: FeedbackResponse[] = [];
      querySnapshot.forEach((doc: any) => {
        responses.push(doc.data() as FeedbackResponse);
      });

      return responses.sort((a, b) => b.timestamp - a.timestamp);
    } catch (e) {
      return [];
    }
  }
};

import { User, FeedbackResponse, FirebaseConfig, RelationshipType } from '../types';
import { firebaseService } from './firebaseService';

// =================================================================
// הגדרות FIREBASE (ממשתני סביבה בלבד)
// =================================================================

const FIREBASE_CONFIG: FirebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY || "",
  authDomain: process.env.FIREBASE_AUTH_DOMAIN || "",
  projectId: process.env.FIREBASE_PROJECT_ID || "",
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID || "",
  appId: process.env.FIREBASE_APP_ID || "",
  measurementId: process.env.FIREBASE_MEASUREMENT_ID || ""
}; 

// =================================================================

const USER_KEY = '360_user_session';
const MOCK_RESPONSES_KEY = '360_mock_responses'; // For offline demo storage

const generateId = () => Math.random().toString(36).substring(2, 9) + Date.now().toString(36);

export const storageService = {

  init: () => {
    if (firebaseService.isInitialized()) return;

    // Check if config exists
    if (!FIREBASE_CONFIG.apiKey) {
        // console.warn("⚠️ App running in DEMO MODE (No Firebase Config detected).");
        return;
    }

    const success = firebaseService.init(FIREBASE_CONFIG);
    if (!success) console.warn("Running in local mode.");
  },

  isCloudEnabled: () => firebaseService.isInitialized(),
  testConnection: async () => firebaseService.testConnection(),

  getCurrentUser: (): User | null => {
    try {
        const stored = localStorage.getItem(USER_KEY);
        return stored ? JSON.parse(stored) : null;
    } catch (e) {
        return null;
    }
  },

  // ADMIN
  updateRegistrationCode: async (newCode: string): Promise<void> => {
      if (storageService.isCloudEnabled()) {
          await firebaseService.updateRegistrationCode(newCode);
      } else {
          // Local simulation
          localStorage.setItem('demo_reg_code', newCode);
      }
  },

  // LOGIN (EMAIL)
  login: async (email: string, password?: string): Promise<User> => {
    // 1. Try Cloud
    if (storageService.isCloudEnabled()) {
        const user = await firebaseService.findUserByEmail(email);
        if (user && user.password === password) {
             localStorage.setItem(USER_KEY, JSON.stringify(user));
             return user;
        }
    }

    // 2. Fallback / Local check (very basic for demo)
    const stored = localStorage.getItem(USER_KEY);
    if (stored) {
        const user = JSON.parse(stored);
        if (user.email === email) return user;
    }

    throw new Error("משתמש לא נמצא או סיסמה שגויה (נסה כניסה מהירה עם גוגל).");
  },

  // Explicit Demo Login
  loginAsGuest: async (): Promise<User> => {
     const demoUser: User = {
          id: 'demo-user-id',
          name: 'אורח (מצב הדגמה)',
          email: 'demo@guest.com',
          createdAt: Date.now()
      };
      localStorage.setItem(USER_KEY, JSON.stringify(demoUser));
      return demoUser;
  },

  // LOGIN (GOOGLE) - WITH DEMO FALLBACK
  loginWithGoogle: async (): Promise<User> => {
      // Attempt Real Login
      if (storageService.isCloudEnabled()) {
          try {
            const firebaseUser = await firebaseService.loginWithGoogle();
            if (!firebaseUser.email) throw new Error("No email from Google");

            let user = await firebaseService.findUserByEmail(firebaseUser.email);
            if (!user) {
                user = {
                    id: generateId(),
                    name: firebaseUser.displayName || firebaseUser.email.split('@')[0],
                    email: firebaseUser.email,
                    createdAt: Date.now()
                };
                await firebaseService.createUser(user);
            }
            localStorage.setItem(USER_KEY, JSON.stringify(user));
            return user;

          } catch (e) {
              console.warn("Cloud login failed, switching to Demo User", e);
          }
      }

      // Fallback: If cloud fails or isn't enabled, use Guest Login logic
      return storageService.loginAsGuest();
  },

  // REGISTER (With Access Code)
  registerUser: async (name: string, email: string, password?: string, registrationCode?: string): Promise<User> => {
    const isValidCode = registrationCode?.toUpperCase() === 'OBT-VIP' || registrationCode === localStorage.getItem('demo_reg_code');

    if (!registrationCode) throw new Error("נדרש קוד רישום.");

    // Cloud Validation
    if (storageService.isCloudEnabled()) {
        const cloudValid = await firebaseService.validateRegistrationCode(registrationCode);
        if (!cloudValid) throw new Error("קוד רישום שגוי.");

        const existing = await firebaseService.findUserByEmail(email);
        if (existing) throw new Error("המייל כבר קיים במערכת.");
    } else {
        if (!isValidCode) throw new Error("קוד רישום שגוי (דמו: OBT-VIP).");
    }

    const newUser: User = {
      id: generateId(),
      name,
      email,
      password,
      createdAt: Date.now(),
    };

    // Save
    if (storageService.isCloudEnabled()) {
        await firebaseService.createUser(newUser);
    }

    // Always save locally for session
    localStorage.setItem(USER_KEY, JSON.stringify(newUser));
    return newUser;
  },

  // RESET PASSWORD
  resetPassword: async (email: string, registrationCode: string, newPassword: string): Promise<void> => {
    if (storageService.isCloudEnabled()) {
        const isValid = await firebaseService.validateRegistrationCode(registrationCode);
        if (!isValid) throw new Error("קוד שגוי.");
        const user = await firebaseService.findUserByEmail(email);
        if (!user) throw new Error("משתמש לא נמצא.");
        await firebaseService.updatePassword(user.id, newPassword);
    } else {
        // Mock success
        await new Promise(r => setTimeout(r, 1000));
    }
  },

  logout: async () => {
    if (storageService.isCloudEnabled()) {
        await firebaseService.logout();
    }
    localStorage.removeItem(USER_KEY);
  },

  // DATA OPERATIONS (Hybrid Cloud/Local)

  addResponse: async (surveyId: string, relationship: RelationshipType, q1: string, q2: string) => {
    const newResponse: FeedbackResponse = {
      id: generateId(),
      surveyId,
      relationship,
      q1_change: q1,
      q2_actions: q2,
      timestamp: Date.now(),
    };

    if (storageService.isCloudEnabled()) {
      await firebaseService.addResponse(newResponse);
    } else {
        // Save to LocalStorage for Demo
        const existing = JSON.parse(localStorage.getItem(MOCK_RESPONSES_KEY) || '[]');
        existing.push(newResponse);
        localStorage.setItem(MOCK_RESPONSES_KEY, JSON.stringify(existing));
    }
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    let responses: FeedbackResponse[] = [];

    if (storageService.isCloudEnabled()) {
       try {
        responses = await firebaseService.getResponsesForUser(userId);
       } catch (e) { console.warn("Cloud fetch failed"); }
    }

    // Merge with local demo responses
    const local = JSON.parse(localStorage.getItem(MOCK_RESPONSES_KEY) || '[]');
    const userLocal = local.filter((r: FeedbackResponse) => r.surveyId === userId);

    // If no responses found at all (and it's a demo user), maybe add some fake ones for "Wow effect"?
    if (responses.length === 0 && userLocal.length === 0 && userId === 'demo-user-id') {
        return [
            { id: '1', surveyId: userId, relationship: 'manager', q1_change: 'לשחרר יותר שליטה ולסמוך על הצוות.', q2_actions: 'בודק כל אימייל שיוצא, נכנס לפרטים טכניים קטנים מדי.', timestamp: Date.now() },
            { id: '2', surveyId: userId, relationship: 'peer', q1_change: 'להיות יותר קשוב בישיבות צוות.', q2_actions: 'נוטה להתפרץ לדברי אחרים, מסתכל בטלפון בזמן שאחרים מדברים.', timestamp: Date.now() - 100000 },
            { id: '3', surveyId: userId, relationship: 'subordinate', q1_change: 'לתת פידבק חיובי, לא רק ביקורת.', q2_actions: 'שיחות המשוב מתמקדות רק במה לא עבד טוב.', timestamp: Date.now() - 200000 }
        ];
    }

    return [...responses, ...userLocal];
  },

  getUserNameById: async (userId: string): Promise<string> => {
    if (storageService.isCloudEnabled()) {
        const user = await firebaseService.getUser(userId);
        if (user) return user.name;
    }
    if (userId === 'demo-user-id') return "אורח (הדגמה)";

    // Fallback try local session
    const currentUser = storageService.getCurrentUser();
    if (currentUser && currentUser.id === userId) return currentUser.name;

    return "משתמש"; 
  }
};

storageService.init();

