                <div className="pt-8 text-center border-t border-white/5">
                    <Button type="submit" variant="primary" isLoading={isSending} className="w-full md:w-2/3 text-lg py-4 font-bold shadow-glow hover:shadow-[0_0_40px_rgba(249,115,22,0.5)] transform hover:-translate-y-1 transition-all duration-300">
                        שלח משוב
                    </Button>
                    <div className="mt-6 flex items-center justify-center gap-2 text-[10px] text-slate-500 uppercase tracking-widest opacity-60">
                        <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M5 9V7a5 5 0 0110 0v2a2 2 0 012 2v5a2 2 0 01-2 2H5a2 2 0 01-2-2v-5a2 2 0 012-2zm8-2v2H7V7a3 3 0 016 0z" clipRule="evenodd" /></svg>
                        <span>המידע מאובטח ומוצפן</span>
                    </div>
                </div>
            </form>
        </div>
      </div>
    </Layout>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהלים',
  'peer': 'קולגות',
  'subordinate': 'כפיפים',
  'friend': 'חברים',
  'other': 'אחר'
};

export const Dashboard: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [loadingData, setLoadingData] = useState(true);
  const [copied, setCopied] = useState(false);
  const [cloudError, setCloudError] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    // Check Cloud Status
    if (!storageService.isCloudEnabled()) {
        setCloudError(true);
    }

    const currentUser = storageService.getCurrentUser();
    if (!currentUser) {
      navigate('/');
      return;
    }
    setUser(currentUser);

    const loadData = async () => {
        setLoadingData(true);
        try {
            const data = await storageService.getResponsesForUser(currentUser.id);
            setResponses(data);
        } catch (e) {
            console.error(e);
        } finally {
            setLoadingData(false);
        }
    };
    loadData();
  }, [navigate]);

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses);
      setAnalysis(result);
    } catch (error) {
      console.error(error);
      alert("שגיאה בניתוח הנתונים. וודא שיש מפתח API תקין.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    if (!user) return;
    const baseUrl = window.location.href.split('#')[0];
    const cleanBase = baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl;
    const url = `${cleanBase}/#/survey/${user.id}`;

    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  const handleExport = () => {
      if(user) exportToWord(user, analysis, responses);
  };

  const groupResponses = (data: FeedbackResponse[]) => {
      const grouped: Record<string, FeedbackResponse[]> = {};
      data.forEach(r => {
          const key = r.relationship || 'other';
          if (!grouped[key]) grouped[key] = [];
          grouped[key].push(r);
      });
      return grouped;
  };

  if (!user) return null;
  const groupedResponses = groupResponses(responses);

  return (
    <Layout>
      <div className="pb-12">

        {/* Critical Cloud Error Banner */}
        {cloudError && (
            <div className="bg-rose-600/20 border border-rose-500 text-rose-200 p-4 rounded-xl mb-8 flex items-start gap-3">
                <span className="text-2xl">⚠️</span>
                <div>
                    <h3 className="font-bold">אין חיבור לענן (Firebase)</h3>
                    <p className="text-sm opacity-90">
                        המערכת פועלת במצב מקומי בלבד כי חסרים מפתחות התחברות. 
                        <br/>
                        <strong>המשמעות:</strong> הקישור האישי שלך לא יעבוד עבור אנשים אחרים והמידע שלהם לא יישמר. יש להגדיר משתני סביבה תקינים.
                    </p>
                </div>
            </div>
        )}

        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 pb-8 border-b border-white/5">
          <div>
            <span className="text-primary-500 font-bold uppercase tracking-widest text-xs mb-2 block">Dashboard</span>
            <h1 className="text-4xl font-heading font-bold text-white">
                שלום, {user.name}
            </h1>
            <p className="text-slate-400 mt-2 flex items-center gap-2">
                <span className={`w-2 h-2 rounded-full ${cloudError ? 'bg-rose-500' : 'bg-emerald-500 animate-pulse'}`}></span>
                סטטוס: {cloudError ? 'מנותק' : 'מחובר לענן'} • נאספו {responses.length} משובים
            </p>
          </div>
          <div className="flex flex-wrap gap-3">
             <Button onClick={copyLink} variant="secondary" className="whitespace-nowrap" disabled={cloudError}>
               {copied ? '✓ הועתק' : 'העתק קישור לשליחה'}
             </Button>
             <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost">
                יציאה
             </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Main Content (Responses) */}
          <div className="lg:col-span-8 space-y-10">

            {responses.length === 0 ? (
              <div className="glass-panel rounded-2xl p-16 text-center border-dashed border-2 border-white/10">
                <div className="w-20 h-20 bg-white/5 rounded-full flex items-center justify-center mx-auto mb-6 text-3xl shadow-inner animate-bounce-slow">
                    🚀
                </div>
                <h3 className="text-2xl font-heading font-semibold text-white mb-3">המסע שלך מתחיל כאן</h3>
                <p className="text-slate-400 max-w-sm mx-auto mb-8 leading-relaxed">
                    כדי להתחיל את תהליך הצמיחה, יש לשלוח את הקישור האישי שלך לאנשים שעובדים איתך.
                </p>
                <Button onClick={copyLink} variant="primary" disabled={cloudError}>
                    העתק קישור אישי
                </Button>
              </div>
            ) : (
              <div className="space-y-12">
                {Object.entries(groupedResponses).map(([rel, items]) => (
                   <div key={rel}>
                       <h3 className="text-lg font-bold text-primary-400 mb-5 flex items-center gap-3 uppercase tracking-wider">
                           {relationshipLabels[rel] || rel}
                           <span className="text-[10px] text-white bg-white/10 px-2 py-0.5 rounded-full">{items.length}</span>
                           <div className="h-px bg-white/10 flex-grow"></div>
                       </h3>

                       <div className="grid gap-4">
                            {items.map((resp) => (
                                <div key={resp.id} className="glass-panel p-6 rounded-xl hover:bg-white/5 transition-colors group border-l-4 border-l-transparent hover:border-l-primary-500">
                                    <div className="grid md:grid-cols-2 gap-6">
                                        <div>
                                            <div className="text-[10px] font-bold text-primary-500 uppercase tracking-widest mb-2">הדבר האחד לשינוי</div>
                                            <p className="text-slate-100 text-lg leading-relaxed">{resp.q1_change}</p>
                                        </div>
                                        <div className="md:border-r md:border-white/10 md:pr-6">
                                            <div className="text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">התנהגויות מעכבות</div>
                                            <p className="text-slate-400 text-sm italic">"{resp.q2_actions}"</p>
                                        </div>
                                    </div>
                                </div>
                            ))}
                       </div>
                   </div> 
                ))}
              </div>
            )}
          </div>

          {/* Sidebar (Analysis) */}
          <div className="lg:col-span-4">
            <div className="sticky top-28 space-y-6">

                 {/* Analysis Card */}
                 <div className="glass-panel rounded-2xl overflow-hidden shadow-glass border-t border-white/10">
                    <div className="bg-gradient-to-r from-midnight-800 to-midnight-900 p-6 border-b border-white/5">
                        <h2 className="text-xl font-heading font-semibold text-white flex items-center gap-2">
                            <span className="text-primary-500 text-2xl">✦</span> ניתוח AI
                        </h2>
                        <p className="text-slate-500 text-xs mt-1 uppercase tracking-widest">Powered by Gemini Pro</p>
                    </div>

                    <div className="p-6">
                        {!analysis ? (
                        <div className="text-center py-8">
                            <p className="text-slate-400 mb-8 text-sm leading-relaxed">
                            המערכת תסרוק את כל המשובים ותזקק עבורך את התובנה המדויקת ביותר לצמיחה.
                            </p>
                            <Button 
                            onClick={handleAnalyze} 
                            disabled={responses.length === 0}
                            isLoading={loadingAnalysis}
                            variant="primary"
                            className={`w-full shadow-lg ${responses.length > 0 ? 'animate-pulse' : ''}`}
                            >
                            צור דוח תובנות
                            </Button>
                        </div>
                        ) : (
                        <div className="space-y-6 animate-fade-in-up">
                            <div>
                                <h4 className="text-[10px] font-bold text-primary-400 uppercase tracking-widest mb-3">התובנה המרכזית</h4>
                                <p className="text-white font-medium text-lg leading-relaxed">{analysis.summary}</p>
                            </div>

                            <div className="bg-white/5 p-4 rounded-xl">
                                <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">נושאים חוזרים</h4>
                                <ul className="space-y-2">
                                    {analysis.keyThemes.map((theme, i) => (
                                    <li key={i} className="text-sm text-slate-300 flex items-start gap-2">
                                        <span className="w-1.5 h-1.5 rounded-full bg-primary-500 mt-1.5"></span>
                                        {theme}
                                    </li>
                                    ))}
                                </ul>
                            </div>

                            {analysis.groupAnalysis && (
                                <div className="pt-4 border-t border-white/5">
                                    <h4 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">פרספקטיבות</h4>
                                    <div className="space-y-4">
                                        {Object.entries(analysis.groupAnalysis).map(([key, val]) => (
                                            <div key={key}>
                                                <span className="text-xs font-bold text-white block mb-1">{relationshipLabels[key] || key}</span>
                                                <p className="text-xs text-slate-400 leading-relaxed">{val}</p>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            )}

                            <div className="bg-gradient-to-br from-primary-900/20 to-transparent p-5 rounded-xl border border-primary-500/20">
                                <h4 className="text-[10px] font-bold text-primary-400 uppercase tracking-widest mb-2">המלצה לביצוע</h4>
                                <p className="text-sm text-primary-100 font-medium italic">"{analysis.actionableAdvice}"</p>
                            </div>

                            <div className="space-y-3 pt-4">
                                <Button onClick={handleExport} variant="secondary" className="w-full">
                                    הורד כקובץ Word
                                </Button>
                                <button 
                                    onClick={handleAnalyze} 
                                    className="text-[10px] uppercase tracking-widest text-slate-500 hover:text-white w-full text-center transition-colors"
                                >
                                רענן ניתוח מחדש
                                </button>
                            </div>
                        </div>
                        )}
                    </div>
                 </div>
            </div>
          </div>

        </div>
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';

// SECURITY SETTING:
// Set this to 'true' to allow anyone to try the app without registering.
// Set this to 'false' to force users to have the Registration Code.
const ALLOW_GUEST_MODE = false;

export const Landing: React.FC = () => {
  const [view, setView] = useState<'login' | 'register' | 'reset'>('login');

  // Fields
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [registrationCode, setRegistrationCode] = useState(''); 

  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  // Connection State
  const [offlineMode, setOfflineMode] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    storageService.init();
    const isConnected = storageService.isCloudEnabled();

    if (!isConnected) {
        setOfflineMode(true);
    }
  }, []);

  const handleGoogleLogin = async () => {
    setError('');
    setIsLoading(true);
    try {
        await storageService.loginWithGoogle();
        navigate('/dashboard');
    } catch (err: any) {
        console.warn("Google login failed, forcing guest mode.");

        if (ALLOW_GUEST_MODE) {
             try {
                await storageService.loginAsGuest();
                navigate('/dashboard');
            } catch (e) {
                setError("התחברות נכשלה.");
            }
        } else {
             setError("התחברות נכשלה. אנא נסה להירשם עם אימייל וסיסמה.");
        }
    } finally {
        setIsLoading(false);
    }
  };

  const handleGuestLogin = async () => {
      setIsLoading(true);
      await storageService.loginAsGuest();
      setIsLoading(false);
      navigate('/dashboard');
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setIsLoading(true);

    try {
      if (offlineMode && !ALLOW_GUEST_MODE) throw new Error("המערכת באופליין וגישת אורחים חסומה.");
      if (offlineMode) throw new Error("המערכת במצב אופליין. ניתן להיכנס כאורח בלבד.");

      if (view === 'register') {
        if (!name || !email || !password || !registrationCode) throw new Error("נא למלא את כל השדות");
        await storageService.registerUser(name, email, password, registrationCode);
        navigate('/dashboard');
      } 
      else if (view === 'login') {
        if (!email || !password) throw new Error("נא למלא אימייל וסיסמה");
        await storageService.login(email, password);
        navigate('/dashboard');
      }
      else if (view === 'reset') {
         if (!email || !registrationCode || !password) throw new Error("חסרים פרטים לשיחזור");
         await storageService.resetPassword(email, registrationCode, password);
         setSuccessMsg("הסיסמה עודכנה. אפשר להתחבר.");
         setTimeout(() => setView('login'), 2000);
      }
    } catch (err: any) {
      console.error("Submit Error:", err);
      if (err.message.includes("auth")) setError("פרטים שגויים.");
      else setError(err.message || 'אירעה שגיאה.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Layout>
      <div className="flex flex-col items-center justify-center py-12 relative">

        {/* Connection Status Banner */}
        {offlineMode && (
             <div className="fixed top-20 left-0 right-0 z-50 flex justify-center px-4">
                 <div className="bg-amber-900/90 border border-amber-500 text-amber-100 px-6 py-3 rounded-xl shadow-2xl backdrop-blur-xl flex items-center gap-3">
                     <span className="text-xl">⚠️</span>
                     <div>
                         <p className="font-bold text-sm">מצב אופליין (הדגמה)</p>
                         <p className="text-xs opacity-80">לא זוהה חיבור לענן. הנתונים יישמרו מקומית בלבד.</p>
                     </div>
                 </div>
             </div>
        )}

        {/* Header */}
        <div className="text-center mb-12 relative">
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-32 h-32 bg-primary-500/20 rounded-full blur-[50px]"></div>
            <h1 className="relative text-5xl md:text-6xl font-heading font-bold text-white mb-4 tracking-tight">
                One Big <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary-400 to-primary-600">Thing</span>
            </h1>
            <p className="relative text-lg text-slate-400 max-w-md mx-auto leading-relaxed">
               פלטפורמת 360° חכמה לזיהוי מנוע הצמיחה המרכזי שלך.
            </p>
        </div>

        {/* Glass Card */}
        <div className="glass-panel w-full max-w-[420px] p-8 md:p-10 rounded-2xl relative overflow-hidden">

            <div className="mb-8 text-center">
                <h2 className="text-2xl font-heading font-semibold text-white">
                    {view === 'register' ? 'הצטרפות למערכת' : view === 'reset' ? 'שחזור גישה' : 'כניסה למנויים'}
                </h2>
                {view === 'login' && <p className="text-xs text-slate-500 mt-2">התחבר כדי לראות את המשובים שלך</p>}
