    setError('');
    setIsLoading(true);
    try {
        await storageService.loginWithGoogle();
        navigate('/dashboard');
    } catch (err: any) {
        console.warn("Google login failed", err);

        // Custom error handling for our new security restriction
        if (err.message && err.message.includes("קוד ההצטרפות")) {
             setError(err.message);
        } else {
             // Fallback for generic errors
             if (ALLOW_GUEST_MODE) {
                  try {
                     await storageService.loginAsGuest();
                     navigate('/dashboard');
