import { 
  getFirestore, 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where,
  limit,
  updateDoc
} from "firebase/firestore";
import type { Firestore } from "firebase/firestore";
import { initializeApp, getApp, getApps, FirebaseApp } from "firebase/app";
import { getAuth, GoogleAuthProvider, signInWithPopup, Auth, User as FirebaseUser } from "firebase/auth";
import { FirebaseConfig, User, FeedbackResponse } from "../types";

// Global instances
let app: FirebaseApp | null = null;
let db: Firestore | null = null;
let auth: Auth | null = null;

export const firebaseService = {
  init: (config: FirebaseConfig) => {
    console.log("------------------------------------------------");
    console.log("FIREBASE INIT START");
    console.log("API Key present:", config.apiKey ? "YES (Length: " + config.apiKey.length + ")" : "NO");
    console.log("Project ID:", config.projectId);
    console.log("Auth Domain:", config.authDomain);
    console.log("------------------------------------------------");

    if (!config.apiKey || config.apiKey.length === 0) {
        console.error("Firebase Init Failed: Missing API Key.");
        return false;
    }

    try {
      const apps = getApps();
      if (apps.length > 0) {
        console.log("Firebase App already exists, reusing.");
        app = getApp();
      } else {
        console.log("Initializing new Firebase App...");
        app = initializeApp(config);
      }

      db = getFirestore(app);
      auth = getAuth(app);

      console.log("Firebase services initialized successfully.");
      return true;
    } catch (e) {
      console.error("CRITICAL ERROR during Firebase Initialization:", e);
      db = null;
      app = null;
      auth = null;
      return false;
    }
  },

  isInitialized: () => {
      const initialized = !!db && !!auth;
      if (!initialized) console.warn("Firebase isInitialized check returned FALSE");
      return initialized;
  },

  testConnection: async (): Promise<boolean> => {
    if (!db) {
        console.error("testConnection failed: DB is null");
        return false;
    }
    try {
      console.log("Testing connection to Firestore...");
      const dummyRef = collection(db, "users");
      const q = query(dummyRef, limit(1));
      await getDocs(q);
      console.log("Connection test PASSED");
      return true;
    } catch (e: any) {
      if (e.code === 'permission-denied') {
          console.log("Connection verified (permission denied is expected without login)");
          return true;
      }
      console.error("Connection test FAILED:", e.code, e.message);
      return false;
    }
  },

  // --- Auth & Google Sign In ---

  loginWithGoogle: async (): Promise<FirebaseUser> => {
    if (!auth) {
        console.error("Login attempted but Auth is null");
        throw new Error("Auth not initialized - check console logs");
    }
    console.log("Starting Google Sign In...");
    const provider = new GoogleAuthProvider();
    try {
        const result = await signInWithPopup(auth, provider);
        console.log("Google Sign In Success:", result.user.email);
        return result.user;
    } catch (error: any) {
        console.error("Google Sign In Error Details:", error);
        console.error("Error Code:", error.code);
        console.error("Error Message:", error.message);
        throw error;
    }
  },

  logout: async (): Promise<void> => {
      if (auth) {
          await auth.signOut();
      }
  },

  // --- System Config (Registration Code) ---

  validateRegistrationCode: async (codeToCheck: string): Promise<boolean> => {
    if (!db) return false;
    const cleanCode = codeToCheck.trim().toUpperCase();

    try {
        const configRef = doc(db, "settings", "config");
        const docSnap = await getDoc(configRef);

        let validCode = "OBT-VIP"; 

        if (docSnap.exists()) {
            const data = docSnap.data();
            if (data.registrationCode) {
                validCode = data.registrationCode;
            }
        } 
        return cleanCode === validCode.toUpperCase();

    } catch (e) {
        console.warn("Error validating code (using fallback mode):", e);
        return cleanCode === "OBT-VIP";
    }
  },

  updateRegistrationCode: async (newCode: string): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    try {
        const configRef = doc(db, "settings", "config");
        await setDoc(configRef, { registrationCode: newCode }, { merge: true });
    } catch (e) {
        throw new Error("Failed to update registration code");
    }
  },

  // --- User Operations ---

  createUser: async (user: User): Promise<void> => {
    if (!db) throw new Error("System Error: Database not connected.");
    try {
      console.log("Creating user in Firestore:", user.id);
      const userRef = doc(db, "users", user.id);
      await setDoc(userRef, user);
      console.log("User created successfully");
    } catch (e: any) {
      console.error("Create User Error:", e);
      if (e.code === 'permission-denied') {
        throw new Error("שגיאת הרשאה. ייתכן וקוד הרישום לא נקלט כראוי, או שיש חסימת אבטחה.");
      }
      throw new Error("נכשל הרישום לענן. אנא נסה שוב.");
    }
  },

  updatePassword: async (userId: string, newPassword: string): Promise<void> => {
    if (!db) throw new Error("Database disconnected");
    try {
        const userRef = doc(db, "users", userId);
        await updateDoc(userRef, { password: newPassword });
    } catch (e) {
        console.error("Password update failed", e);
        throw new Error("עדכון סיסמה נכשל.");
    }
  },

  updateUserGoal: async (userId: string, goal: string): Promise<void> => {
    if (!db) throw new Error("Database disconnected");
    try {
        const userRef = doc(db, "users", userId);
        await updateDoc(userRef, { userGoal: goal });
    } catch (e) {
        console.error("User goal update failed", e);
        throw new Error("עדכון מטרה נכשל.");
    }
  },

  getUser: async (userId: string): Promise<User | null> => {
    if (!db) return null;
    try {
      const userRef = doc(db, "users", userId);
      const docSnap = await getDoc(userRef);
      if (docSnap.exists()) return docSnap.data() as User;
      return null;
    } catch (e) { return null; }
  },

  findUserByEmail: async (email: string): Promise<User | null> => {
    if (!db) return null;
    try {
      console.log("Searching for user by email:", email);
      const usersRef = collection(db, "users");
      const q = query(usersRef, where("email", "==", email));
      const querySnapshot = await getDocs(q);

      if (querySnapshot.empty) {
          console.log("User not found via email query");
          return null;
      }
      console.log("User found via email");
      return querySnapshot.docs[0].data() as User;
    } catch (e: any) {
      console.error("findUserByEmail Error:", e);
      if (e.code === 'permission-denied') throw new Error("permission-denied");
      throw e;
    }
  },

  // --- Response Operations ---

  addResponse: async (response: FeedbackResponse): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    try {
      const responseRef = doc(db, "responses", response.id);
      await setDoc(responseRef, response);
    } catch (e) {
      console.error("Add Response Error:", e);
      throw new Error("Failed to save response to cloud.");
    }
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (!db) return [];
    try {
      const responsesRef = collection(db, "responses");
      const q = query(responsesRef, where("surveyId", "==", userId));
      const querySnapshot = await getDocs(q);

      const responses: FeedbackResponse[] = [];
      querySnapshot.forEach((doc: any) => {
        responses.push(doc.data() as FeedbackResponse);
      });

      return responses.sort((a, b) => b.timestamp - a.timestamp);
    } catch (e) {
      console.error("Get Responses Error:", e);
      return [];
    }
  }
};

import { User, FeedbackResponse, FirebaseConfig, RelationshipType } from '../types';
import { firebaseService } from './firebaseService';

// =================================================================
// הגדרות FIREBASE (ממשתני סביבה בלבד)
// =================================================================

const FIREBASE_CONFIG: FirebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY || "",
  authDomain: process.env.FIREBASE_AUTH_DOMAIN || "",
  projectId: process.env.FIREBASE_PROJECT_ID || "",
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID || "",
  appId: process.env.FIREBASE_APP_ID || "",
  measurementId: process.env.FIREBASE_MEASUREMENT_ID || ""
}; 

// =================================================================

const USER_KEY = '360_user_session';

const generateId = () => Math.random().toString(36).substring(2, 9) + Date.now().toString(36);

export const storageService = {

  init: () => {
    if (firebaseService.isInitialized()) return;

    // Debug Log - helps diagnose connection issues
    if (FIREBASE_CONFIG.apiKey) {
        console.log("Initializing Storage Service with Key: " + FIREBASE_CONFIG.apiKey.substring(0, 4) + "...");
        const success = firebaseService.init(FIREBASE_CONFIG);
        if (!success) console.error("Failed to connect to Firebase Cloud.");
    } else {
        console.warn("Storage Init: No API Key found. App will run in Offline/Demo mode.");
    }
  },

  isCloudEnabled: () => firebaseService.isInitialized(),
  testConnection: async () => firebaseService.testConnection(),

  getCurrentUser: (): User | null => {
    try {
        const stored = localStorage.getItem(USER_KEY);
        return stored ? JSON.parse(stored) : null;
    } catch (e) {
        return null;
    }
  },

  // ADMIN
  updateRegistrationCode: async (newCode: string): Promise<void> => {
      if (storageService.isCloudEnabled()) {
          await firebaseService.updateRegistrationCode(newCode);
      } else {
          throw new Error("אין חיבור לענן. לא ניתן לעדכן קוד.");
      }
  },

  // LOGIN (EMAIL)
  login: async (email: string, password?: string): Promise<User> => {
    // Must be cloud based
    if (!storageService.isCloudEnabled()) throw new Error("מצב אופליין: לא ניתן להתחבר עם חשבון קיים.");

    const user = await firebaseService.findUserByEmail(email);
    if (user && user.password === password) {
            localStorage.setItem(USER_KEY, JSON.stringify(user));
            return user;
    }

    throw new Error("משתמש לא נמצא או סיסמה שגויה.");
  },

  // CLOUD GUEST LOGIN (Anonymous Session that SAVES to DB)
  loginAsGuest: async (): Promise<User> => {
     // 1. Generate a UNIQUE real ID
     const guestId = generateId();

     // 2. Create User Object
     const guestUser: User = {
          id: guestId,
          name: 'אורח מערכת', 
          email: `guest_${guestId}@obt.system`, // Fake email identifier
          createdAt: Date.now()
      };

      // 3. Save to Cloud DB so links work for others
      if (storageService.isCloudEnabled()) {
           try {
            await firebaseService.createUser(guestUser);
           } catch (e) {
             console.error("Cloud creation failed", e);
             throw new Error("שגיאה ביצירת משתמש ענן. אנא בדוק חיבור אינטרנט.");
           }
      } else {
           console.warn("Running in Offline Mode: Guest user created locally only.");
      }

      localStorage.setItem(USER_KEY, JSON.stringify(guestUser));
      return guestUser;
  },

  // REGISTER (With Access Code)
  registerUser: async (name: string, email: string, password?: string, registrationCode?: string): Promise<User> => {
    if (!storageService.isCloudEnabled()) throw new Error("מצב אופליין: לא ניתן להירשם.");

    if (!registrationCode) throw new Error("נדרש קוד רישום.");

    const cloudValid = await firebaseService.validateRegistrationCode(registrationCode);
    if (!cloudValid) throw new Error("קוד רישום שגוי.");

    const existing = await firebaseService.findUserByEmail(email);
    if (existing) throw new Error("המייל כבר קיים במערכת.");

    const newUser: User = {
      id: generateId(),
      name,
      email,
      password,
      createdAt: Date.now(),
    };

    await firebaseService.createUser(newUser);

    localStorage.setItem(USER_KEY, JSON.stringify(newUser));
    return newUser;
  },

  // UPDATE USER GOAL
  updateUserGoal: async (userId: string, goal: string): Promise<void> => {
      // 1. Update Local Storage
      const currentUser = storageService.getCurrentUser();
      if (currentUser && currentUser.id === userId) {
          const updatedUser = { ...currentUser, userGoal: goal };
          localStorage.setItem(USER_KEY, JSON.stringify(updatedUser));
      }

      // 2. Update Cloud
      if (storageService.isCloudEnabled()) {
          await firebaseService.updateUserGoal(userId, goal);
      }
  },

  // RESET PASSWORD
  resetPassword: async (email: string, registrationCode: string, newPassword: string): Promise<void> => {
    if (!storageService.isCloudEnabled()) throw new Error("אין חיבור לענן.");

    const isValid = await firebaseService.validateRegistrationCode(registrationCode);
    if (!isValid) throw new Error("קוד שגוי.");
    const user = await firebaseService.findUserByEmail(email);
    if (!user) throw new Error("משתמש לא נמצא.");
    await firebaseService.updatePassword(user.id, newPassword);
  },

  logout: async () => {
    if (storageService.isCloudEnabled()) {
        await firebaseService.logout();
    }
    localStorage.removeItem(USER_KEY);
  },

  // DATA OPERATIONS

  addResponse: async (surveyId: string, relationship: RelationshipType, q1: string, q2: string) => {
    const newResponse: FeedbackResponse = {
      id: generateId(),
      surveyId,
      relationship,
      q1_change: q1,
      q2_actions: q2,
      timestamp: Date.now(),
    };

    if (storageService.isCloudEnabled()) {
      await firebaseService.addResponse(newResponse);
    } else {
        throw new Error("שגיאה: במצב אופליין לא ניתן לשמור תשובות.");
    }
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (storageService.isCloudEnabled()) {
       try {
        return await firebaseService.getResponsesForUser(userId);
       } catch (e) { 
           console.error("Cloud fetch failed", e);
           return [];
       }
    }
    return [];
  },

  getUserDataById: async (userId: string): Promise<{name: string, userGoal?: string}> => {
    if (storageService.isCloudEnabled()) {
        const user = await firebaseService.getUser(userId);
        if (user) return { name: user.name, userGoal: user.userGoal };
    }
    // Only fallback to session if it matches
    const currentUser = storageService.getCurrentUser();
    if (currentUser && currentUser.id === userId) return { name: currentUser.name, userGoal: currentUser.userGoal };

    return { name: "משתמש" }; 
  }
};

