import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) {
    throw new Error("No responses to analyze");
  }

  const ai = getClient();

  // Format data for AI
  const formattedData = responses.map(r => ({
      relationship: r.relationship,
      feedbackOnGoal: r.q1_change,
      contradictions: r.q2_actions
  }));

  const goalContext = userGoal 
    ? `The user defined their growth goal as: "${userGoal}".`
    : `The user did NOT define a specific goal, so the feedback is general.`;

  const prompt = `
    תפקידך הוא להיות פסיכולוג ארגוני ומאמן קריירה בכיר.

    הקשר:
    ${goalContext}

    המשימה:
    יש לנתח את המשובים שהתקבלו. השאלה הראשונה שנשאלה הייתה "האם המטרה הזו תקפיץ את האדם מדרגה? דייק או נסח מחדש".

    1. בדוק האם הסביבה מסכימה עם המטרה שהאדם הציב לעצמו? האם הם מציעים לדייק אותה? אם כן, איך?
    2. זהה את "הדבר האחד" האמיתי (בין אם הוא תואם את מה שהמשתמש חשב ובין אם לא).
    3. נתח נושאים חוזרים בהתנהגויות המעכבות.
    4. נתח הבדלים בין הקבוצות השונות (מנהל, כפיף, וכו').
    5. תן עצה מעשית לביצוע.

    הנתונים:
    ${JSON.stringify(formattedData)}
  `;

  try {
    const result = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: "You are an expert organizational psychologist speaking Hebrew. Focus on alignment between self-perception and external feedback.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: {
              type: Type.STRING,
              description: "A summary of whether the feedback validates the user's goal or suggests a different focus.",
            },
            keyThemes: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "List of 3-5 recurring themes (refinements to the goal or blocking behaviors).",
            },
            actionableAdvice: {
              type: Type.STRING,
              description: "A specific, encouraging piece of advice based on the gap (or alignment) between the user's goal and the feedback.",
            },
            groupAnalysis: {
                type: Type.OBJECT,
                description: "A dictionary where key is the group name (e.g. 'Manager', 'Peer') and value is a short insight about that group's perspective.",
                properties: {
                    "manager": { type: Type.STRING },
                    "peer": { type: Type.STRING },
                    "subordinate": { type: Type.STRING },
                    "friend": { type: Type.STRING },
                    "other": { type: Type.STRING }
                }
            }
          },
          required: ["summary", "keyThemes", "actionableAdvice", "groupAnalysis"],
        },
      },
    });

    const text = result.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw new Error("Failed to analyze feedback.");
  }
};

import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } from "docx";
import { AnalysisResult, FeedbackResponse, User } from "../types";

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהלים',
  'peer': 'קולגות',
  'subordinate': 'כפיפים',
  'friend': 'חברים/משפחה',
  'other': 'אחר'
};

export const exportToWord = async (
  user: User, 
  analysis: AnalysisResult | null, 
  responses: FeedbackResponse[]
) => {
  const doc = new Document({
    sections: [{
      properties: {},
      children: [
        // Title
        new Paragraph({
          text: `דוח צמיחה אישי 360 - ${user.name}`,
          heading: HeadingLevel.HEADING_1,
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
          bidirectional: true,
        }),
        new Paragraph({
            text: `תאריך הפקה: ${new Date().toLocaleDateString('he-IL')}`,
            alignment: AlignmentType.CENTER,
            spacing: { after: 600 },
            bidirectional: true,
        }),

        // Analysis Section (if exists)
        ...(analysis ? [
            new Paragraph({
                text: "סיכום תובנות (AI Analysis)",
                heading: HeadingLevel.HEADING_2,
                bidirectional: true,
                spacing: { before: 400, after: 200 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "הדבר האחד לפריצת דרך:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { after: 100 }
            }),
            new Paragraph({
                text: analysis.summary,
                bidirectional: true,
                spacing: { after: 300 }
            }),
            // Group Analysis
            ...(analysis.groupAnalysis ? [
                 new Paragraph({
                    children: [new TextRun({ text: "תובנות לפי קבוצות:", bold: true, size: 24, rightToLeft: true })],
                    bidirectional: true,
                    spacing: { before: 200, after: 100 }
                }),
                ...Object.entries(analysis.groupAnalysis).map(([key, val]) => new Paragraph({
                    children: [
                        new TextRun({ text: `${relationshipLabels[key] || key}: `, bold: true }),
                        new TextRun({ text: val })
                    ],
                    bidirectional: true,
                    bullet: { level: 0 }
                }))
            ] : []),
            new Paragraph({
                children: [
                    new TextRun({ text: "המלצה לפעולה:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { before: 300 }
            }),
            new Paragraph({
                text: analysis.actionableAdvice,
                bidirectional: true,
            }),
            new Paragraph({ text: "", spacing: { after: 600 } }) // Spacer
        ] : []),

        // Raw Responses
        new Paragraph({
            text: "תשובות גולמיות (אנונימי)",
            heading: HeadingLevel.HEADING_2,
            bidirectional: true,
            spacing: { after: 200 }
        }),

        ...responses.flatMap((res, index) => [
            new Paragraph({
                children: [
                    new TextRun({ text: `משיב #${index + 1}`, bold: true, color: "888888" }),
                    new TextRun({ text: ` | ${relationshipLabels[res.relationship] || 'אחר'}`, color: "888888" })
                ],
                bidirectional: true,
                spacing: { before: 200, after: 100 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "1. הדבר לשינוי: ", bold: true }),
                    new TextRun({ text: res.q1_change })
                ],
                bidirectional: true,
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "2. פעולות סותרות: ", bold: true }),
                    new TextRun({ text: res.q2_actions })
                ],
                bidirectional: true,
                spacing: { after: 300 },
                border: { bottom: { color: "cccccc", space: 1, value: "single", size: 6 } }
            })
        ])
      ],
    }],
  });

  const blob = await Packer.toBlob(doc);
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `Growth_Report_${user.name.replace(/\s+/g, '_')}.docx`;
  a.click();
  window.URL.revokeObjectURL(url);
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {

  const baseStyles = "relative inline-flex items-center justify-center px-6 py-2 rounded font-medium text-sm transition-all duration-200 disabled:opacity-50 disabled:cursor-not-allowed tracking-wide";

  const variants = {
    // Bronze Primary
    primary: "bg-bronze-700 hover:bg-bronze-600 text-white shadow-lg border border-bronze-600/50",

    // Onyx Dark
    secondary: "bg-onyx-700 hover:bg-onyx-600 text-onyx-100 border border-onyx-600",

    // Bronze Outline
    outline: "bg-transparent text-bronze-400 border border-bronze-700 hover:bg-bronze-700/10",

    // Minimal
    ghost: "bg-transparent text-onyx-400 hover:text-onyx-100 hover:bg-onyx-800"
  };

  const finalClassName = `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <>
          <svg className="animate-spin -mr-1 ml-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
