                <input 
                  type="email" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  className={`dark-input ${lang === 'he' ? 'text-right' : 'text-left'}`} 
                  placeholder={t.email} 
                  dir="ltr"
