import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";
import { translations } from "../translations";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const lang = (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he';
  const t = translations[lang];
  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      impact: r.q1_change,
      contradictions: r.q2_actions
  }));

  const prompt = `
    Role: World-Class Executive Coach & Organizational Psychologist.
    Task: Conduct a high-level 360 synthesis for an individual.

    Context:
    Individual's Stated Goal: "${userGoal || 'Not specified'}"
    Feedback Data: ${JSON.stringify(rawData)}

    Instructions:
    1. Language: Write the entire report in ${lang === 'he' ? 'Hebrew' : 'English'}.
    2. Deep Dive: Don't just summarize. Identify "Blind Spots" and "Unconscious Patterns".
    3. Goal Precision: Evaluate if their current goal is actually their "One Big Thing" or just a symptom.
    4. Quality: Use sophisticated, professional, and empowering language.

    Output Format: Strict JSON matching the defined schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: `You analyze 360 feedback with extreme precision. You are helpful, insightful, and direct. Use the provided JSON schema.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique: { type: Type.STRING },
                    refinedGoal: { type: Type.STRING }
                },
                required: ["score", "critique", "refinedGoal"]
            },
            executiveSummary: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    alignmentLevel: { type: Type.STRING }
                },
                required: ["opportunities", "alignmentLevel"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns: { type: Type.STRING }
                },
                required: ["blockers", "psychologicalPatterns"]
            },
            theOneBigThing: { type: Type.STRING },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        content: { type: Type.STRING }
                    }
                }
            },
            groupPerspectives: {
                type: Type.OBJECT,
                properties: {
                    "manager": { type: Type.STRING },
                    "peer": { type: Type.STRING },
                    "subordinate": { type: Type.STRING },
                    "other": { type: Type.STRING }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary", "question1Analysis", "question2Analysis", "theOneBigThing", "actionPlan", "groupPerspectives"],
        },
      },
    });

    return JSON.parse(response.text || '{}') as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("Analysis failed. Please try again.");
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');
    if (!currentUser.userGoal) setIsEditingGoal(true);
    storageService.getResponsesForUser(currentUser.id).then(setResponses);
  }, [navigate]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
  };

  const handleAnalyze = async () => {
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses, user?.userGoal);
      setAnalysis(result);
    } catch (error) {
      alert("Analysis encounterd an issue. Check responses count.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.href.split('#')[0];
    const url = `${baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl}/#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return null;

  return (
    <Layout>
      <div className="pb-20">
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 pb-8 border-b border-onyx-800">
          <div>
            <span className="text-bronze-500 font-bold tracking-widest text-xs uppercase mb-2 block">Workspace Control</span>
            <h1 className="text-4xl font-heading text-onyx-100">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-onyx-400 mt-2">{t.feedbacksCollected}: <span className="text-onyx-100 font-bold">{responses.length}</span></p>
          </div>
          <div className="flex gap-4">
            <Button onClick={copyLink} variant="outline" className="rounded-full">{copied ? t.linkCopied : t.copyLink}</Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost">{t.logout}</Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          {/* Left Column: Input & Responses */}
          <div className="lg:col-span-4 space-y-8">
            <div className="glass-panel border-l-4 border-l-bronze-500">
                <div className="flex justify-between items-start mb-4">
                    <h3 className="text-sm font-bold text-onyx-400 uppercase tracking-tighter">🎯 {t.myGoal}</h3>
                    <button onClick={() => setIsEditingGoal(true)} className="text-bronze-500 text-xs hover:underline">{t.edit}</button>
                </div>
                {isEditingGoal ? (
                    <div className="space-y-4">
                        <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm" rows={4} placeholder={t.goalHint} />
                        <div className="flex gap-2">
                            <Button onClick={handleSaveGoal} className="px-4 py-1.5 text-xs">{t.save}</Button>
                            <button onClick={() => setIsEditingGoal(false)} className="text-onyx-500 text-xs px-2">{t.cancel}</button>
                        </div>
                    </div>
                ) : (
                    <p className="text-lg font-light leading-relaxed text-onyx-200">"{goal || '...'}"</p>
                )}
            </div>

