import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } from "docx";
import { AnalysisResult, FeedbackResponse, User } from "../types";

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהלים',
  'peer': 'קולגות',
  'subordinate': 'כפיפים',
  'friend': 'חברים/משפחה',
  'other': 'אחר'
};

export const exportToWord = async (
  user: User, 
  analysis: AnalysisResult | null, 
  responses: FeedbackResponse[]
) => {
  const doc = new Document({
    sections: [{
      properties: {},
      children: [
        // Title
        new Paragraph({
          text: `דוח צמיחה אישי 360 - ${user.name}`,
          heading: HeadingLevel.HEADING_1,
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
          bidirectional: true,
        }),
        new Paragraph({
            text: `תאריך הפקה: ${new Date().toLocaleDateString('he-IL')}`,
            alignment: AlignmentType.CENTER,
            spacing: { after: 600 },
            bidirectional: true,
        }),

        // Analysis Section (if exists)
        ...(analysis ? [
            new Paragraph({
                text: "סיכום תובנות (AI Analysis)",
                heading: HeadingLevel.HEADING_2,
                bidirectional: true,
                spacing: { before: 400, after: 200 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "הדבר האחד לפריצת דרך:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { after: 100 }
            }),
            // FIX: Property 'summary' does not exist on type 'AnalysisResult'. Changed to 'executiveSummary'
            new Paragraph({
                text: analysis.executiveSummary,
                bidirectional: true,
                spacing: { after: 300 }
            }),
            // Group Analysis
            // FIX: Property 'groupAnalysis' does not exist on type 'AnalysisResult'. Changed to 'groupPerspectives'
            ...(analysis.groupPerspectives ? [
                 new Paragraph({
                    children: [new TextRun({ text: "תובנות לפי קבוצות:", bold: true, size: 24, rightToLeft: true })],
                    bidirectional: true,
                    spacing: { before: 200, after: 100 }
                }),
                ...Object.entries(analysis.groupPerspectives).map(([key, val]) => new Paragraph({
                    children: [
                        new TextRun({ text: `${relationshipLabels[key] || key}: `, bold: true }),
                        new TextRun({ text: val as string })
                    ],
                    bidirectional: true,
                    bullet: { level: 0 }
                }))
            ] : []),
            new Paragraph({
                children: [
                    new TextRun({ text: "תכנית פעולה:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { before: 300 }
            }),
            // FIX: Property 'actionableAdvice' does not exist on type 'AnalysisResult'. Using 'theOneBigThing' or first action plan item.
            new Paragraph({
                text: analysis.theOneBigThing,
                bidirectional: true,
            }),
            ...analysis.actionPlan.map(step => new Paragraph({
                children: [
                    new TextRun({ text: `${step.title}: `, bold: true }),
                    new TextRun({ text: step.content })
                ],
                bidirectional: true,
                bullet: { level: 0 }
            })),
            new Paragraph({ text: "", spacing: { after: 600 } }) // Spacer
        ] : []),

        // Raw Responses
        new Paragraph({
            text: "תשובות גולמיות (אנונימי)",
            heading: HeadingLevel.HEADING_2,
            bidirectional: true,
            spacing: { after: 200 }
        }),

        ...responses.flatMap((res, index) => [
            new Paragraph({
                children: [
                    new TextRun({ text: `משיב #${index + 1}`, bold: true, color: "888888" }),
                    new TextRun({ text: ` | ${relationshipLabels[res.relationship] || 'אחר'}`, color: "888888" })
                ],
                bidirectional: true,
                spacing: { before: 200, after: 100 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "1. הדבר לשינוי: ", bold: true }),
                    new TextRun({ text: res.q1_change })
                ],
                bidirectional: true,
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "2. פעולות סותרות: ", bold: true }),
                    new TextRun({ text: res.q2_actions })
                ],
                bidirectional: true,
                spacing: { after: 300 },
                border: { bottom: { color: "cccccc", space: 1, value: "single", size: 6 } }
            })
        ])
      ],
    }],
  });

  const blob = await Packer.toBlob(doc);
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `Growth_Report_${user.name.replace(/\s+/g, '_')}.docx`;
  a.click();
  window.URL.revokeObjectURL(url);
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";
import { translations } from "../translations";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const lang = (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he';
  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      impact: r.q1_change,
      contradictions: r.q2_actions
  }));

  const prompt = `
    Role: Senior Executive Coach & Behavioral Psychologist.
    Task: Synthesize a high-stakes 360 feedback report.

    Context:
    The individual's stated growth goal: "${userGoal || 'Not specified'}"
    The collective feedback data: ${JSON.stringify(rawData)}

    Instructions:
    1. Analysis Level: Extremely deep. Look for the "Golden Thread" connecting the feedbacks.
    2. Precision Check: Evaluate if the individual's goal is truly the highest leverage point or if the feedback suggests a deeper, more urgent "One Big Thing".
    3. Output Language: ${lang === 'he' ? 'Hebrew' : 'English'}.
    4. Quality: Use high-end professional vocabulary (Executive level).

    Expected Structure:
    - goalPrecision: Score (0-100) and a sophisticated critique of how aligned the goal is with external reality.
    - executiveSummary: A narrative synthesis of the situation.
    - question1Analysis: Key opportunities and alignment.
    - question2Analysis: Critical blockers and unconscious psychological patterns discovered.
    - theOneBigThing: The single, most powerful shift this person must make.
    - actionPlan: 3-5 high-resolution strategic steps.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: `You are an elite organizational psychologist. You provide world-class, deep, and actionable 360 feedback synthesis in JSON format.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique: { type: Type.STRING },
                    refinedGoal: { type: Type.STRING }
                },
                required: ["score", "critique", "refinedGoal"]
            },
            executiveSummary: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    alignmentLevel: { type: Type.STRING }
                },
                required: ["opportunities", "alignmentLevel"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns: { type: Type.STRING }
                },
                required: ["blockers", "psychologicalPatterns"]
            },
            theOneBigThing: { type: Type.STRING },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        content: { type: Type.STRING }
                    }
                }
            },
            groupPerspectives: {
                type: Type.OBJECT,
                properties: {
                    "manager": { type: Type.STRING },
                    "peer": { type: Type.STRING },
                    "subordinate": { type: Type.STRING },
                    "other": { type: Type.STRING }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary", "question1Analysis", "question2Analysis", "theOneBigThing", "actionPlan", "groupPerspectives"],
        },
      },
    });

    return JSON.parse(response.text || '{}') as AnalysisResult;
  } catch (error) {
    console.error("Gemini Synthesis Error:", error);
    throw new Error("Analysis synthesis failed.");
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');
    if (!currentUser.userGoal) setIsEditingGoal(true);
    storageService.getResponsesForUser(currentUser.id).then(setResponses);
  }, [navigate]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
  };

  const handleAnalyze = async () => {
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses, user?.userGoal);
      setAnalysis(result);
    } catch (error) {
      alert("Analysis encounterd an issue. Check your connection.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.href.split('#')[0];
    const url = `${baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl}/#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return null;

  return (
    <Layout>
      <div className="pb-24">
        {/* Upper Dashboard Controls */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-16 pb-8 border-b border-onyx-800">
          <div className="space-y-1">
            <span className="text-bronze-500 font-bold tracking-[0.2em] text-[10px] uppercase block">Analysis Hub</span>
            <h1 className="text-4xl md:text-5xl font-heading font-light text-onyx-100">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-onyx-500 text-sm">{t.feedbacksCollected}: <span className="text-bronze-400 font-mono font-bold">{responses.length}</span></p>
          </div>
          <div className="flex flex-wrap gap-3">
            <Button onClick={copyLink} variant="outline" className="rounded-full border-onyx-700 text-onyx-300 hover:border-bronze-500">
                <span className="flex items-center gap-2">
                    <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M10 13a5 5 0 0 0 7.54.54l3-3a5 5 0 0 0-7.07-7.07l-1.72 1.71"/><path d="M14 11a5 5 0 0 0-7.54-.54l-3 3a5 5 0 0 0 7.07 7.07l1.71-1.71"/></svg>
                    {copied ? t.linkCopied : t.copyLink}
                </span>
            </Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost" className="text-xs uppercase tracking-widest">{t.logout}</Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          {/* Sidebar / Context */}
          <div className="lg:col-span-4 space-y-10">
            <div className="glass-panel border-l-2 border-l-bronze-500/50 bg-onyx-800/20">
                <div className="flex justify-between items-center mb-6">
                    <h3 className="text-xs font-black text-onyx-500 uppercase tracking-widest">{t.myGoal}</h3>
                    <button onClick={() => setIsEditingGoal(true)} className="text-bronze-500 text-[10px] uppercase font-bold hover:text-bronze-400 transition-colors tracking-tighter">{t.edit}</button>
                </div>
                {isEditingGoal ? (
                    <div className="space-y-4">
                        <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm bg-onyx-950/50" rows={5} placeholder={t.goalHint} />
                        <div className="flex gap-2">
                            <Button onClick={handleSaveGoal} className="px-5 py-1 text-xs">{t.save}</Button>
                            <button onClick={() => setIsEditingGoal(false)} className="text-onyx-600 text-xs px-2 hover:text-onyx-400">✕</button>
