import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      impact: r.q1_change,
      contradictions: r.q2_actions
  }));

  // פומפט מזוקק וברור יותר למניעת תקיעות
  const prompt = `
    תפקיד: פסיכולוג ארגוני בכיר ומאמן מנהלים.
    משימה: ניתוח משוב 360 וגיבוש אסטרטגיית צמיחה.

    נתוני המשתמש:
    המטרה שהוגדרה: "${userGoal || 'לא הוגדרה'}"
    משובים גולמיים: ${JSON.stringify(rawData)}

    הנחיות קריטיות:
    1. שפה: כתוב את כל הטקסטים בעברית רהוטה ומקצועית.
    2. עומק: זהה את "הדבר האחד" (The One Big Thing) שיהווה את פריצת הדרך.
    3. פורמט: החזר אך ורק JSON תקין התואם ל-Schema. אל תוסיף טקסט חופשי לפני או אחרי ה-JSON.

    מבנה ה-JSON הנדרש:
    - goalPrecision: ציון (0-100), ביקורת בונה, וניסוח מחדש של המטרה.
    - executiveSummary: סיכום מנהלים מזוקק.
    - theOneBigThing: התובנה המרכזית לפריצת הדרך.
    - question1Analysis: הזדמנויות ורמת הלימה.
    - question2Analysis: חסמים ודפוסים פסיכולוגיים מעכבים.
    - actionPlan: 3-4 צעדים אופרטיביים (title ו-content).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', // שימוש במודל Flash לביצועים מהירים יותר במשימות טקסט
      contents: prompt,
      config: {
        systemInstruction: `אתה מומחה לניתוח פסיכולוגי ארגוני. עליך לספק ניתוח מעמיק בעברית בלבד בתצורת JSON. אל תשתמש במילים באנגלית בתוך הערכים, למעט מושגים מקצועיים הכרחיים.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique: { type: Type.STRING },
                    refinedGoal: { type: Type.STRING }
                },
                required: ["score", "critique", "refinedGoal"]
            },
            executiveSummary: { type: Type.STRING },
            theOneBigThing: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    alignmentLevel: { type: Type.STRING }
                },
                required: ["opportunities", "alignmentLevel"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns: { type: Type.STRING }
                },
                required: ["blockers", "psychologicalPatterns"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        content: { type: Type.STRING }
                    },
                    required: ["title", "content"]
                }
            },
            groupPerspectives: {
                type: Type.OBJECT,
                properties: {
                    manager: { type: Type.STRING },
                    peer: { type: Type.STRING },
                    subordinate: { type: Type.STRING },
                    other: { type: Type.STRING }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary", "theOneBigThing", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    if (!response.text) throw new Error("Empty response from AI");
    return JSON.parse(response.text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("הניתוח נכשל. אנא נסה שוב.");
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');
    if (!currentUser.userGoal) setIsEditingGoal(true);
    storageService.getResponsesForUser(currentUser.id).then(setResponses);
  }, [navigate]);

  useEffect(() => {
    if (loadingAnalysis) {
      const messages = [
        "סורק משובים...",
        "מזהה דפוסים פסיכולוגיים...",
        "מגבש תובנות אסטרטגיות...",
        "מנסח את ה-One Big Thing שלך...",
        "כמעט מוכן..."
      ];
      let i = 0;
      const interval = setInterval(() => {
        setLoadingMessage(messages[i % messages.length]);
        i++;
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loadingAnalysis]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
  };

  const handleAnalyze = async () => {
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses, user?.userGoal);
      setAnalysis(result);
    } catch (error) {
      alert("הניתוח נכשל. וודא שיש לפחות משוב אחד במערכת.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.href.split('#')[0];
    const url = `${baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl}/#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return null;

  return (
    <Layout>
      <div className="pb-24">
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 pb-8 border-b border-onyx-800">
          <div>
            <span className="text-bronze-500 font-bold tracking-widest text-[10px] uppercase mb-2 block">מרכז בקרה</span>
            <h1 className="text-4xl font-heading text-white">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-onyx-400 mt-2">{t.feedbacksCollected}: <span className="text-bronze-500 font-bold">{responses.length}</span></p>
          </div>
          <div className="flex gap-4">
            <Button onClick={copyLink} variant="outline" className="rounded-full border-bronze-500/30 text-bronze-500">
              {copied ? t.linkCopied : t.copyLink}
            </Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost" className="text-onyx-500">
              {t.logout}
            </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Left Column: Context & Responses */}
          <div className="lg:col-span-4 space-y-8">
            <div className="glass-panel p-6 border-r-4 border-r-bronze-500/50">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xs font-bold text-onyx-400 uppercase tracking-tighter">🎯 {t.myGoal}</h3>
                    <button onClick={() => setIsEditingGoal(true)} className="text-bronze-500 text-[10px] uppercase hover:underline">{t.edit}</button>
                </div>
                {isEditingGoal ? (
                    <div className="space-y-4">
                        <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm p-4 rounded-lg" rows={4} placeholder={t.goalHint} />
                        <div className="flex gap-2">
                            <Button onClick={handleSaveGoal} className="px-4 py-1.5 text-xs bg-bronze-600">שמור מטרה</Button>
                            <button onClick={() => setIsEditingGoal(false)} className="text-onyx-500 text-xs">ביטול</button>
                        </div>
                    </div>
