import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      impact: r.q1_change,
      contradictions: r.q2_actions
  }));

  const prompt = `
    תפקיד: פסיכולוג ארגוני בכיר.
    משימה: ניתוח משוב 360 וגיבוש תובנות.

    המטרה שהמשתמש הגדיר: "${userGoal || 'לא הוגדרה'}"
    משובים: ${JSON.stringify(rawData)}

    הנחיות:
    1. כתוב את כל התשובות בעברית בלבד.
    2. זהה את ה-One Big Thing שיביא לפריצת דרך.
    3. החזר JSON תקין בלבד.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        systemInstruction: `אתה מומחה לניתוח פסיכולוגי. עליך להחזיר אובייקט JSON בעברית בלבד.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique: { type: Type.STRING },
                    refinedGoal: { type: Type.STRING }
                },
                required: ["score", "critique", "refinedGoal"]
            },
            executiveSummary: { type: Type.STRING },
            theOneBigThing: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    alignmentLevel: { type: Type.STRING }
                },
                required: ["opportunities", "alignmentLevel"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns: { type: Type.STRING }
                },
                required: ["blockers", "psychologicalPatterns"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        content: { type: Type.STRING }
                    },
                    required: ["title", "content"]
                }
            },
            groupPerspectives: {
                type: Type.OBJECT,
                properties: {
                    manager: { type: Type.STRING },
                    peer: { type: Type.STRING },
                    subordinate: { type: Type.STRING },
                    other: { type: Type.STRING }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary", "theOneBigThing", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    const text = response.text;
    if (!text) throw new Error("Empty response");
    return JSON.parse(text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("הניתוח נכשל. נסה שוב.");
  }
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {

  const baseStyles = "relative inline-flex items-center justify-center px-8 py-3 rounded-full font-bold text-sm transition-all duration-300 disabled:opacity-40 disabled:cursor-not-allowed tracking-wide uppercase";

  const variants = {
    primary: "bg-bronze-600 hover:bg-bronze-500 text-onyx-950 shadow-[0_4px_20px_rgba(205,127,50,0.3)] border border-bronze-400/50 transform active:scale-95",
    secondary: "bg-onyx-800 hover:bg-onyx-700 text-onyx-100 border border-onyx-700 hover:border-bronze-500/50",
    outline: "bg-transparent text-bronze-400 border border-bronze-500/30 hover:bg-bronze-500/10 hover:border-bronze-500",
    ghost: "bg-transparent text-onyx-500 hover:text-bronze-400"
  };

  const finalClassName = `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <div className="flex items-center gap-3">
          <svg className="animate-spin h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
