import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'ghost';
  isLoading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  isLoading, 
  className = '', 
  disabled,
  ...props 
}) => {

  const baseStyles = "relative inline-flex items-center justify-center px-6 py-3.5 font-medium text-base transition-all duration-200 disabled:opacity-40 disabled:cursor-not-allowed tracking-wide";

  const variants = {
    primary: "bg-[#c25400] hover:bg-[#e66a00] text-white rounded-lg shadow-lg active:scale-[0.98]",
    secondary: "bg-onyx-700 hover:bg-onyx-600 text-white rounded-lg",
    outline: "bg-transparent text-white border border-white/10 hover:bg-white/5 rounded-lg",
    ghost: "bg-transparent text-white/60 hover:text-white"
  };

  const finalClassName = `${baseStyles} ${variants[variant]} ${className}`;

  return (
    <button 
      className={finalClassName}
      disabled={disabled || isLoading}
      {...props}
    >
      {isLoading ? (
        <div className="flex items-center gap-2">
          <svg className="animate-spin h-5 w-5 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
          </svg>
          <span>מעבד...</span>
        </div>
      ) : children}
    </button>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Landing: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [view, setView] = useState<'login' | 'register' | 'reset'>('login');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [registrationCode, setRegistrationCode] = useState(''); 
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setIsLoading(true);

    try {
      if (view === 'register') {
        await storageService.registerUser(name, email, password, registrationCode);
        navigate('/dashboard');
      } else if (view === 'login') {
        await storageService.login(email, password);
        navigate('/dashboard');
      } else if (view === 'reset') {
        await storageService.resetPassword(email, registrationCode, password);
        setSuccessMsg(lang === 'he' ? "הסיסמה עודכנה" : "Password updated");
        setTimeout(() => setView('login'), 2000);
      }
    } catch (err: any) {
      setError(err.message || 'Error');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <Layout>
      <div className="flex flex-col items-center justify-center min-h-[70vh] py-12">
        <div className="text-center mb-12">
            <h1 className="text-5xl md:text-6xl font-bold text-white mb-6 tracking-tight">
                One Big <span className="text-[#e66a00]">Thing</span>
            </h1>
            <p className="text-xl text-white/60 max-w-xl mx-auto leading-relaxed">
               {t.subtitle}
            </p>
        </div>

        <div className="glass-panel w-full max-w-[460px] p-10">
            <div className="mb-10 text-center">
                <h2 className="text-2xl font-medium text-white">
                    {view === 'register' ? 'צור חשבון חדש' : view === 'reset' ? t.reset : 'Member Login'}
                </h2>
                <div className="h-px bg-white/10 w-full mt-6"></div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
                {view === 'register' && (
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="dark-input" placeholder={t.fullName} />
                )}

                <input 
                  type="email" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  className="dark-input" 
                  placeholder="Email Address" 
                  dir="ltr"
                />

                {(view === 'register' || view === 'reset') && (
                    <input type="text" value={registrationCode} onChange={(e) => setRegistrationCode(e.target.value)} className="dark-input uppercase" placeholder="Registration Code" />
                )}

                <input 
                  type="password" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  className="dark-input" 
                  placeholder="Password" 
                  dir="ltr"
                />

                {error && <p className="text-red-400 text-sm text-center font-light">{error}</p>}
                {successMsg && <p className="text-green-400 text-sm text-center font-light">{successMsg}</p>}

                <Button type="submit" variant="primary" className="w-full text-lg py-4" isLoading={isLoading}>
                    {view === 'register' ? t.registerBtn : view === 'reset' ? t.save : 'Login'}
                </Button>
            </form>

            <div className="mt-10 flex flex-col items-center gap-4 text-sm font-light">
                {view === 'login' ? (
                    <>
                        <button onClick={() => setView('reset')} className="text-white/40 hover:text-white transition-colors">Forgot Password</button>
                        <div className="text-white/40 mt-2">
                            Don't have an account? <button onClick={() => setView('register')} className="text-[#e66a00] font-medium hover:underline">Create Account</button>
                        </div>
                    </>
                ) : (
                    <button onClick={() => setView('login')} className="text-white/40 hover:text-white transition-colors">Back to Login</button>
                )}
            </div>
        </div>
      </div>
    </Layout>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      q1: r.q1_change,
      q2: r.q2_actions
  }));

  const prompt = `
    נל משוב 360 עבור מנהל.
    מטרה: "${userGoal || 'לא הוגדרה'}"
    משובים: ${JSON.stringify(rawData)}

    דרישות:
    1. הכל בעברית.
    2. זהה את ה-One Big Thing (התובנה המרכזית).
    3. החזר JSON תקין בלבד.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        systemInstruction: `אתה פסיכולוג ארגוני. השב ב-JSON בעברית בלבד.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique: { type: Type.STRING },
                    refinedGoal: { type: Type.STRING }
                },
                required: ["score", "critique", "refinedGoal"]
            },
            executiveSummary: { type: Type.STRING },
            theOneBigThing: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities: { type: Type.ARRAY, items: { type: Type.STRING } },
                    alignmentLevel: { type: Type.STRING }
                },
                required: ["opportunities", "alignmentLevel"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns: { type: Type.STRING }
                },
                required: ["blockers", "psychologicalPatterns"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING },
                        content: { type: Type.STRING }
                    },
                    required: ["title", "content"]
                }
            }
          },
          required: ["goalPrecision", "executiveSummary", "theOneBigThing", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    if (!response.text) throw new Error("Empty response");
    return JSON.parse(response.text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("הניתוח נכשל. נסה שוב.");
  }
};

