import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType } from "docx";
import { AnalysisResult, FeedbackResponse, User } from "../types";

const relationshipLabels: Record<string, string> = {
  'manager': 'מנהלים',
  'peer': 'קולגות',
  'subordinate': 'כפיפים',
  'friend': 'חברים/משפחה',
  'other': 'אחר'
};

export const exportToWord = async (
  user: User, 
  analysis: AnalysisResult | null, 
  responses: FeedbackResponse[]
) => {
  const doc = new Document({
    sections: [{
      properties: {},
      children: [
        // Title
        new Paragraph({
          text: `דוח צמיחה אישי 360 - ${user.name}`,
          heading: HeadingLevel.HEADING_1,
          alignment: AlignmentType.CENTER,
          spacing: { after: 400 },
          bidirectional: true,
        }),
        new Paragraph({
            text: `תאריך הפקה: ${new Date().toLocaleDateString('he-IL')}`,
            alignment: AlignmentType.CENTER,
            spacing: { after: 600 },
            bidirectional: true,
        }),

        // Analysis Section (if exists)
        ...(analysis ? [
            new Paragraph({
                text: "סיכום תובנות (AI Analysis)",
                heading: HeadingLevel.HEADING_2,
                bidirectional: true,
                spacing: { before: 400, after: 200 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "הדבר האחד לפריצת דרך:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { after: 100 }
            }),
            // Fixed: Using language-specific field executiveSummary_he
            new Paragraph({
                text: analysis.executiveSummary_he,
                bidirectional: true,
                spacing: { after: 300 }
            }),
            // Note: groupPerspectives does not exist on AnalysisResult, 
            // but question1Analysis and question2Analysis do. 
            // We'll skip groupPerspectives since it's not in the type definition.

            new Paragraph({
                children: [
                    new TextRun({ text: "תכנית פעולה:", bold: true, size: 28, rightToLeft: true }),
                ],
                bidirectional: true,
                spacing: { before: 300 }
            }),
            // Fixed: Using language-specific field theOneBigThing_he
            new Paragraph({
                text: analysis.theOneBigThing_he,
                bidirectional: true,
            }),
            // Fixed: Using language-specific fields from DeepInsight
            ...analysis.actionPlan.map(step => new Paragraph({
                children: [
                    new TextRun({ text: `${step.title_he}: `, bold: true }),
                    new TextRun({ text: step.content_he })
                ],
                bidirectional: true,
                bullet: { level: 0 }
            })),
            new Paragraph({ text: "", spacing: { after: 600 } }) // Spacer
        ] : []),

        // Raw Responses
        new Paragraph({
            text: "תשובות גולמיות (אנונימי)",
            heading: HeadingLevel.HEADING_2,
            bidirectional: true,
            spacing: { after: 200 }
        }),

        ...responses.flatMap((res, index) => [
            new Paragraph({
                children: [
                    new TextRun({ text: `משיב #${index + 1}`, bold: true, color: "888888" }),
                    new TextRun({ text: ` | ${relationshipLabels[res.relationship] || 'אחר'}`, color: "888888" })
                ],
                bidirectional: true,
                spacing: { before: 200, after: 100 }
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "1. הדבר לשינוי: ", bold: true }),
                    new TextRun({ text: res.q1_change })
                ],
                bidirectional: true,
            }),
            new Paragraph({
                children: [
                    new TextRun({ text: "2. פעולות סותרות: ", bold: true }),
                    new TextRun({ text: res.q2_actions })
                ],
                bidirectional: true,
                spacing: { after: 300 },
                border: { bottom: { color: "cccccc", space: 1, value: "single", size: 6 } }
            })
        ])
      ],
    }],
  });

  const blob = await Packer.toBlob(doc);
  const url = window.URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = `Growth_Report_${user.name.replace(/\s+/g, '_')}.docx`;
  a.click();
  window.URL.revokeObjectURL(url);
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (responses: FeedbackResponse[], userGoal?: string): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const ai = getClient();

  const rawData = responses.map(r => ({
      role: r.relationship,
      q1: r.q1_change,
      q2: r.q2_actions
  }));

  const prompt = `
    משימה: זיקוק תובנות ממשוב 360 עבור מנהל/ת.
    מטרה נוכחית: "${userGoal || 'לא הוגדרה'}"
    משובים: ${JSON.stringify(rawData)}

    הנחיות חשובות לטון ולשפה:
    1. השתמש בשפה פשוטה, ברורה ובגובה העיניים. בלי "מילים גבוהות" מדי של יועצים.
    2. הצג את ה-One Big Thing כ**הצעה למחשבה** (Suggested direction) ולא כתשובה סופית. השתמש בניסוחים כמו "נראה ש...", "נקודה למחשבה שעולה היא...", "אולי כדאי לשקול...".
    3. כתוב בעברית נקייה ללא ערבוב אנגלית.
    4. בצע ניתוח של פערים בין המטרה שהמנהל הציב לבין מה שהסביבה רואה.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        systemInstruction: `אתה מלווה מנהלים שמאמין שהתשובה נמצאת אצלם. תפקידך להציע זווית ראייה חדשה מתוך המשובים. דבר בפשטות ובידידותיות. השב ב-JSON בלבד.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique_he: { type: Type.STRING },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "critique_en", "refinedGoal_he", "refinedGoal_en"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["opportunities_he", "opportunities_en"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                },
                required: ["blockers_he", "blockers_en", "psychologicalPatterns_he", "psychologicalPatterns_en"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    },
                    required: ["title_he", "title_en", "content_he", "content_en"]
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "executiveSummary_en", "theOneBigThing_he", "theOneBigThing_en", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    if (!response.text) throw new Error("Empty response");
    return JSON.parse(response.text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("משהו השתבש בניתוח. כדאי לנסות שוב.");
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [user, setUser] = useState<User | null>(null);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');
    if (!currentUser.userGoal) setIsEditingGoal(true);
    storageService.getResponsesForUser(currentUser.id).then(setResponses);
  }, [navigate]);

  useEffect(() => {
    if (loadingAnalysis) {
      const messages = lang === 'he' ? [
        "מקשיב למשובים...",
        "מחפש דפוסים חוזרים...",
        "מזקק כיווני מחשבה...",
        "מנסח הצעה לפעולה אחת משמעותית...",
        "מכין לך את הדוח..."
      ] : [
        "Listening to feedback...",
        "Looking for patterns...",
        "Synthesizing thoughts...",
        "Drafting a suggestion for growth...",
        "Preparing your report..."
      ];
      let i = 0;
      setLoadingMessage(messages[0]);
      const interval = setInterval(() => {
        i = (i + 1) % messages.length;
        setLoadingMessage(messages[i]);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loadingAnalysis, lang]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
  };

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses, user?.userGoal);
      setAnalysis(result);
    } catch (error) {
      alert(lang === 'he' ? "הניתוח נכשל. נסה שוב." : "Analysis failed.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.href.split('#')[0];
    const url = `${baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl}/#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return null;

  return (
    <Layout>
      <div className="pb-24">
        {/* Header Section */}
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 pb-8 border-b border-white/5">
          <div className="space-y-1">
            <span className="text-amber-600 font-bold tracking-widest text-[10px] uppercase block">
                {lang === 'he' ? 'מרחב הצמיחה האישי' : 'PERSONAL GROWTH SPACE'}
            </span>
            <h1 className="text-4xl font-bold text-white tracking-tight">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-white/40 text-sm">{t.feedbacksCollected}: <span className="text-amber-500 font-bold">{responses.length}</span></p>
          </div>
          <div className="flex gap-3">
            <Button onClick={copyLink} variant="outline" className="rounded-lg py-2.5">
              {copied ? t.linkCopied : t.copyLink}
            </Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost" className="text-white/30 hover:text-white">
              {t.logout}
            </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          <div className="lg:col-span-4 space-y-8">
            <div className="glass-panel p-6 border-l-4 border-l-amber-600">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xs font-bold text-white/40 uppercase tracking-tighter">{t.myGoal}</h3>
                    <button onClick={() => setIsEditingGoal(true)} className="text-amber-600 text-[10px] uppercase hover:underline">{t.edit}</button>
                </div>
                {isEditingGoal ? (
                    <div className="space-y-4">
                        <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm" rows={4} />
                        <div className="flex gap-2">
