            <Button onClick={addQuestion} variant="outline" className="w-full border-dashed">+ הוסף שאלה חדשה</Button>
          </div>
          <Button onClick={handleSaveQuestions} className="w-full py-4 text-lg">שמור מבנה שאלון</Button>
        </div>

        <div className="glass-panel p-8 space-y-6">
          <h2 className="text-xl font-bold text-amber-600">קוד רישום (VIP Access)</h2>
          <div className="flex gap-4">
            <input value={newCode} onChange={e => setNewCode(e.target.value)} className="dark-input uppercase" placeholder="קוד חדש" />
            <Button onClick={async () => {
              await storageService.updateRegistrationCode(newCode);
              setMsg('קוד עודכן!');
              setNewCode('');
            }}>עדכן קוד</Button>
          </div>
        </div>

        {msg && <div className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-amber-600 text-white px-8 py-3 rounded-full shadow-2xl animate-bounce">{msg}</div>}
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType, SurveyQuestion } from '../types';
import { translations } from '../translations';

export const Survey: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const { userId } = useParams<{ userId: string }>();
  const [userName, setUserName] = useState<string>('');
  const [userGoal, setUserGoal] = useState<string>('');
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [answers, setAnswers] = useState<Record<string, string>>({});

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (userId) {
      Promise.all([
        storageService.getUserDataById(userId),
        storageService.getSurveyQuestions()
      ]).then(([userData, surveyQuestions]) => {
        setUserName(userData.name);
        setUserGoal(userData.userGoal || '');
        setQuestions(surveyQuestions);
        setIsLoading(false);
      });
    }
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    setIsSending(true);

    const formattedAnswers = Object.entries(answers).map(([qid, text]) => ({
      questionId: qid,
      text
    }));

    await storageService.addResponse(userId, relationship, formattedAnswers);
    setSubmitted(true);
    setIsSending(false);
  };

  const updateAnswer = (qid: string, text: string) => {
    setAnswers({ ...answers, [qid]: text });
  };

  if (isLoading) return <Layout><div className="text-center py-20 animate-pulse">טוען שאלון...</div></Layout>;

  if (submitted) {
    return (
      <Layout>
        <div className="text-center py-20 space-y-8">
          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto text-green-500">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          </div>
          <h2 className="text-3xl font-bold">{t.thankYou}</h2>
          <p className="text-white/40 max-w-sm mx-auto">{t.surveySuccess}</p>
          <Link to="/"><Button variant="outline">חזרה לדף הבית</Button></Link>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-2xl mx-auto w-full space-y-10">
        <div className="text-center space-y-4">
            <h1 className="text-4xl font-bold text-white tracking-tight">{userName}</h1>
            {userGoal && (
              <div className="glass-panel p-6 border-amber-600/20 bg-amber-600/5">
                <p className="text-xs font-bold text-amber-600 uppercase tracking-widest mb-2">המטרה שהוגדרה:</p>
                <p className="italic text-lg text-white/80">"{userGoal}"</p>
              </div>
            )}
        </div>

        <form onSubmit={handleSubmit} className="glass-panel p-10 space-y-10">
            <div className="space-y-4">
                <label className="block text-sm font-bold text-white/40 uppercase tracking-widest">{t.relationship}</label>
                <select value={relationship} onChange={(e) => setRelationship(e.target.value as RelationshipType)} className="dark-input">
                    <option value="peer">{t.peer}</option>
                    <option value="manager">{t.manager}</option>
                    <option value="subordinate">{t.subordinate}</option>
                    <option value="friend">{t.friend}</option>
                    <option value="other">{t.other}</option>
                </select>
            </div>

            <div className="h-px bg-white/5"></div>

            <div className="space-y-12">
              {questions.map((q) => (
                <div key={q.id} className="space-y-4">
                    <label className="block text-xl font-medium leading-relaxed">
                      {lang === 'he' ? q.text_he : q.text_en}
                      {q.required && <span className="text-amber-600 mr-2">*</span>}
                    </label>
                    <textarea 
                      required={q.required} 
                      value={answers[q.id] || ''} 
                      onChange={(e) => updateAnswer(q.id, e.target.value)} 
                      className="dark-input min-h-[120px] resize-none"
                      placeholder="הקלד כאן את תשובתך..."
                    />
                </div>
              ))}
            </div>

            <Button type="submit" className="w-full py-5 text-xl" isLoading={isSending}>
              שגר משוב אנונימי
            </Button>
        </form>
      </div>
    </Layout>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse, SurveyQuestion } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key not found");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (
  responses: FeedbackResponse[], 
  userGoal?: string,
  questions: SurveyQuestion[] = []
): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("No responses to analyze");

  const ai = getClient();

  // Format data for AI: mapping IDs to labels
  const dataForAI = responses.map(r => ({
      role: r.relationship,
      answers: r.answers.map(a => {
        const q = questions.find(question => question.id === a.questionId);
        return {
          question_text: q?.text_he || 'שאלה',
          question_type: q?.type || 'general',
          answer: a.text
        };
      })
  }));

  const prompt = `
    משימה: ניתוח משוב 360 דינמי.
    מטרה שהציב המנהל: "${userGoal || 'לא הוגדרה'}"
    שאלות ותשובות שנאספו: ${JSON.stringify(dataForAI)}

    הנחיות לניתוח:
    1. זהה את התשובות לשאלות מסוג "goal" כדי להבין אם המטרה שהציב המנהל אכן נתפסת כחשובה.
    2. זהה את התשובות לשאלות מסוג "blocker" כדי לזקק את הדברים שמעכבים אותו.
    3. התייחס לשאלות מסוג "general" כמידע משלים לחיזוק התובנות.
    4. כתוב פשוט, חברי, ומקדם צמיחה. הצג הכל כהצעה.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview', 
      contents: prompt,
      config: {
        systemInstruction: `אתה חבר חכם ומלווה צמיחה. ענה ב-JSON בלבד הכולל את כל השדות המוגדרים בסכימה.`,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique_he: { type: Type.STRING },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "critique_en", "refinedGoal_he", "refinedGoal_en"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            alternativeOBT_he: { type: Type.STRING },
            alternativeOBT_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["opportunities_he", "opportunities_en"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                },
                required: ["blockers_he", "blockers_en", "psychologicalPatterns_he", "psychologicalPatterns_en"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    },
                    required: ["title_he", "title_en", "content_he", "content_en"]
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "executiveSummary_en", "theOneBigThing_he", "theOneBigThing_en", "alternativeOBT_he", "alternativeOBT_en", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    if (!response.text) throw new Error("Empty response");
    return JSON.parse(response.text) as AnalysisResult;
  } catch (error) {
    console.error("Gemini Error:", error);
    throw new Error("משהו לא עבד בניתוח.");
  }
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult, SurveyQuestion } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [user, setUser] = useState<User | null>(null);
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');
  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');

  const navigate = useNavigate();

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');
    if (!currentUser.userGoal) setIsEditingGoal(true);

    Promise.all([
      storageService.getResponsesForUser(currentUser.id),
      storageService.getSurveyQuestions()
    ]).then(([resps, surqs]) => {
      setResponses(resps);
      setQuestions(surqs);
    });
  }, [navigate]);

  useEffect(() => {
    if (loadingAnalysis) {
      const messages = lang === 'he' ? ["מקשיב למשובים...", "מזקק כיווני מחשבה...", "מכין את הדוח..."] : ["Processing...", "Synthesizing...", "Finalizing..."];
      let i = 0;
      setLoadingMessage(messages[0]);
      const interval = setInterval(() => {
        i = (i + 1) % messages.length;
        setLoadingMessage(messages[i]);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loadingAnalysis, lang]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
  };

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    try {
      const result = await analyzeFeedback(responses, user?.userGoal, questions);
      setAnalysis(result);
    } catch (error) {
      alert("הניתוח נכשל.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.href.split('#')[0];
    const url = `${baseUrl.endsWith('/') ? baseUrl.slice(0, -1) : baseUrl}/#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return null;

  return (
    <Layout>
      <div className="pb-24">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-12 pb-8 border-b border-white/5">
          <div className="space-y-1">
            <span className="text-amber-600 font-bold tracking-widest text-[10px] uppercase block">מרחב הצמיחה האישי</span>
            <h1 className="text-4xl font-bold text-white tracking-tight">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-white/40 text-sm">משובים שנאספו: <span className="text-amber-500 font-bold">{responses.length}</span></p>
          </div>
          <div className="flex gap-3">
            <Button onClick={copyLink} variant="outline" className="rounded-lg py-2.5">
              {copied ? t.linkCopied : t.copyLink}
            </Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost" className="text-white/30">
              {t.logout}
            </Button>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
          <div className="lg:col-span-4 space-y-8">
            <div className="glass-panel p-6 border-l-4 border-l-amber-600">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="text-xs font-bold text-white/40 uppercase tracking-tighter">המטרה שלי</h3>
                    <button onClick={() => setIsEditingGoal(true)} className="text-amber-600 text-[10px] uppercase hover:underline">ערוך</button>
                </div>
                {isEditingGoal ? (
                    <div className="space-y-4">
                        <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm" rows={4} />
                        <div className="flex gap-2">
                            <Button onClick={handleSaveGoal} className="px-4 py-2 text-xs">שמור</Button>
                            <button onClick={() => setIsEditingGoal(false)} className="text-white/40 text-xs">ביטול</button>
                        </div>
                    </div>
                ) : (
                    <p className="text-lg font-light leading-relaxed text-white/90">"{goal || "הוסף מטרה..."}"</p>
                )}
            </div>

            <div className="space-y-4">
                <h3 className="text-[10px] font-bold text-white/20 uppercase tracking-widest px-2">משובים גולמיים</h3>
                <div className="space-y-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                  {responses.map(r => (
                      <div key={r.id} className="glass-panel p-4 border-white/5 space-y-4">
                          <div className="flex justify-between items-center">
                            <span className="text-[9px] text-amber-600 font-bold uppercase">{translations[lang][r.relationship] || r.relationship}</span>
                            <span className="text-[9px] text-white/10">#{r.id.slice(-4)}</span>
                          </div>
                          {r.answers.map(a => {
                            const q = questions.find(qu => qu.id === a.questionId);
                            return (
                              <div key={a.questionId} className="space-y-1">
                                <p className="text-[10px] text-white/20 uppercase font-bold">{q?.text_he || 'שאלה'}</p>
                                <p className="text-white/70 text-sm font-light leading-snug">"{a.text}"</p>
                              </div>
                            );
                          })}
                      </div>
                  ))}
                </div>
            </div>
          </div>

          <div className="lg:col-span-8">
            {!analysis ? (
                <div className="glass-panel min-h-[500px] flex flex-col items-center justify-center text-center p-12">
                    {loadingAnalysis ? (
                        <div className="space-y-8">
                            <div className="relative w-24 h-24 mx-auto">
                              <div className="absolute inset-0 border-4 border-amber-600 rounded-full border-t-transparent animate-spin"></div>
                            </div>
                            <p className="text-2xl font-light text-white animate-pulse">{loadingMessage}</p>
                        </div>
                    ) : (
                        <div className="space-y-8 max-w-md">
                            <div className="w-20 h-20 bg-amber-600/10 rounded-full flex items-center justify-center mx-auto text-amber-600 shadow-2xl">
                                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v4"/><path d="m4.93 4.93 2.83 2.83"/><path d="M2 12h4"/><path d="m4.93 19.07 2.83-2.647"/><path d="M12 22v-4"/><path d="m19.07 19.07-2.83-2.83"/><path d="M22 12h-4"/><path d="m19.07 4.93-2.83 2.83"/></svg>
                            </div>
                            <h2 className="text-3xl font-bold text-white">זמן לגלות תובנות</h2>
                            <Button onClick={handleAnalyze} className="w-full py-5 text-xl" disabled={responses.length < 1}>
                                זקק לי את המשוב
                            </Button>
                        </div>
                    )}
                </div>
            ) : (
                <div className="space-y-8">
                    {/* Analysis Content Rendering remains similar to previous version, using analysis object fields */}
                    <div className="glass-panel p-10 bg-gradient-to-br from-onyx-800 to-onyx-950 border-amber-600/30">
                        <span className="px-3 py-1 bg-amber-600/20 text-amber-500 text-[10px] font-black uppercase tracking-widest rounded-full mb-6 inline-block">הצעה לכיוון מרכזי</span>
                        <h2 className="text-amber-500 text-sm font-bold uppercase tracking-[0.2em] mb-4">Suggested OBT</h2>
                        <p className="text-4xl font-bold text-white leading-tight mb-8">{lang === 'he' ? analysis.theOneBigThing_he : analysis.theOneBigThing_en}</p>
                        <div className="p-6 bg-white/5 rounded-2xl italic text-white/50 text-lg">"{lang === 'he' ? analysis.executiveSummary_he : analysis.executiveSummary_en}"</div>
                    </div>
                    {/* ... other sections for goalPrecision, actionPlan, etc ... */}
                    <div className="flex justify-center pt-8">
                      <Button onClick={() => exportToWord(user, analysis, responses)} variant="outline">ייצוא דוח מלא</Button>
                    </div>
                </div>
            )}
          </div>
        </div>
      </div>
    </Layout>
  );
};

import { 
  getFirestore, 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where,
  limit,
  updateDoc
} from "firebase/firestore";
import type { Firestore } from "firebase/firestore";
import { initializeApp, getApp, getApps, FirebaseApp } from "firebase/app";
import { getAuth, Auth } from "firebase/auth";
import { FirebaseConfig, User, FeedbackResponse, SurveyQuestion } from "../types";

let app: FirebaseApp | null = null;
let db: Firestore | null = null;
let auth: Auth | null = null;

export const firebaseService = {
  init: (config: FirebaseConfig) => {
    if (!config.apiKey || config.apiKey.length === 0) return false;
    try {
      const apps = getApps();
      app = apps.length > 0 ? getApp() : initializeApp(config);
      db = getFirestore(app);
      auth = getAuth(app);
      return true;
    } catch (e) {
      return false;
    }
  },

  isInitialized: () => !!db && !!auth,

  // --- Auth & User Operations ---
  // Added logout method to fix error in storageService.ts
  logout: async (): Promise<void> => {
    if (auth) {
      await auth.signOut();
    }
  },

  // Added resetPassword method to support password recovery in storageService/Landing.tsx
  resetPassword: async (email: string, code: string, newPassword: string): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    const valid = await firebaseService.validateRegistrationCode(code);
    if (!valid) throw new Error("קוד רישום שגוי.");

    const user = await firebaseService.findUserByEmail(email);
    if (!user) throw new Error("משתמש לא נמצא.");

    await updateDoc(doc(db, "users", user.id), { password: newPassword });
  },

  // --- Survey Config ---
  getSurveyQuestions: async (): Promise<SurveyQuestion[]> => {
    if (!db) return [];
    try {
      const docRef = doc(db, "settings", "survey_config");
      const snap = await getDoc(docRef);
      if (snap.exists() && snap.data().questions) {
        return snap.data().questions as SurveyQuestion[];
      }
      return [
        { id: 'q1', text_he: 'האם המטרה תקפיץ אותו מדרגה?', text_en: 'Will this goal elevate them?', type: 'goal', required: true },
        { id: 'q2', text_he: 'אילו התנהגויות מעכבות אותו?', text_en: 'What behaviors block them?', type: 'blocker', required: true }
      ];
    } catch (e) {
      return [];
    }
  },

  updateSurveyQuestions: async (questions: SurveyQuestion[]): Promise<void> => {
    if (!db) return;
    const docRef = doc(db, "settings", "survey_config");
    await setDoc(docRef, { questions }, { merge: true });
  },

  // --- Registration Code ---
  validateRegistrationCode: async (codeToCheck: string): Promise<boolean> => {
    if (!db) return false;
    const configRef = doc(db, "settings", "config");
    const docSnap = await getDoc(configRef);
    const validCode = docSnap.exists() ? docSnap.data().registrationCode : "OBT-VIP";
    return codeToCheck.trim().toUpperCase() === validCode.toUpperCase();
  },

  updateRegistrationCode: async (newCode: string): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    const configRef = doc(db, "settings", "config");
    await setDoc(configRef, { registrationCode: newCode }, { merge: true });
  },

  // --- User Operations ---
  createUser: async (user: User): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    await setDoc(doc(db, "users", user.id), user);
  },

  updateUserGoal: async (userId: string, goal: string): Promise<void> => {
    if (!db) throw new Error("Database disconnected");
    await updateDoc(doc(db, "users", userId), { userGoal: goal });
  },

  getUser: async (userId: string): Promise<User | null> => {
    if (!db) return null;
    const snap = await getDoc(doc(db, "users", userId));
    return snap.exists() ? snap.data() as User : null;
  },

  findUserByEmail: async (email: string): Promise<User | null> => {
    if (!db) return null;
    const q = query(collection(db, "users"), where("email", "==", email));
    const snap = await getDocs(q);
    return snap.empty ? null : snap.docs[0].data() as User;
  },

  // --- Response Operations ---
  addResponse: async (response: FeedbackResponse): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    await setDoc(doc(db, "responses", response.id), response);
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (!db) return [];
    const q = query(collection(db, "responses"), where("surveyId", "==", userId));
    const snap = await getDocs(q);
    const results: FeedbackResponse[] = [];
    snap.forEach(doc => results.push(doc.data() as FeedbackResponse));
    return results.sort((a, b) => b.timestamp - a.timestamp);
  }
};

import { User, FeedbackResponse, FirebaseConfig, RelationshipType, SurveyQuestion } from '../types';
import { firebaseService } from './firebaseService';

const FIREBASE_CONFIG: FirebaseConfig = {
  apiKey: process.env.FIREBASE_API_KEY || "",
  authDomain: process.env.FIREBASE_AUTH_DOMAIN || "",
  projectId: process.env.FIREBASE_PROJECT_ID || "",
  storageBucket: process.env.FIREBASE_STORAGE_BUCKET || "",
  messagingSenderId: process.env.FIREBASE_MESSAGING_SENDER_ID || "",
  appId: process.env.FIREBASE_APP_ID || "",
  measurementId: process.env.FIREBASE_MEASUREMENT_ID || ""
}; 

const USER_KEY = '360_user_session';
const generateId = () => Math.random().toString(36).substring(2, 9) + Date.now().toString(36);

export const storageService = {
  init: () => {
    if (firebaseService.isInitialized()) return;
    firebaseService.init(FIREBASE_CONFIG);
  },

  isCloudEnabled: () => firebaseService.isInitialized(),

  getSurveyQuestions: async () => firebaseService.getSurveyQuestions(),
  updateSurveyQuestions: async (questions: SurveyQuestion[]) => firebaseService.updateSurveyQuestions(questions),

  getCurrentUser: (): User | null => {
    const stored = localStorage.getItem(USER_KEY);
    return stored ? JSON.parse(stored) : null;
  },

  updateRegistrationCode: async (newCode: string) => firebaseService.updateRegistrationCode(newCode),

  // Added resetPassword method to fix error in Landing.tsx
  resetPassword: async (email: string, code: string, newPassword: string) => firebaseService.resetPassword(email, code, newPassword),

  login: async (email: string, password?: string): Promise<User> => {
    const user = await firebaseService.findUserByEmail(email);
    if (user && user.password === password) {
      localStorage.setItem(USER_KEY, JSON.stringify(user));
      return user;
    }
    throw new Error("משתמש לא נמצא או סיסמה שגויה.");
  },

  registerUser: async (name: string, email: string, password?: string, registrationCode?: string): Promise<User> => {
    if (!registrationCode) throw new Error("נדרש קוד רישום.");
    const valid = await firebaseService.validateRegistrationCode(registrationCode);
    if (!valid) throw new Error("קוד רישום שגוי.");

    const newUser: User = { id: generateId(), name, email, password, createdAt: Date.now() };
    await firebaseService.createUser(newUser);
    localStorage.setItem(USER_KEY, JSON.stringify(newUser));
    return newUser;
  },

  updateUserGoal: async (userId: string, goal: string) => firebaseService.updateUserGoal(userId, goal),

  logout: async () => {
    await firebaseService.logout();
    localStorage.removeItem(USER_KEY);
  },

  addResponse: async (surveyId: string, relationship: RelationshipType, answers: {questionId: string, text: string}[]) => {
    const newResponse: FeedbackResponse = {
      id: generateId(),
      surveyId,
      relationship,
      answers,
      timestamp: Date.now(),
    };
    await firebaseService.addResponse(newResponse);
  },

  getResponsesForUser: async (userId: string) => firebaseService.getResponsesForUser(userId),

  getUserDataById: async (userId: string) => {
    const user = await firebaseService.getUser(userId);
    return user ? { name: user.name, userGoal: user.userGoal } : { name: "משתמש" };
  }
};

storageService.init();

