import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Landing: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [view, setView] = useState<'login' | 'register' | 'reset'>('login');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [registrationCode, setRegistrationCode] = useState(''); 
  const [isLoading, setIsLoading] = useState(false);
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setIsLoading(true);

    try {
      if (view === 'register') {
        await storageService.registerUser(name, email, password, registrationCode);
        navigate('/dashboard');
      } else if (view === 'login') {
        await storageService.login(email, password);
        navigate('/dashboard');
      } else if (view === 'reset') {
        await storageService.resetPassword(email, registrationCode, password);
        setSuccessMsg(lang === 'he' ? "הסיסמה עודכנה" : "Password updated");
        setTimeout(() => setView('login'), 2000);
      }
    } catch (err: any) {
      setError(err.message || 'Error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setIsGoogleLoading(true);
    try {
      await storageService.loginWithGoogle();
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.message || 'Google login failed');
    } finally {
      setIsGoogleLoading(false);
    }
  };

  return (
    <Layout>
      <div className="flex flex-col items-center justify-center min-h-[70vh] py-12">
        <div className="text-center mb-12">
            <h1 className="text-5xl md:text-6xl font-bold text-white mb-6 tracking-tight">
                One Big <span className="text-[#e66a00]">Thing</span>
            </h1>
            <p className="text-xl text-white/60 max-w-xl mx-auto leading-relaxed">
               {t.subtitle}
            </p>
        </div>

        <div className="glass-panel w-full max-w-[460px] p-10">
            <div className="mb-10 text-center">
                <h2 className="text-2xl font-medium text-white">
                    {view === 'register' ? 'צור חשבון חדש' : view === 'reset' ? t.reset : 'Member Login'}
                </h2>
                <div className="h-px bg-white/10 w-full mt-6"></div>
            </div>

            <div className="mb-8">
              <button 
                onClick={handleGoogleLogin} 
                disabled={isGoogleLoading}
                className="w-full flex items-center justify-center gap-3 bg-white text-black font-bold py-3.5 rounded-lg hover:bg-gray-100 transition-all active:scale-[0.98] disabled:opacity-50"
              >
                {isGoogleLoading ? (
                  <div className="w-5 h-5 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 48 48">
                    <path fill="#FFC107" d="M43.611 20.083H42V20H24v8h11.303c-1.649 4.657-6.08 8-11.303 8c-6.627 0-12-5.373-12-12s5.373-12 12-12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C12.955 4 4 12.955 4 24s8.955 20 20 20s20-8.955 20-20c0-1.341-.138-2.65-.389-3.917z"/><path fill="#FF3D00" d="m6.306 14.691l6.571 4.819C14.655 15.108 18.961 12 24 12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C16.318 4 9.656 8.337 6.306 14.691z"/><path fill="#4CAF50" d="M24 44c5.166 0 9.86-1.977 13.409-5.192l-6.19-5.238A11.91 11.91 0 0 1 24 36c-5.202 0-9.619-3.317-11.283-7.946l-6.522 5.025C9.505 39.556 16.227 44 24 44z"/><path fill="#1976D2" d="M43.611 20.083H42V20H24v8h11.303a12.04 12.04 0 0 1-4.087 5.571l.003-.002l6.19 5.238C36.971 39.205 44 34 44 24c0-1.341-.138-2.65-.389-3.917z"/>
                  </svg>
                )}
                <span>Continue with Google</span>
              </button>

              <div className="relative flex items-center justify-center my-8">
                <div className="flex-grow border-t border-white/10"></div>
                <span className="flex-shrink mx-4 text-white/20 text-xs uppercase font-bold tracking-widest">or email</span>
                <div className="flex-grow border-t border-white/10"></div>
              </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
                {view === 'register' && (
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="dark-input" placeholder={t.fullName} />
                )}

                <input 
                  type="email" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  className="dark-input" 
                  placeholder="Email Address" 
                  dir="ltr"
                />

                {(view === 'register' || view === 'reset') && (
                    <input type="text" value={registrationCode} onChange={(e) => setRegistrationCode(e.target.value)} className="dark-input uppercase" placeholder="Registration Code" />
                )}

                <input 
                  type="password" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  className="dark-input" 
                  placeholder="Password" 
                  dir="ltr"
                />

                {error && <p className="text-red-400 text-sm text-center font-light">{error}</p>}
                {successMsg && <p className="text-green-400 text-sm text-center font-light">{successMsg}</p>}

                <Button type="submit" variant="primary" className="w-full text-lg py-4" isLoading={isLoading}>
                    {view === 'register' ? t.registerBtn : view === 'reset' ? t.save : 'Login'}
                </Button>
            </form>

            <div className="mt-10 flex flex-col items-center gap-4 text-sm font-light">
                {view === 'login' ? (
                    <>
                        <button onClick={() => setView('reset')} className="text-white/40 hover:text-white transition-colors">Forgot Password</button>
                        <div className="text-white/40 mt-2">
                            Don't have an account? <button onClick={() => setView('register')} className="text-[#e66a00] font-medium hover:underline">Create Account</button>
                        </div>
                    </>
                ) : (
                    <button onClick={() => setView('login')} className="text-white/40 hover:text-white transition-colors">Back to Login</button>
                )}
            </div>
        </div>
      </div>
    </Layout>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse, SurveyQuestion } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key (process.env.API_KEY) missing. Please check your environment variables.");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (
  responses: FeedbackResponse[], 
  userGoal?: string,
  questions: SurveyQuestion[] = []
): Promise<AnalysisResult> => {
  if (responses.length === 0) throw new Error("לא נמצאו תשובות לניתוח.");

  const ai = getClient();

  // הכנת המידע ל-AI: מיפוי תשובות לשאלות והצמדת סוג השאלה
  const dataForAI = responses.map(r => ({
      relationship: r.relationship,
      feedback: r.answers.map(a => {
        const q = questions.find(question => question.id === a.questionId);
        return {
          question: q?.text_he || 'שאלה כללית',
          type: q?.type || 'general',
          answer: a.text
        };
      })
  }));

  const prompt = `
    משימה: אתה יועץ פיתוח מנהיגות בכיר. עליך לנתח משוב 360 עבור מנהל.
    המטרה שהמנהל הציב לעצמו: "${userGoal || 'לא הוגדרה מטרה ספציפית'}"

    נתוני המשוב (בפורמט JSON):
    ${JSON.stringify(dataForAI, null, 2)}

    הנחיות לניתוח:
    1. קרא את כל התשובות. חפש תבניות שחוזרות על עצמן.
    2. "The One Big Thing": זהה את השינוי האחד והמשמעותי ביותר (המנוע המרכזי) שישנה את כל התמונה עבור המנהל הזה.
    3. נתח את הדיוק של המטרה המקורית מול מה שאנשים אומרים בשטח.
    4. בודד חסמים (Blockers) - התנהגויות ספציפיות שמעכבות אותו.
    5. בנה תוכנית פעולה של 3 צעדים פרקטיים.

    חשוב: ענה בעברית רהוטה ומקצועית.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // שימוש ב-Pro לניתוח עמוק יותר
      contents: prompt,
      config: {
        systemInstruction: `אתה מומחה לניתוח משוב 360. עליך להחזיר תשובה בפורמט JSON תקין בלבד, על פי הסכימה המדויקת שסופקה. אל תוסיף טקסט לפני או אחרי ה-JSON.`,
        thinkingConfig: { thinkingBudget: 4000 }, // מאפשר ל-AI "לחשוב" לפני מתן תשובה סופית
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER, description: "ציון בין 1-10 למידת הדיוק של המטרה המקורית" },
                    critique_he: { type: Type.STRING },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "critique_en", "refinedGoal_he", "refinedGoal_en"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            alternativeOBT_he: { type: Type.STRING },
            alternativeOBT_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["opportunities_he", "opportunities_en"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                },
                required: ["blockers_he", "blockers_en", "psychologicalPatterns_he", "psychologicalPatterns_en"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    },
                    required: ["title_he", "title_en", "content_he", "content_en"]
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "executiveSummary_en", "theOneBigThing_he", "theOneBigThing_en", "alternativeOBT_he", "alternativeOBT_en", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    if (!response.text) {
      console.error("Gemini returned empty text response");
      throw new Error("ה-AI לא הצליח לייצר תשובה. נסה שוב בעוד רגע.");
    }

    const cleanJson = response.text.trim();
    return JSON.parse(cleanJson) as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini Service Detailed Error:", error);
    if (error.message?.includes("API_KEY")) {
      throw new Error("מפתח ה-API חסר או לא תקין.");
    }
    throw new Error(`תקלה בניתוח הנתונים: ${error.message || "שגיאה לא ידועה"}`);
  }
};

import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult, SurveyQuestion } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const navigate = useNavigate();

  const [user, setUser] = useState<User | null>(null);
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');

  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [isEditingQuestions, setIsEditingQuestions] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [activeTab, setActiveTab] = useState<'overview' | 'responses' | 'settings'>('overview');
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  const t = translations[lang];

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { 
      navigate('/'); 
      return; 
    }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');

    // שליפת נתונים
    Promise.all([
      storageService.getResponsesForUser(currentUser.id),
      storageService.getSurveyQuestions(currentUser.id)
    ]).then(([resps, surqs]) => {
      setResponses(resps);
      setQuestions(surqs);
    }).catch(err => {
      console.error("Failed to load dashboard data", err);
    });
  }, [navigate]);

  useEffect(() => {
    if (loadingAnalysis) {
      const messages = lang === 'he' ? ["מקשיב למשובים...", "מזהה דפוסים...", "מזקק תובנות...", "מכין את הדוח..."] : ["Listening to feedback...", "Identifying patterns...", "Synthesizing insights...", "Finalizing report..."];
      let i = 0;
      setLoadingMessage(messages[0]);
      const interval = setInterval(() => {
        i = (i + 1) % messages.length;
        setLoadingMessage(messages[i]);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loadingAnalysis, lang]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
      showFeedback('המטרה עודכנה!');
  };

  const handleSaveQuestions = async () => {
    if (!user) return;
    try {
      await storageService.updateUserQuestions(user.id, questions);
      setIsEditingQuestions(false);
      showFeedback('השאלון עודכן בהצלחה!');
    } catch (e) {
      showFeedback('שגיאה בשמירת השאלון');
    }
  };

  const showFeedback = (msg: string) => {
    setFeedbackMsg(msg);
    setTimeout(() => setFeedbackMsg(''), 3000);
  };

  const addQuestion = () => {
    const newQ: SurveyQuestion = {
      id: 'q_' + Date.now(),
      text_he: '',
      text_en: '',
      type: 'general',
      required: true
    };
    setQuestions([...questions, newQ]);
  };

  const removeQuestion = (id: string) => {
    if (window.confirm('למחוק את השאלה?')) {
      setQuestions(questions.filter(q => q.id !== id));
    }
  };

  const updateQuestion = (id: string, field: keyof SurveyQuestion, value: any) => {
    setQuestions(questions.map(q => q.id === id ? { ...q, [field]: value } : q));
  };

  const handleAnalyze = async () => {
    if (responses.length === 0) return;
    setLoadingAnalysis(true);
    setErrorMsg('');
    try {
      const result = await analyzeFeedback(responses, user?.userGoal, questions);
      setAnalysis(result);
    } catch (error: any) {
      console.error("Analysis Error:", error);
      setErrorMsg(error.message || "משהו לא עבד בניתוח המשוב. נסה שוב.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const baseUrl = window.location.origin + window.location.pathname;
    const url = `${baseUrl}#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return <Layout><div className="text-center py-20">טוען...</div></Layout>;

  return (
