                          <input value={q.text_en} onChange={e => updateQuestion(q.id, 'text_en', e.target.value)} className="dark-input" placeholder="English" dir="ltr" />
                        </div>
                      </div>
                    ))}
                    <button onClick={addQuestion} className="w-full py-4 border-2 border-dashed border-white/5 rounded-xl text-white/20 hover:text-amber-600">+ הוסף שאלה</button>
                  </div>
                  <Button onClick={handleSaveQuestions} className="w-full py-5 text-xl">שמור שינויים בשאלון</Button>
               </div>
            </div>
          )}

        </div>
      </div>

      {feedbackMsg && (
        <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-amber-600 text-white px-8 py-4 rounded-full shadow-2xl animate-bounce z-[100] font-bold">
           {feedbackMsg}
        </div>
      )}
    </Layout>
  );
};

import { 
  getFirestore, 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where,
  updateDoc
} from "firebase/firestore";
import type { Firestore } from "firebase/firestore";
import { initializeApp, getApp, getApps, FirebaseApp } from "firebase/app";
import { getAuth, Auth, GoogleAuthProvider, signInWithPopup } from "firebase/auth";
import { FirebaseConfig, User, FeedbackResponse, SurveyQuestion } from "../types";

let app: FirebaseApp | null = null;
let db: Firestore | null = null;
let auth: Auth | null = null;

export const firebaseService = {
  init: (config: FirebaseConfig) => {
    if (!config.apiKey || config.apiKey.length === 0) return false;
    try {
      const apps = getApps();
      app = apps.length > 0 ? getApp() : initializeApp(config);
      db = getFirestore(app);
      auth = getAuth(app);
      return true;
    } catch (e) {
      return false;
    }
  },

  isInitialized: () => !!db && !!auth,

  loginWithGoogle: async (): Promise<User> => {
    if (!auth || !db) throw new Error("Firebase not initialized");
    const provider = new GoogleAuthProvider();
    const result = await signInWithPopup(auth, provider);
    const fbUser = result.user;
    if (!fbUser.email) throw new Error("No email returned from Google");
    let user = await firebaseService.findUserByEmail(fbUser.email);
    if (!user) {
      user = {
        id: fbUser.uid,
        name: fbUser.displayName || "משתמש גוגל",
        email: fbUser.email,
        createdAt: Date.now()
      };
      await firebaseService.createUser(user);
    }
    return user;
  },

  logout: async (): Promise<void> => {
    if (auth) await auth.signOut();
  },

  resetPassword: async (email: string, code: string, newPassword: string): Promise<void> => {
    if (!db) throw new Error("Database not connected");
    const valid = await firebaseService.validateRegistrationCode(code);
    if (!valid) throw new Error("קוד רישום שגוי.");
    const user = await firebaseService.findUserByEmail(email);
    if (!user) throw new Error("משתמש לא נמצא.");
    await updateDoc(doc(db, "users", user.id), { password: newPassword });
  },

  getSurveyQuestions: async (userId?: string): Promise<SurveyQuestion[]> => {
    if (!db) return [];
    if (userId) {
      try {
        const userRef = doc(db, "users", userId);
        const userSnap = await getDoc(userRef);
        if (userSnap.exists() && userSnap.data().customQuestions) {
          return userSnap.data().customQuestions as SurveyQuestion[];
        }
      } catch (e) {}
    }
    try {
      const docRef = doc(db, "settings", "survey_config");
      const snap = await getDoc(docRef);
      if (snap.exists() && snap.data().questions) return snap.data().questions;
      return [
        { id: 'q1', text_he: 'מהו לדעתך הדבר האחד שהוא/היא צריכים לשנות כדי להגיע לרמה הבאה?', text_en: 'What is the one thing they should change to reach the next level?', type: 'goal', required: true },
        { id: 'q2', text_he: 'אילו התנהגויות מעכבות אותו/ה כיום?', text_en: 'Which behaviors currently hinder them?', type: 'blocker', required: true }
      ];
    } catch (e) { return []; }
  },

  updateSurveyQuestions: async (questions: SurveyQuestion[]): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "settings", "survey_config"), { questions }, { merge: true });
  },

  updateUserQuestions: async (userId: string, questions: SurveyQuestion[]): Promise<void> => {
    if (!db) return;
    await updateDoc(doc(db, "users", userId), { customQuestions: questions });
  },

  validateRegistrationCode: async (codeToCheck: string): Promise<boolean> => {
    if (!db) return false;
    const docSnap = await getDoc(doc(db, "settings", "config"));
    const validCode = docSnap.exists() ? docSnap.data().registrationCode : "OBT-VIP";
    return codeToCheck.trim().toUpperCase() === validCode.toUpperCase();
  },

  updateRegistrationCode: async (newCode: string): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "settings", "config"), { registrationCode: newCode }, { merge: true });
  },

  createUser: async (user: User): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "users", user.id), user);
  },

  updateUserGoal: async (userId: string, goal: string): Promise<void> => {
    if (!db) return;
    await updateDoc(doc(db, "users", userId), { userGoal: goal });
  },

  getUser: async (userId: string): Promise<User | null> => {
    if (!db) return null;
    const snap = await getDoc(doc(db, "users", userId));
    return snap.exists() ? snap.data() as User : null;
  },

  findUserByEmail: async (email: string): Promise<User | null> => {
    if (!db) return null;
    const q = query(collection(db, "users"), where("email", "==", email));
    const snap = await getDocs(q);
    return snap.empty ? null : snap.docs[0].data() as User;
  },

  addResponse: async (response: FeedbackResponse): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "responses", response.id), response);
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (!db) return [];
    try {
      const q = query(collection(db, "responses"), where("surveyId", "==", userId));
      const snap = await getDocs(q);
      const results: FeedbackResponse[] = [];

      snap.forEach(docSnap => {
        const data = docSnap.data();
        if (data) {
          // מיפוי נתונים ישנים אם קיימים (Backward Compatibility)
          let finalAnswers = data.answers || [];
          if (finalAnswers.length === 0) {
            if (data.q1_change) finalAnswers.push({ questionId: 'q1', text: data.q1_change });
            if (data.q2_actions) finalAnswers.push({ questionId: 'q2', text: data.q2_actions });
          }

          results.push({
            ...data,
            id: docSnap.id,
            answers: finalAnswers
          } as FeedbackResponse);
        }
      });
      return results.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
    } catch (e) {
      console.error("Error fetching responses:", e);
      return [];
    }
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse, SurveyQuestion } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing.");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (
  responses: FeedbackResponse[], 
  userGoal?: string,
  questions: SurveyQuestion[] = []
): Promise<AnalysisResult> => {
  if (!responses || responses.length === 0) throw new Error("No responses for analysis.");

  const ai = getClient();
  const dataForAI = responses.map(r => ({
      relationship: r.relationship,
      feedback: (r.answers || []).map(a => {
        const q = questions.find(question => question.id === a.questionId);
        return {
          question: q?.text_he || 'General',
          type: q?.type || 'general',
          answer: a.text || ''
        };
      })
  }));

  const prompt = `
    ROLE: You are a World-Class Executive Coach and Leadership Strategist (Think McKinsey/HBS style).
    CONTEXT: You are analyzing 360-degree feedback for a leader.
    USER'S SELF-DEFINED GOAL: "${userGoal || 'Not specified'}"

    RAW DATA:
    ${JSON.stringify(dataForAI, null, 2)}

    YOUR MISSION:
    1. VALIDATE THE GOAL: Is the user's goal actually what they need based on the feedback? Or are they focusing on a symptom instead of the root cause? 
    2. THE ONE BIG THING: Identify the single most transformative shift (psychological or behavioral) that will unlock their next level of performance.
    3. BLIND SPOTS: Reveal what others see that the leader is missing.
    4. ALTERNATIVE GOALS: If their current goal is weak or misaligned, propose a "Power Goal".
    5. PSYCHOLOGICAL PATTERNS: Identify the underlying internal narratives driving their external blockers.

    OUTPUT: Hebrew (Fluent, Professional, Direct, High-Level).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: "You provide elite executive analysis. You must return ONLY valid JSON matching the schema. No conversational filler. Your analysis must be cutting, deep, and highly actionable.",
        thinkingConfig: { thinkingBudget: 16000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER, description: "1-10 alignment score" },
                    critique_he: { type: Type.STRING, description: "Deep analysis of why the goal is/isn't right" },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING, description: "The upgraded version of the goal" },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "refinedGoal_he"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            alternativeOBT_he: { type: Type.STRING, description: "If the first OBT isn't the whole story" },
            alternativeOBT_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                }
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "theOneBigThing_he", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    return JSON.parse(response.text.trim()) as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("כשל בניתוח הנתונים. וודא שיש מספיק משובים איכותיים.");
  }
};

