import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType, SurveyQuestion } from '../types';
import { translations } from '../translations';

export const Survey: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const { userId } = useParams<{ userId: string }>();

  const [userName, setUserName] = useState<string>('');
  const [userGoal, setUserGoal] = useState<string>('');
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [answers, setAnswers] = useState<Record<string, string>>({});

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  useEffect(() => {
    if (userId) {
      storageService.getUserDataById(userId).then(userData => {
        setUserName(userData.name);
        setUserGoal(userData.userGoal || '');
        storageService.getSurveyQuestions(userId).then(surveyQuestions => {
          setQuestions(surveyQuestions);
          setIsLoading(false);
        });
      }).catch(err => {
        console.error("Failed to load survey", err);
        setIsLoading(false);
      });
    }
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    const missing = questions.filter(q => q.required && !answers[q.id]);
    if (missing.length > 0) {
      alert(t.fillRequired);
      return;
    }
    setIsSending(true);
    const formattedAnswers = Object.entries(answers).map(([qid, text]) => ({ questionId: qid, text }));
    try {
      await storageService.addResponse(userId, relationship, formattedAnswers);
      setSubmitted(true);
    } catch (err) {
      alert("Submission error");
    } finally {
      setIsSending(false);
    }
  };

  const updateAnswer = (qid: string, text: string) => {
    setAnswers({ ...answers, [qid]: text });
  };

  if (isLoading) return <Layout><div className="text-center py-20 animate-pulse">{t.loadingSurvey}</div></Layout>;

  if (submitted) {
    return (
      <Layout>
        <div className="text-center py-20 space-y-8">
          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto text-green-500">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          </div>
          <h2 className="text-3xl font-bold">{t.thankYou}</h2>
          <p className="text-white/40 max-w-sm mx-auto">{t.surveySuccess}</p>
          <Link to="/"><Button variant="outline">{t.backHome}</Button></Link>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-2xl mx-auto w-full space-y-10">
        <div className="text-center space-y-4">
            <h1 className="text-4xl font-bold text-white tracking-tight">{userName}</h1>
            {userGoal && (
              <div className="glass-panel p-6 border-amber-600/20 bg-amber-600/5">
                <p className="text-xs font-bold text-amber-600 uppercase tracking-widest mb-2">{t.myGoal}:</p>
                <p className="italic text-lg text-white/80">"{userGoal}"</p>
              </div>
            )}
        </div>

        <form onSubmit={handleSubmit} className="glass-panel p-10 space-y-10">
            <div className="space-y-4">
                <label className="block text-sm font-bold text-white/40 uppercase tracking-widest">{t.relationship}</label>
                <select value={relationship} onChange={(e) => setRelationship(e.target.value as RelationshipType)} className="dark-input">
                    <option value="peer">{t.peer}</option>
                    <option value="manager">{t.manager}</option>
                    <option value="subordinate">{t.subordinate}</option>
                    <option value="friend">{t.friend}</option>
                    <option value="other">{t.other}</option>
                </select>
            </div>
            <div className="space-y-12">
              {questions.map((q) => (
                <div key={q.id} className="space-y-4">
                    <label className="block text-xl font-medium leading-relaxed">
                      {lang === 'he' ? q.text_he : q.text_en || q.text_he}
                      {q.required && <span className="text-amber-600 mx-2">*</span>}
                    </label>
                    <textarea 
                      required={q.required} 
                      value={answers[q.id] || ''} 
                      onChange={(e) => updateAnswer(q.id, e.target.value)} 
                      className="dark-input min-h-[120px] resize-none"
                    />
                </div>
              ))}
            </div>
            <Button type="submit" className="w-full py-5 text-xl" isLoading={isSending}>
              {t.submitSurvey}
            </Button>
        </form>
      </div>
    </Layout>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse, SurveyQuestion } from "../types";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing.");
  return new GoogleGenAI({ apiKey });
};

export const analyzeFeedback = async (
  responses: FeedbackResponse[], 
  userGoal?: string,
  questions: SurveyQuestion[] = []
): Promise<AnalysisResult> => {
  if (!responses || responses.length === 0) throw new Error("No responses for analysis.");

  const ai = getClient();
  const dataForAI = responses.map(r => ({
      relationship: r.relationship,
      feedback: (r.answers || []).map(a => {
        const q = questions.find(question => question.id === a.questionId);
        return {
          question: q?.text_he || 'General',
          type: q?.type || 'general',
          answer: a.text || ''
        };
      })
  }));

  const prompt = `
    ROLE: You are an Elite Executive Strategy Consultant.
    TASK: Synthesize 360-degree feedback to find the "One Big Thing" for growth.
    USER GOAL: "${userGoal || 'Not specified'}"
    DATA: ${JSON.stringify(dataForAI)}

    REQUIRED ANALYSIS:
    1. GOAL VALIDATION: Score 1-10 alignment between their goal and reality. Provide a "Power Goal".
    2. THE ONE BIG THING: The single psychological or behavioral shift needed.
    3. BLIND SPOTS: Hidden patterns others see.
    4. PSYCHOLOGICAL PATTERNS: The internal "narrative" holding them back.

    OUTPUT: Valid JSON only. Languages: Provide both Hebrew and English for all fields.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a high-level leadership analyst. Return ONLY a JSON object. Be direct, profound, and sharp. Do not include introductory text.",
        thinkingConfig: { thinkingBudget: 2000 },
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique_he: { type: Type.STRING },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "critique_en", "refinedGoal_he", "refinedGoal_en"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            alternativeOBT_he: { type: Type.STRING },
            alternativeOBT_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                }
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                }
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    }
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "executiveSummary_en", "theOneBigThing_he", "theOneBigThing_en", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    return JSON.parse(response.text.trim()) as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("Analysis failed. Please try again with more data.");
  }
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Landing: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  const [view, setView] = useState<'login' | 'register' | 'reset'>('login');
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [registrationCode, setRegistrationCode] = useState(''); 
  const [isLoading, setIsLoading] = useState(false);
  const [isGoogleLoading, setIsGoogleLoading] = useState(false);
  const [error, setError] = useState('');
  const [successMsg, setSuccessMsg] = useState('');

  const navigate = useNavigate();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setSuccessMsg('');
    setIsLoading(true);

    try {
      if (view === 'register') {
        await storageService.registerUser(name, email, password, registrationCode);
        navigate('/dashboard');
      } else if (view === 'login') {
        await storageService.login(email, password);
        navigate('/dashboard');
      } else if (view === 'reset') {
        await storageService.resetPassword(email, registrationCode, password);
        setSuccessMsg(t.adminSuccess);
        setTimeout(() => setView('login'), 2000);
      }
    } catch (err: any) {
      setError(err.message || 'Error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setError('');
    setIsGoogleLoading(true);
    try {
      await storageService.loginWithGoogle();
      navigate('/dashboard');
    } catch (err: any) {
      setError(err.message || 'Google login failed');
    } finally {
      setIsGoogleLoading(false);
    }
  };

  return (
    <Layout>
      <div className="flex flex-col items-center justify-center min-h-[70vh] py-12">
        <div className="text-center mb-12">
            <h1 className="text-5xl md:text-6xl font-bold text-white mb-6 tracking-tight">
                One Big <span className="text-[#e66a00]">Thing</span>
            </h1>
            <p className="text-xl text-white/60 max-w-xl mx-auto leading-relaxed">
               {t.subtitle}
            </p>
        </div>

        <div className="glass-panel w-full max-w-[460px] p-10">
            <div className="mb-10 text-center">
                <h2 className="text-2xl font-medium text-white">
                    {view === 'register' ? t.registerTitle : view === 'reset' ? t.resetTitle : t.loginTitle}
                </h2>
                <div className="h-px bg-white/10 w-full mt-6"></div>
            </div>

            <div className="mb-8">
              <button 
                onClick={handleGoogleLogin} 
                disabled={isGoogleLoading}
                className="w-full flex items-center justify-center gap-3 bg-white text-black font-bold py-3.5 rounded-lg hover:bg-gray-100 transition-all active:scale-[0.98] disabled:opacity-50"
              >
                {isGoogleLoading ? (
                  <div className="w-5 h-5 border-2 border-black/20 border-t-black rounded-full animate-spin"></div>
                ) : (
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 48 48">
                    <path fill="#FFC107" d="M43.611 20.083H42V20H24v8h11.303c-1.649 4.657-6.08 8-11.303 8c-6.627 0-12-5.373-12-12s5.373-12 12-12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C12.955 4 4 12.955 4 24s8.955 20 20 20s20-8.955 20-20c0-1.341-.138-2.65-.389-3.917z"/><path fill="#FF3D00" d="m6.306 14.691l6.571 4.819C14.655 15.108 18.961 12 24 12c3.059 0 5.842 1.154 7.961 3.039l5.657-5.657C34.046 6.053 29.268 4 24 4C16.318 4 9.656 8.337 6.306 14.691z"/><path fill="#4CAF50" d="M24 44c5.166 0 9.86-1.977 13.409-5.192l-6.19-5.238A11.91 11.91 0 0 1 24 36c-5.202 0-9.619-3.317-11.283-7.946l-6.522 5.025C9.505 39.556 16.227 44 24 44z"/><path fill="#1976D2" d="M43.611 20.083H42V20H24v8h11.303a12.04 12.04 0 0 1-4.087 5.571l.003-.002l6.19 5.238C36.971 39.205 44 34 44 24c0-1.341-.138-2.65-.389-3.917z"/>
                  </svg>
                )}
                <span>{t.googleLogin}</span>
              </button>

              <div className="relative flex items-center justify-center my-8">
                <div className="flex-grow border-t border-white/10"></div>
                <span className="flex-shrink mx-4 text-white/20 text-xs uppercase font-bold tracking-widest">{t.orEmail}</span>
                <div className="flex-grow border-t border-white/10"></div>
              </div>
            </div>

            <form onSubmit={handleSubmit} className="space-y-6">
                {view === 'register' && (
                    <input type="text" value={name} onChange={(e) => setName(e.target.value)} className="dark-input" placeholder={t.fullName} />
                )}

                <input 
                  type="email" 
                  value={email} 
                  onChange={(e) => setEmail(e.target.value)} 
                  className="dark-input" 
                  placeholder={t.email} 
                  dir="ltr"
                />

                {(view === 'register' || view === 'reset') && (
                    <input type="text" value={registrationCode} onChange={(e) => setRegistrationCode(e.target.value)} className="dark-input uppercase" placeholder={t.regCode} />
                )}

                <input 
                  type="password" 
                  value={password} 
                  onChange={(e) => setPassword(e.target.value)} 
                  className="dark-input" 
                  placeholder={t.password} 
                  dir="ltr"
                />

                {error && <p className="text-red-400 text-sm text-center font-light">{error}</p>}
                {successMsg && <p className="text-green-400 text-sm text-center font-light">{successMsg}</p>}

                <Button type="submit" variant="primary" className="w-full text-lg py-4" isLoading={isLoading}>
                    {view === 'register' ? t.registerBtn : view === 'reset' ? t.save : t.loginBtn}
                </Button>
            </form>

            <div className="mt-10 flex flex-col items-center gap-4 text-sm font-light">
                {view === 'login' ? (
                    <>
                        <button onClick={() => setView('reset')} className="text-white/40 hover:text-white transition-colors">{t.forgotPassword}</button>
                        <div className="text-white/40 mt-2">
                            {t.noAccount} <button onClick={() => setView('register')} className="text-[#e66a00] font-medium hover:underline">{t.registerBtn}</button>
                        </div>
                    </>
                ) : (
                    <button onClick={() => setView('login')} className="text-white/40 hover:text-white transition-colors">{t.backToLogin}</button>
                )}
            </div>
        </div>
      </div>
    </Layout>
  );
};

import React, { useEffect, useState, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { analyzeFeedback } from '../services/geminiService';
import { exportToWord } from '../services/exportService';
import { User, FeedbackResponse, AnalysisResult, SurveyQuestion } from '../types';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { translations } from '../translations';

export const Dashboard: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const navigate = useNavigate();

  const [user, setUser] = useState<User | null>(null);
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [responses, setResponses] = useState<FeedbackResponse[]>([]);
  const [analysis, setAnalysis] = useState<AnalysisResult | null>(null);
  const [goal, setGoal] = useState('');

  const [isEditingGoal, setIsEditingGoal] = useState(false);
  const [loadingAnalysis, setLoadingAnalysis] = useState(false);
  const [copied, setCopied] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [activeTab, setActiveTab] = useState<'overview' | 'responses' | 'settings'>('overview');
  const [feedbackMsg, setFeedbackMsg] = useState('');
  const [errorMsg, setErrorMsg] = useState('');

  const t = translations[lang];

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  useEffect(() => {
    const currentUser = storageService.getCurrentUser();
    if (!currentUser) { navigate('/'); return; }
    setUser(currentUser);
    setGoal(currentUser.userGoal || '');

    storageService.getResponsesForUser(currentUser.id).then(resps => setResponses(resps || []));
    storageService.getSurveyQuestions(currentUser.id).then(surqs => setQuestions(surqs || []));
  }, [navigate]);

  useEffect(() => {
    if (loadingAnalysis) {
      const messages = lang === 'he' ? 
        ["מנתח דפוסים פסיכולוגיים...", "מתקף את מטרת הצמיחה שלך...", "מזקק תובנות אסטרטגיות...", "מנסח את ה-The One Big Thing..."] : 
        ["Analyzing psychological patterns...", "Validating your growth goal...", "Synthesizing strategic insights...", "Formulating The One Big Thing..."];
      let i = 0;
      setLoadingMessage(messages[0]);
      const interval = setInterval(() => {
        i = (i + 1) % messages.length;
        setLoadingMessage(messages[i]);
      }, 3000);
      return () => clearInterval(interval);
    }
  }, [loadingAnalysis, lang]);

  const handleSaveGoal = async () => {
      if (!user || !goal.trim()) return;
      await storageService.updateUserGoal(user.id, goal);
      setUser({ ...user, userGoal: goal });
      setIsEditingGoal(false);
      showFeedback(t.adminSuccess);
  };

  const showFeedback = (msg: string) => {
    setFeedbackMsg(msg);
    setTimeout(() => setFeedbackMsg(''), 3000);
  };

  const handleAnalyze = async () => {
    if (!responses || responses.length === 0) return;
    setLoadingAnalysis(true);
    setErrorMsg('');
    try {
      const result = await analyzeFeedback(responses, user?.userGoal, questions);
      setAnalysis(result);
    } catch (error: any) {
      setErrorMsg(error.message || "Analysis failed.");
    } finally {
      setLoadingAnalysis(false);
    }
  };

  const copyLink = () => {
    const url = `${window.location.origin}${window.location.pathname}#/survey/${user?.id}`;
    navigator.clipboard.writeText(url).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };

  if (!user) return <Layout><div className="text-center py-20">{t.adminLoading}</div></Layout>;

  return (
    <Layout>
      <div className="pb-24">
        <div className="flex flex-col md:flex-row md:items-end justify-between gap-6 mb-10 pb-8 border-b border-white/5">
          <div className="space-y-1">
            <span className="text-amber-600 font-bold tracking-widest text-[10px] uppercase block">{t.workspaceLabel}</span>
            <h1 className="text-4xl font-bold text-white tracking-tight">{t.dashboardTitle}, {user.name}</h1>
            <p className="text-white/40 text-sm">{t.feedbacksCollected}: <span className="text-amber-500 font-bold">{responses?.length || 0}</span></p>
          </div>
          <div className="flex flex-wrap gap-3">
            <Button onClick={copyLink} variant="outline" className="rounded-lg py-2.5">{copied ? t.linkCopied : t.copyLink}</Button>
            <Button onClick={() => { storageService.logout(); navigate('/'); }} variant="ghost" className="text-white/30">{t.logout}</Button>
          </div>
        </div>

        <div className="flex gap-8 mb-10 border-b border-white/5">
          <button onClick={() => setActiveTab('overview')} className={`pb-4 px-2 text-sm font-bold uppercase tracking-widest transition-all ${activeTab === 'overview' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-white/30 hover:text-white/60'}`}>
            {t.strategyTab}
          </button>
          <button onClick={() => setActiveTab('responses')} className={`pb-4 px-2 text-sm font-bold uppercase tracking-widest transition-all ${activeTab === 'responses' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-white/30 hover:text-white/60'}`}>
            {t.responsesTab}
          </button>
          <button onClick={() => setActiveTab('settings')} className={`pb-4 px-2 text-sm font-bold uppercase tracking-widest transition-all ${activeTab === 'settings' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-white/30 hover:text-white/60'}`}>
            {t.settingsTab}
          </button>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">
          {activeTab === 'overview' && (
            <>
              <div className="lg:col-span-4 space-y-8">
                <div className="glass-panel p-6 border-l-4 border-l-amber-600">
                    <div className="flex justify-between items-center mb-4">
                        <h3 className="text-xs font-bold text-white/40 uppercase tracking-tighter">{t.originalGoal}</h3>
                        <button onClick={() => setIsEditingGoal(true)} className="text-amber-600 text-[10px] uppercase hover:underline">{t.edit}</button>
                    </div>
                    {isEditingGoal ? (
                        <div className="space-y-4">
                            <textarea value={goal} onChange={(e) => setGoal(e.target.value)} className="dark-input w-full text-sm" rows={4} autoFocus />
                            <div className="flex gap-2">
                                <Button onClick={handleSaveGoal} className="px-4 py-2 text-xs">{t.save}</Button>
                                <button onClick={() => setIsEditingGoal(false)} className="text-white/40 text-xs">{t.cancel}</button>
                            </div>
                        </div>
                    ) : (
                        <p className="text-lg font-light leading-relaxed text-white/90">"{goal || t.goalHint}"</p>
                    )}
                </div>

                {analysis && (
                  <div className="glass-panel p-6 border-l-4 border-l-blue-500 bg-blue-500/5">
                    <h3 className="text-xs font-bold text-blue-400 uppercase tracking-tighter mb-4">{t.validationTitle}</h3>
                    <div className="flex items-center gap-4 mb-4">
                      <div className="text-3xl font-bold text-white">{analysis.goalPrecision.score}/10</div>
                      <div className="text-xs text-white/40">{t.alignmentLevel}</div>
                    </div>
                    <p className="text-sm text-white/70 leading-relaxed mb-4">{lang === 'he' ? analysis.goalPrecision.critique_he : analysis.goalPrecision.critique_en}</p>
                    <div className="pt-4 border-t border-white/10">
                      <span className="text-[10px] font-bold text-blue-400 uppercase">{t.powerGoal}:</span>
                      <p className="text-md font-bold text-white mt-1">"{lang === 'he' ? analysis.goalPrecision.refinedGoal_he : analysis.goalPrecision.refinedGoal_en}"</p>
                    </div>
                  </div>
                )}
              </div>

              <div className="lg:col-span-8">
                {!analysis ? (
                    <div className="glass-panel min-h-[500px] flex flex-col items-center justify-center text-center p-12">
                        {loadingAnalysis ? (
                            <div className="space-y-8">
                                <div className="relative w-24 h-24 mx-auto flex items-center justify-center">
                                  <div className="absolute inset-0 border-4 border-amber-600 rounded-full border-t-transparent animate-spin"></div>
                                </div>
                                <p className="text-2xl font-light text-white animate-pulse">{loadingMessage}</p>
                            </div>
                        ) : (
                            <div className="space-y-8 max-w-md">
                                <div className="w-20 h-20 bg-amber-600/10 rounded-full flex items-center justify-center mx-auto text-amber-600 shadow-2xl">
                                    <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><circle cx="12" cy="12" r="10"/><path d="m9 12 2 2 4-4"/></svg>
                                </div>
                                <h2 className="text-3xl font-bold text-white">{t.generateReport}</h2>
                                <p className="text-white/40">{lang === 'he' ? `ה-AI ינתח את כל ${responses.length} המשובים כדי לחשוף את הנקודות העיוורות שלך.` : `AI will analyze all ${responses.length} feedbacks to reveal your blind spots.`}</p>
                                {errorMsg && <div className="bg-red-500/10 border border-red-500/20 text-red-400 p-4 rounded-xl text-sm">{errorMsg}</div>}
                                <Button onClick={handleAnalyze} className="w-full py-5 text-xl" disabled={responses.length < 1}>{t.generateReport}</Button>
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <div className="glass-panel p-10 bg-gradient-to-br from-onyx-800 to-onyx-950 border-amber-600/30 relative overflow-hidden">
                            <span className="px-3 py-1 bg-amber-600/20 text-amber-500 text-[10px] font-black uppercase tracking-widest rounded-full mb-6 inline-block">{t.strategicSynthesis}</span>
                            <h2 className="text-amber-500 text-sm font-bold uppercase tracking-[0.2em] mb-4">{t.obtTitle}</h2>
                            <p className="text-4xl font-bold text-white leading-tight mb-8">{lang === 'he' ? analysis.theOneBigThing_he : analysis.theOneBigThing_en}</p>
                            <div className="p-6 bg-white/5 rounded-2xl italic text-white/70 text-lg leading-relaxed">
                              "{lang === 'he' ? analysis.executiveSummary_he : analysis.executiveSummary_en}"
                            </div>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                           <div className="glass-panel p-6 space-y-4">
                              <h4 className="text-xs font-bold text-amber-600 uppercase">{t.psychologicalPatterns}</h4>
                              <p className="text-sm text-white/60 leading-relaxed">{lang === 'he' ? analysis.question2Analysis?.psychologicalPatterns_he : analysis.question2Analysis?.psychologicalPatterns_en}</p>
                           </div>
                           <div className="glass-panel p-6 space-y-4">
                              <h4 className="text-xs font-bold text-amber-600 uppercase">{t.missedOpportunities}</h4>
                              <ul className="space-y-2">
                                {(lang === 'he' ? analysis.question1Analysis?.opportunities_he : analysis.question1Analysis?.opportunities_en).map((o: string, i: number) => (
                                  <li key={i} className="text-sm text-white/80 flex gap-2"><span className="text-amber-600">•</span> {o}</li>
                                ))}
                              </ul>
                           </div>
                        </div>

                        <div className="flex justify-center pt-8 gap-4">
                          <Button onClick={() => exportToWord(user, analysis, responses)} variant="outline">{t.exportWord}</Button>
                          <Button onClick={() => setAnalysis(null)} variant="ghost" className="text-white/20">{t.reAnalyze}</Button>
                        </div>
                    </div>
                )}
              </div>
            </>
          )}

          {activeTab === 'responses' && (
            <div className="lg:col-span-12">
               <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                  {responses && responses.length > 0 ? responses.map(r => (
                      <div key={r.id} className="glass-panel p-6 border-white/5 space-y-6">
                          <div className="flex justify-between items-center pb-4 border-b border-white/5">
                            <span className="text-[10px] text-amber-600 font-bold uppercase tracking-widest">{t[r.relationship as keyof typeof t] || r.relationship}</span>
                            <span className="text-[9px] text-white/10">{new Date(r.timestamp).toLocaleDateString(lang === 'he' ? 'he-IL' : 'en-US')}</span>
                          </div>
                          <div className="space-y-6">
                            {(r.answers || []).map(a => {
                              const q = questions.find(qu => qu.id === a.questionId);
                              return (
                                <div key={a.questionId} className="space-y-2">
                                  <p className="text-[10px] text-white/20 uppercase font-bold">{lang === 'he' ? q?.text_he : q?.text_en}</p>
                                  <p className="text-white/80 text-sm font-light leading-relaxed">"{a.text}"</p>
                                </div>
                              );
                            })}
                          </div>
                      </div>
                  )) : <div className="col-span-full py-20 text-center glass-panel text-white/20 uppercase tracking-widest">{t.noResponses}</div>}
               </div>
            </div>
          )}

          {activeTab === 'settings' && (
            <div className="lg:col-span-12 glass-panel p-8 space-y-8">
                <div className="border-b border-white/5 pb-4">
                  <h2 className="text-xl font-bold text-amber-600">{t.settingsTab}</h2>
                  <p className="text-xs text-white/30">{lang === 'he' ? 'נדרש חיבור לפורטל הניהול לעריכת מבנה השאלון' : 'Admin portal is required for survey modification'}</p>
                </div>
                <div className="py-10 text-center text-white/20">{lang === 'he' ? 'עבור לדף הניהול (Admin) לשינויים מבניים בשאלון' : 'Navigate to Admin portal for structure changes'}</div>
            </div>
          )}
        </div>
      </div>
      {feedbackMsg && <div className="fixed bottom-10 left-1/2 -translate-x-1/2 bg-amber-600 text-white px-8 py-4 rounded-full shadow-2xl z-[100] font-bold">{feedbackMsg}</div>}
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType, SurveyQuestion } from '../types';
import { translations } from '../translations';

export const Survey: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const { userId } = useParams<{ userId: string }>();

  const [userName, setUserName] = useState<string>('');
  const [userGoal, setUserGoal] = useState<string>('');
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [answers, setAnswers] = useState<Record<string, string>>({});

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  useEffect(() => {
    if (userId) {
      storageService.getUserDataById(userId).then(userData => {
        setUserName(userData.name);
        setUserGoal(userData.userGoal || '');
        storageService.getSurveyQuestions(userId).then(surveyQuestions => {
          setQuestions(surveyQuestions);
          setIsLoading(false);
        });
      }).catch(err => {
        console.error("Failed to load survey", err);
        setIsLoading(false);
      });
    }
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    const missing = questions.filter(q => q.required && !answers[q.id]);
    if (missing.length > 0) {
      alert(t.fillRequired);
      return;
    }
    setIsSending(true);
    const formattedAnswers = Object.entries(answers).map(([qid, text]) => ({ questionId: qid, text }));
    try {
      await storageService.addResponse(userId, relationship, formattedAnswers);
      setSubmitted(true);
    } catch (err) {
      alert(t.submissionError);
    } finally {
      setIsSending(false);
    }
  };

  const updateAnswer = (qid: string, text: string) => {
    setAnswers({ ...answers, [qid]: text });
  };

  if (isLoading) return <Layout><div className="text-center py-20 animate-pulse">{t.loadingSurvey}</div></Layout>;

  if (submitted) {
    return (
      <Layout>
        <div className="text-center py-20 space-y-8">
          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto text-green-500">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          </div>
          <h2 className="text-3xl font-bold">{t.thankYou}</h2>
          <p className="text-white/40 max-w-sm mx-auto">{t.surveySuccess}</p>
          <Link to="/"><Button variant="outline">{t.backHome}</Button></Link>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-2xl mx-auto w-full space-y-10">
        <div className="text-center space-y-4">
            <h1 className="text-4xl font-bold text-white tracking-tight">{userName}</h1>
            {userGoal && (
              <div className="glass-panel p-6 border-amber-600/20 bg-amber-600/5">
                <p className="text-xs font-bold text-amber-600 uppercase tracking-widest mb-2">{t.myGoal}:</p>
                <p className="italic text-lg text-white/80">"{userGoal}"</p>
              </div>
            )}
        </div>

        <form onSubmit={handleSubmit} className="glass-panel p-10 space-y-10">
            <div className="space-y-4">
                <label className="block text-sm font-bold text-white/40 uppercase tracking-widest">{t.relationship}</label>
                <select value={relationship} onChange={(e) => setRelationship(e.target.value as RelationshipType)} className="dark-input">
                    <option value="peer">{t.peer}</option>
                    <option value="manager">{t.manager}</option>
                    <option value="subordinate">{t.subordinate}</option>
                    <option value="friend">{t.friend}</option>
                    <option value="other">{t.other}</option>
                </select>
            </div>
            <div className="space-y-12">
              {questions.map((q) => (
                <div key={q.id} className="space-y-4">
                    <label className="block text-xl font-medium leading-relaxed">
                      {lang === 'he' ? q.text_he : q.text_en}
                      {q.required && <span className="text-amber-600 mx-2">*</span>}
                    </label>
                    <textarea 
                      required={q.required} 
                      value={answers[q.id] || ''} 
                      onChange={(e) => updateAnswer(q.id, e.target.value)} 
                      className="dark-input min-h-[120px] resize-none"
                    />
                </div>
              ))}
            </div>
            <Button type="submit" className="w-full py-5 text-xl" isLoading={isSending}>
              {t.submitSurvey}
            </Button>
        </form>
      </div>
    </Layout>
  );
};

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { SurveyQuestion } from '../types';
import { translations } from '../translations';

export const Admin: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const t = translations[lang];

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
