import { 
  getFirestore, 
  collection, 
  doc, 
  setDoc, 
  getDoc, 
  getDocs, 
  query, 
  where,
  updateDoc
} from "firebase/firestore";
import type { Firestore } from "firebase/firestore";
import { initializeApp, getApp, getApps, FirebaseApp } from "firebase/app";
import { 
  getAuth, 
  Auth, 
  GoogleAuthProvider, 
  signInWithPopup, 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword,
  signOut
} from "firebase/auth";
import { FirebaseConfig, User, FeedbackResponse, SurveyQuestion } from "../types";

let app: FirebaseApp | null = null;
let db: Firestore | null = null;
let auth: Auth | null = null;

const DEFAULT_QUESTIONS: SurveyQuestion[] = [
  { id: 'q1', text_he: 'מהו לדעתך הדבר האחד שהוא/היא צריכים לשנות כדי להגיע לרמה הבאה?', text_en: 'What is the one thing they should change to reach the next level?', type: 'goal', required: true },
  { id: 'q2', text_he: 'אילו התנהגויות מעכבות אותו/ה כיום?', text_en: 'Which behaviors currently hinder them?', type: 'blocker', required: true }
];

export const firebaseService = {
  init: (config: FirebaseConfig) => {
    if (!config.apiKey || config.apiKey.length === 0) return false;
    try {
      const apps = getApps();
      app = apps.length > 0 ? getApp() : initializeApp(config);
      db = getFirestore(app);
      auth = getAuth(app);
      return true;
    } catch (e) {
      return false;
    }
  },

  isInitialized: () => !!db && !!auth,

  registerWithEmail: async (name: string, email: string, password: string): Promise<User> => {
    if (!auth || !db) throw new Error("Firebase not initialized");
    const credential = await createUserWithEmailAndPassword(auth, email, password);
    const user: User = {
      id: credential.user.uid,
      name,
      email,
      createdAt: Date.now()
    };
    await setDoc(doc(db, "users", user.id), user);
    return user;
  },

  loginWithEmail: async (email: string, password: string): Promise<User> => {
    if (!auth || !db) throw new Error("Firebase not initialized");
    const credential = await signInWithEmailAndPassword(auth, email, password);
    const userSnap = await getDoc(doc(db, "users", credential.user.uid));
    if (!userSnap.exists()) throw new Error("User profile not found");
    return userSnap.data() as User;
  },

  loginWithGoogle: async (): Promise<User> => {
    if (!auth || !db) throw new Error("Firebase not initialized");
    const provider = new GoogleAuthProvider();
    const result = await signInWithPopup(auth, provider);
    const fbUser = result.user;
    if (!fbUser.email) throw new Error("No email returned from Google");

    const userRef = doc(db, "users", fbUser.uid);
    const userSnap = await getDoc(userRef);

    if (!userSnap.exists()) {
      const user = {
        id: fbUser.uid,
        name: fbUser.displayName || "משתמש גוגל",
        email: fbUser.email,
        createdAt: Date.now()
      };
      await setDoc(userRef, user);
      return user;
    }
    return userSnap.data() as User;
  },

  logout: async (): Promise<void> => {
    if (auth) await signOut(auth);
  },

  getSurveyQuestions: async (userId?: string): Promise<SurveyQuestion[]> => {
    if (!db) return DEFAULT_QUESTIONS;

    // 1. ניסיון לטעון שאלות ספציפיות למשתמש (אם קיים userId בקישור)
    if (userId) {
      try {
        const userRef = doc(db, "users", userId);
        const userSnap = await getDoc(userRef);
        if (userSnap.exists() && userSnap.data().customQuestions && userSnap.data().customQuestions.length > 0) {
          return userSnap.data().customQuestions as SurveyQuestion[];
        }
      } catch (e) {
        console.warn("Could not fetch user-specific questions, falling back to global/defaults", e);
      }
    }

    // 2. ניסיון לטעון הגדרות גלובליות (public_content)
    try {
      const docRef = doc(db, "public_content", "survey_config");
      const snap = await getDoc(docRef);
      if (snap.exists() && snap.data().questions && snap.data().questions.length > 0) {
        return snap.data().questions;
      }
    } catch (e) {
      console.warn("Could not fetch global questions, using defaults", e);
    }

    // 3. חזרה לברירת מחדל קשיחה
    return DEFAULT_QUESTIONS;
  },

  updateSurveyQuestions: async (questions: SurveyQuestion[]): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "public_content", "survey_config"), { questions }, { merge: true });
  },

  validateRegistrationCode: async (codeToCheck: string): Promise<boolean> => {
    if (!db) return false;
    const docSnap = await getDoc(doc(db, "public_content", "config"));
    const validCode = docSnap.exists() ? docSnap.data().registrationCode : "OBT-VIP";
    return codeToCheck.trim().toUpperCase() === validCode.toUpperCase();
  },

  resetPassword: async (email: string, registrationCode: string, newPassword: string): Promise<void> => {
    if (!db || !auth) throw new Error("Firebase not initialized");
    const valid = await firebaseService.validateRegistrationCode(registrationCode);
    if (!valid) throw new Error("קוד רישום שגוי.");
    throw new Error("שחזור סיסמה ישיר אינו זמין מטעמי אבטחה. אנא השתמש בקישור 'שכחתי סיסמה' במייל.");
  },

  updateRegistrationCode: async (newCode: string): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "public_content", "config"), { registrationCode: newCode }, { merge: true });
  },

  updateUserGoal: async (userId: string, goal: string): Promise<void> => {
    if (!db) return;
    await updateDoc(doc(db, "users", userId), { userGoal: goal });
  },

  getUser: async (userId: string): Promise<User | null> => {
    if (!db) return null;
    try {
      const snap = await getDoc(doc(db, "users", userId));
      return snap.exists() ? snap.data() as User : null;
    } catch (e) {
      console.error("Error fetching user data:", e);
      return null;
    }
  },

  addResponse: async (response: FeedbackResponse): Promise<void> => {
    if (!db) return;
    await setDoc(doc(db, "responses", response.id), response);
  },

  getResponsesForUser: async (userId: string): Promise<FeedbackResponse[]> => {
    if (!db) return [];
    try {
      const q = query(collection(db, "responses"), where("surveyId", "==", userId));
      const snap = await getDocs(q);
      const results: FeedbackResponse[] = [];

      snap.forEach(docSnap => {
        const data = docSnap.data();
        if (data) {
          results.push({
            ...data,
            id: docSnap.id,
          } as FeedbackResponse);
        }
      });
      return results.sort((a, b) => (b.timestamp || 0) - (a.timestamp || 0));
    } catch (e) {
      console.error("Error fetching responses:", e);
      return [];
    }
  }
};

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { storageService } from '../services/storageService';
import { Button } from '../components/Button';
import { Layout } from '../components/Layout';
import { RelationshipType, SurveyQuestion } from '../types';
import { translations } from '../translations';

export const Survey: React.FC = () => {
  const [lang, setLang] = useState<'he' | 'en'>(() => (localStorage.getItem('obt_lang') as 'he' | 'en') || 'he');
  const { userId } = useParams<{ userId: string }>();

  const [userName, setUserName] = useState<string>('');
  const [userGoal, setUserGoal] = useState<string>('');
  const [questions, setQuestions] = useState<SurveyQuestion[]>([]);
  const [relationship, setRelationship] = useState<RelationshipType>('peer');
  const [answers, setAnswers] = useState<Record<string, string>>({});

  const [submitted, setSubmitted] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    const handleLangChange = (e: any) => setLang(e.detail);
    window.addEventListener('langChange', handleLangChange);
    return () => window.removeEventListener('langChange', handleLangChange);
  }, []);

  const t = translations[lang];

  useEffect(() => {
    if (userId) {
      storageService.getUserDataById(userId).then(userData => {
        setUserName(userData.name);
        setUserGoal(userData.userGoal || '');
        storageService.getSurveyQuestions(userId).then(surveyQuestions => {
          setQuestions(surveyQuestions);
          setIsLoading(false);
        });
      }).catch(err => {
        console.error("Failed to load survey", err);
        setIsLoading(false);
      });
    }
  }, [userId]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!userId) return;
    const missing = questions.filter(q => q.required && !answers[q.id]);
    if (missing.length > 0) {
      alert(t.fillRequired);
      return;
    }
    setIsSending(true);
    // Fix: Explicitly cast 'text' to string to satisfy TypeScript when mapping Object.entries of a Record
    const formattedAnswers = Object.entries(answers).map(([qid, text]) => ({ 
      questionId: qid, 
      text: text as string 
    }));
    try {
      await storageService.addResponse(userId, relationship, formattedAnswers);
      setSubmitted(true);
    } catch (err) {
      alert(t.submissionError);
    } finally {
      setIsSending(false);
    }
  };

  const updateAnswer = (qid: string, text: string) => {
    setAnswers({ ...answers, [qid]: text });
  };

  if (isLoading) return <Layout><div className="text-center py-20 animate-pulse">{t.loadingSurvey}</div></Layout>;

  if (submitted) {
    return (
      <Layout>
        <div className="text-center py-20 space-y-8">
          <div className="w-20 h-20 bg-green-500/10 rounded-full flex items-center justify-center mx-auto text-green-500">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2"><path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/></svg>
          </div>
          <h2 className="text-3xl font-bold">{t.thankYou}</h2>
          <p className="text-white/40 max-w-sm mx-auto">{t.surveySuccess}</p>
          <Link to="/"><Button variant="outline">{t.backHome}</Button></Link>
        </div>
      </Layout>
    );
  }

  return (
    <Layout>
      <div className="max-w-2xl mx-auto w-full space-y-10">
        <div className="text-center space-y-4">
            <h1 className="text-4xl font-bold text-white tracking-tight">{userName}</h1>
            {userGoal && (
              <div className="glass-panel p-6 border-amber-600/20 bg-amber-600/5">
                <p className="text-xs font-bold text-amber-600 uppercase tracking-widest mb-2">{t.myGoal}:</p>
                <p className="italic text-lg text-white/80">"{userGoal}"</p>
              </div>
            )}
        </div>

        <form onSubmit={handleSubmit} className="glass-panel p-10 space-y-10">
            <div className="space-y-4">
                <label className="block text-sm font-bold text-white/40 uppercase tracking-widest">{t.relationship}</label>
                <select value={relationship} onChange={(e) => setRelationship(e.target.value as RelationshipType)} className="dark-input">
                    <option value="peer">{t.peer}</option>
                    <option value="manager">{t.manager}</option>
                    <option value="subordinate">{t.subordinate}</option>
                    <option value="friend">{t.friend}</option>
                    <option value="other">{t.other}</option>
                </select>
            </div>
            <div className="space-y-12">
              {questions.map((q) => (
                <div key={q.id} className="space-y-4">
                    <label className="block text-xl font-medium leading-relaxed">
                      {lang === 'he' ? q.text_he : q.text_en}
                      {q.required && <span className="text-amber-600 mx-2">*</span>}
                    </label>
                    <textarea 
                      required={q.required} 
                      value={answers[q.id] || ''} 
                      onChange={(e) => updateAnswer(q.id, e.target.value)} 
                      className="dark-input min-h-[120px] resize-none"
                    />
                </div>
              ))}
            </div>
            <Button type="submit" className="w-full py-5 text-xl" isLoading={isSending}>
              {t.submitSurvey}
            </Button>
        </form>
      </div>
    </Layout>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult, FeedbackResponse, SurveyQuestion } from "../types";

export const analyzeFeedback = async (
  responses: FeedbackResponse[], 
  userGoal?: string,
  questions: SurveyQuestion[] = []
): Promise<AnalysisResult> => {
  if (!responses || responses.length === 0) throw new Error("No responses for analysis.");

  // Fix: Initialize GoogleGenAI right before making an API call using the mandatory process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const dataForAI = responses.map(r => ({
      relationship: r.relationship,
      feedback: (r.answers || []).map(a => {
        const q = questions.find(question => question.id === a.questionId);
        return {
          question: q?.text_he || 'General',
          type: q?.type || 'general',
          answer: a.text || ''
        };
      })
  }));

  const prompt = `
    ROLE: Elite Executive Strategy Consultant.
    TASK: Analyze 360 feedback and identify the "One Big Thing" (OBT) for professional growth.
    USER GOAL: "${userGoal || 'Not specified'}"
    DATA: ${JSON.stringify(dataForAI)}

    ANALYSIS REQUIREMENTS:
    1. GOAL VALIDATION: Score 1-10 (alignment with feedback). Provide a "Power Goal".
    2. THE ONE BIG THING: The single most important shift needed.
    3. PSYCHOLOGICAL PATTERNS: The inner narrative behind the behavior.
    4. ACTION PLAN: Concrete high-level steps.

    OUTPUT: Strict JSON matching the provided schema. Provide both Hebrew and English for all text fields.
  `;

  try {
    // Fix: Upgrade to 'gemini-3-pro-preview' for advanced reasoning/complex text tasks as per guidelines
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: prompt,
      config: {
        systemInstruction: "You are a direct, sharp, and elite leadership analyst. Return ONLY the requested JSON. No preamble. No conversational filler.",
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            goalPrecision: {
                type: Type.OBJECT,
                properties: {
                    score: { type: Type.NUMBER },
                    critique_he: { type: Type.STRING },
                    critique_en: { type: Type.STRING },
                    refinedGoal_he: { type: Type.STRING },
                    refinedGoal_en: { type: Type.STRING }
                },
                required: ["score", "critique_he", "critique_en", "refinedGoal_he", "refinedGoal_en"]
            },
            executiveSummary_he: { type: Type.STRING },
            executiveSummary_en: { type: Type.STRING },
            theOneBigThing_he: { type: Type.STRING },
            theOneBigThing_en: { type: Type.STRING },
            alternativeOBT_he: { type: Type.STRING },
            alternativeOBT_en: { type: Type.STRING },
            question1Analysis: {
                type: Type.OBJECT,
                properties: {
                    opportunities_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    opportunities_en: { type: Type.ARRAY, items: { type: Type.STRING } }
                },
                required: ["opportunities_he", "opportunities_en"]
            },
            question2Analysis: {
                type: Type.OBJECT,
                properties: {
                    blockers_he: { type: Type.ARRAY, items: { type: Type.STRING } },
                    blockers_en: { type: Type.ARRAY, items: { type: Type.STRING } },
                    psychologicalPatterns_he: { type: Type.STRING },
                    psychologicalPatterns_en: { type: Type.STRING }
                },
                required: ["blockers_he", "blockers_en", "psychologicalPatterns_he", "psychologicalPatterns_en"]
            },
            actionPlan: {
                type: Type.ARRAY,
                items: {
                    type: Type.OBJECT,
                    properties: {
                        title_he: { type: Type.STRING },
                        title_en: { type: Type.STRING },
                        content_he: { type: Type.STRING },
                        content_en: { type: Type.STRING }
                    },
                    required: ["title_he", "title_en", "content_he", "content_en"]
                }
            }
          },
          required: ["goalPrecision", "executiveSummary_he", "executiveSummary_en", "theOneBigThing_he", "theOneBigThing_en", "question1Analysis", "question2Analysis", "actionPlan"],
        },
      },
    });

    // Fix: Access response.text as a property, not a method, per guidelines
    return JSON.parse(response.text.trim()) as AnalysisResult;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error("Analysis process timed out or failed. Please try again.");
  }
};

